"""
offlinai_shell — tiny POSIX-like shell emulator that runs inside the
CodeBench Python runtime. iOS has no /bin/bash, no fork(), no
subprocess — so we implement every builtin the user actually needs in
pure Python and fall back to evaluating the line as Python for anything
else.

Call `run_line(cmd)` once per user input. The function itself does:

  1. If the line is empty / a comment → print nothing, return.
  2. Tokenise with `shlex.split`.
  3. If the first token is a registered builtin → call its handler.
  4. Otherwise interpret the line as Python code (multi-line statements
     are accumulated until `code.compile_command()` says they're done).

The emulator prints to stdout/stderr directly — the Swift terminal
captures them through PythonRuntime's existing streaming hooks.

Keep this file PURE PYTHON and stdlib-only. It must load on a vanilla
CPython with no extensions.
"""

from __future__ import annotations

import builtins
import code
import contextlib
import fnmatch
import io
import os
import runpy
import shlex
import shutil
import stat as _stat
import sys
import time
import traceback
from pathlib import Path
from typing import Callable, Dict, List, Optional

# ---------------------------------------------------------------------------
# ANSI helpers — the Swift terminal supports SGR color codes.

def _c(n: int) -> str:   return f"\x1b[{n}m"
RESET = _c(0)
BOLD  = _c(1)
DIM   = _c(2)
RED   = _c(31)
GRN   = _c(32)
YLW   = _c(33)
BLU   = _c(34)
MAG   = _c(35)
CYN   = _c(36)
WHT   = _c(37)
GRAY  = _c(90)


def _color(path: Path) -> str:
    """Pick an ls color based on the file type/extension."""
    try:
        st = path.lstat()
    except OSError:
        return GRAY
    if _stat.S_ISDIR(st.st_mode):   return BLU + BOLD
    if _stat.S_ISLNK(st.st_mode):   return CYN
    if path.suffix in {".py", ".pyi"}:        return YLW
    if path.suffix in {".md", ".txt", ".rst"}: return WHT
    if path.suffix in {".png", ".jpg", ".jpeg", ".gif", ".svg", ".mp4"}: return MAG
    if path.suffix in {".json", ".yaml", ".yml", ".toml"}:              return CYN
    if st.st_mode & 0o111:  # executable
        return GRN + BOLD
    return ""


def _fmt_size(n: int) -> str:
    for unit in ("B", "K", "M", "G", "T"):
        if n < 1024:
            return f"{n:>5.0f}{unit}" if unit == "B" else f"{n:>5.1f}{unit}"
        n /= 1024
    return f"{n:.1f}P"


# ---------------------------------------------------------------------------
# Shell state

class Shell:
    # Real interactive namespace for Python lines.
    def __init__(self) -> None:
        import __main__
        self.globals: dict = __main__.__dict__
        self.pending: List[str] = []      # buffer for multi-line Python
        self.aliases: Dict[str, str] = {
            "ll": "ls -lah",
            "la": "ls -a",
            "cls": "clear",
            "py": "python",
            "h":  "help",
            "?":  "help",
        }
        self.home = str(Path.home())
        # user/host for the zsh-style PS1 prompt. iOS doesn't expose a
        # traditional getlogin(), so we fall back through a few env vars.
        # The host name is the device display name (e.g. "Eulers-iPhone",
        # "Eulers-iPad", "Eulers-Mac-mini" on Catalyst).
        self.user = (
            os.environ.get("USER")
            or os.environ.get("LOGNAME")
            or "codebench"
        )
        # Default host fallback: pick something sensible for whatever
        # device we're on. UIDevice isn't importable from Python, so
        # we sniff platform.machine() which returns identifiers like
        # "iPhone15,3", "iPad14,8", "arm64" (Mac Catalyst / iPad-on-Mac).
        default_host = "device"
        try:
            import platform as _pl
            _mach = _pl.machine() or ""
            if _mach.startswith("iPhone"):
                default_host = "iPhone"
            elif _mach.startswith("iPad"):
                default_host = "iPad"
            elif _mach in ("arm64", "x86_64"):
                default_host = "Mac"
        except Exception:
            pass
        try:
            import socket as _socket
            _h = _socket.gethostname()
            # Trim the trailing .local that Bonjour adds on macOS/iOS.
            if _h.endswith(".local"):
                _h = _h[:-6]
            self.host = _h or default_host
        except Exception:
            self.host = default_host
        self.start_time = time.time()
        # Users can't chdir into the read-only app bundle, so default to
        # the writable Documents folder on first launch.
        try:
            docs_workspace = Path("~/Documents/Workspace").expanduser()
            if docs_workspace.is_dir():
                os.chdir(docs_workspace)
        except OSError:
            pass

    # ── Prompt ───────────────────────────────────────────────────────
    def prompt(self) -> str:
        """PS1 — modeled on macOS zsh's default:
             user@host cwd %
        (e.g. 'euler@Eulers-iPad ~ %')

        Never raises. If os.getcwd() fails (we landed in a directory
        the app can't read — common after `cd ..` into an iOS-sandboxed
        parent), we auto-recover by chdir'ing back to $HOME and
        showing a one-line hint.
        """
        try:
            cwd = os.getcwd()
        except OSError:
            # cwd is inaccessible — auto-recover so we don't hammer
            # the user with repeated permission errors on every prompt.
            try:
                os.chdir(self.home)
                cwd = self.home
            except OSError:
                cwd = "?"
        if cwd.startswith(self.home):
            cwd = "~" + cwd[len(self.home):]
        return f"{BOLD}{self.user}@{self.host}{RESET} {cwd} {BOLD}%{RESET} "

    def ps2(self) -> str:
        # zsh uses `heredoc>` or `dquote>`; we fall back to a plain
        # continuation arrow because we can't know which kind is active.
        return f"{DIM}>{RESET} "

    # ── Entry point ───────────────────────────────────────────────────
    def run_line(self, line: str) -> None:
        """Execute one user input line and stream results to stdout."""
        # If we're in multi-line Python input mode, keep accumulating.
        if self.pending:
            self.pending.append(line)
            src = "\n".join(self.pending)
            try:
                compiled = code.compile_command(src, "<shell>", "single")
            except SyntaxError as e:
                self.pending.clear()
                self._print_syntax_error(src, e)
                return
            if compiled is None:
                return  # still incomplete — caller shows PS2
            self.pending.clear()
            self._exec_compiled(compiled)
            return

        if not line.strip() or line.strip().startswith("#"):
            return

        # Alias expansion (single level, first word only)
        first, _, rest = line.lstrip().partition(" ")
        if first in self.aliases:
            line = self.aliases[first] + (" " + rest if rest else "")

        # Explicit Python escape: line starts with "%" or ">>" or ":"
        if line.lstrip().startswith(("%", ">>>", ":py ")):
            py = line.lstrip().lstrip("%").lstrip(":py ").lstrip(">>> ").lstrip()
            self._run_python(py)
            return

        # Tokenise. shlex raises ValueError on unbalanced quotes — when
        # the first word LOOKS LIKE A SHELL COMMAND (a known builtin
        # name), surface a clear "unbalanced quote" message before the
        # line falls through to Python eval where it would surface as a
        # confusing "unterminated string literal" with no indication of
        # which quote is the culprit.
        try:
            tokens = shlex.split(line, comments=False, posix=True)
        except ValueError as e:
            head = line.lstrip().split(maxsplit=1)[0]
            if head in BUILTINS:
                # Find the column of the FIRST quote that has no match
                # so we can point at it. shlex's own message already
                # explains the issue, but we add the line + caret in
                # the same shape SyntaxError uses for consistency.
                col = self._find_unbalanced_quote(line)
                shown = line.rstrip("\n")
                if len(shown) > 200: shown = shown[:200] + "…"
                print(f"  {DIM}{shown}{RESET}")
                if col is not None:
                    print(f"  {RED}{' ' * col}^{RESET}")
                print(f"{RED}{head}:{RESET} unbalanced quote ({e})")
                return
            tokens = []

        if tokens and tokens[0] in BUILTINS:
            # Universal help-flag handling. Accepts --help / -h / --h /
            # -H / -help / help / -? / /? — anything in _HELP_TOKENS.
            # Builtins that forward help to an underlying tool (python,
            # pip, clang, gfortran, git, LaTeX engines …) opt out via
            # _FORWARD_HELP so their own richer help is preserved; for
            # those, _normalize_help_arg inside the builtin rewrites
            # non-standard synonyms back to --help before delegation.
            if (len(tokens) == 2 and _is_help_tok(tokens[1])
                    and tokens[0] not in _FORWARD_HELP):
                _print_builtin_help(tokens[0])
                return
            try:
                BUILTINS[tokens[0]](self, tokens[1:])
            except SystemExit:
                raise  # let a sys.exit from a script propagate
            except KeyboardInterrupt:
                print(f"\n{YLW}^C{RESET}")
            except Exception as e:
                print(f"{RED}{type(e).__name__}:{RESET} {e}")
                if os.environ.get("OFFLINAI_SHELL_DEBUG"):
                    traceback.print_exc()
            return

        # Console-script dispatch: pip-installed packages register
        # `console_scripts` entry points (pypistats, black, mypy, etc.).
        # iOS has no PATH/exec model so we can't run their generated
        # `bin/<name>` shim — but the entry point IS just a Python
        # callable, so we can load it and call its main() ourselves.
        # This makes `pypistats recent numpy` Just Work after
        # `pip install pypistats`, no restart needed.
        if tokens and self._dispatch_console_script(tokens[0], tokens[1:]):
            return

        # Fallback: try the whole line as Python.
        self._run_python(line)

    def _dispatch_console_script(self, name: str, args: List[str]) -> bool:
        """Look `name` up as a `console_scripts` entry point in any
        installed distribution and, if found, invoke it as if it were
        the `bin/<name>` script. Returns True iff we dispatched.

        The entry point's `main()` typically calls sys.exit(rc); we
        translate that to the same shell-style behavior the BUILTINS
        path uses. argv[0] is set to `name` so the script's argparse
        sees the program name it expects (some scripts hardcode
        sys.argv[0] in usage strings).
        """
        try:
            import importlib.metadata as _md
        except Exception:
            return False
        try:
            eps = _md.entry_points(group="console_scripts")
        except Exception:
            return False
        match = None
        for ep in eps:
            if ep.name == name:
                match = ep
                break
        if match is None:
            return False
        # Load the entry-point callable. Failure here means the package
        # is broken (missing module, syntax error, etc.) — surface as a
        # normal command error rather than crashing the REPL.
        try:
            target = match.load()
        except BaseException as e:
            print(f"{RED}{name}:{RESET} failed to load entry point ({type(e).__name__}: {e})")
            if os.environ.get("OFFLINAI_SHELL_DEBUG"):
                traceback.print_exc()
            return True
        # Most CLI scripts are written assuming `if __name__ == "__main__":
        # sys.exit(main())`. We replicate that: swap sys.argv, call,
        # restore. SystemExit is the script's normal exit path; we
        # swallow it so the REPL keeps going.
        saved_argv = sys.argv[:]
        sys.argv = [name] + list(args)
        try:
            try:
                rc = target() if callable(target) else None
            except SystemExit as e:
                rc = e.code if isinstance(e.code, int) else (0 if e.code is None else 1)
            except KeyboardInterrupt:
                print(f"\n{YLW}^C{RESET}")
                rc = 130
            except BaseException as e:
                print(f"{RED}{type(e).__name__}:{RESET} {e}")
                if os.environ.get("OFFLINAI_SHELL_DEBUG"):
                    traceback.print_exc()
                rc = 1
        finally:
            sys.argv = saved_argv
        if isinstance(rc, int) and rc not in (0, None):
            print(f"{YLW}{name} exited with code {rc}{RESET}")
        return True

    # ── Python evaluation ─────────────────────────────────────────────
    def _run_python(self, src: str) -> None:
        try:
            compiled = code.compile_command(src, "<shell>", "single")
        except SyntaxError as e:
            self._print_syntax_error(src, e)
            return
        if compiled is None:
            # Need more lines.
            self.pending.append(src)
            return
        self._exec_compiled(compiled)

    def _print_syntax_error(self, src: str, e: SyntaxError) -> None:
        """Render a SyntaxError the way CPython's interactive REPL does:
        the offending line, a `^` caret pointing at the problem column,
        then the message. Without this the user just sees
        `SyntaxError: unterminated string literal (detected at line 1)`
        with no indication what they typed.
        """
        # Echo the line itself (truncate huge ones so we don't blow the
        # terminal). Use `e.text` if the parser captured it (more
        # accurate for multi-line inputs), else `src`.
        line_text = (e.text if e.text is not None else src).rstrip("\n")
        if len(line_text) > 200:
            line_text = line_text[:200] + "…"
        print(f"  {DIM}{line_text}{RESET}")

        # Caret. e.offset is 1-based; clamp to the line length so a
        # bad parser offset doesn't push the caret off-screen.
        if e.offset is not None and e.offset > 0:
            col = min(int(e.offset), len(line_text) + 1) - 1
            print(f"  {RED}{' ' * col}^{RESET}")

        # Strip the noisy "(<shell>, line 1)" parenthetical that adds
        # nothing once we've already shown the line + caret.
        msg = str(e.msg) if hasattr(e, "msg") and e.msg else str(e)
        # Tailored hint for the most common "I typed a bare word the
        # shell didn't recognise" case — but only when the line looks
        # like a shell command, not Python. Heuristics for shell-shape:
        #   • the first token is a plain identifier (no parens, ops, etc.)
        #   • that token is NOT a Python keyword (def, if, for, …)
        #   • the rest of the line has no Python-only syntax
        # Without these guards we'd suggest "did you mean df?" for
        # `def f(:` — which is just confusing.
        import keyword as _kw
        stripped = src.lstrip()
        first_token = stripped.split(maxsplit=1)[0] if stripped else ""
        is_shellish = (
            first_token.isidentifier()
            and not _kw.iskeyword(first_token)
            and not any(c in stripped for c in "(=:[{")
        )
        if is_shellish and (msg.startswith("invalid syntax")
                            or msg.startswith("unterminated")):
            similar = self._similar_builtins(first_token)
            if similar:
                hint = f"  {DIM}did you mean: {', '.join(similar)}?{RESET}"
                print(f"{RED}SyntaxError:{RESET} {msg}\n{hint}")
                return
        print(f"{RED}SyntaxError:{RESET} {msg}")

    @staticmethod
    def _similar_builtins(name: str) -> List[str]:
        """Edit-distance lookup over BUILTINS — surfaces suggestions
        when a user types `gerp` instead of `grep`, etc. Returns at most
        3 names, only those within edit distance 2."""
        if not name or len(name) < 2:
            return []
        import difflib
        return difflib.get_close_matches(
            name, list(BUILTINS.keys()), n=3, cutoff=0.7)

    @staticmethod
    def _find_unbalanced_quote(line: str) -> Optional[int]:
        """Walk `line` tracking quote state. Return the 0-based column
        of the unbalanced quote, or None if all quotes are matched
        (shouldn't happen if shlex actually raised, but defensive)."""
        in_single = False
        in_double = False
        opener_col: Optional[int] = None
        i = 0
        n = len(line)
        while i < n:
            c = line[i]
            if c == "\\" and i + 1 < n:
                i += 2; continue          # backslash-escaped — skip pair
            if in_single:
                if c == "'":
                    in_single = False; opener_col = None
            elif in_double:
                if c == '"':
                    in_double = False; opener_col = None
            else:
                if c == "'":
                    in_single = True; opener_col = i
                elif c == '"':
                    in_double = True; opener_col = i
            i += 1
        return opener_col

    def _exec_compiled(self, compiled) -> None:
        try:
            exec(compiled, self.globals)
        except SystemExit:
            raise
        except KeyboardInterrupt:
            print(f"\n{YLW}^C{RESET}")
        except BaseException:
            traceback.print_exc()


# ---------------------------------------------------------------------------
# Builtin commands

BUILTINS: Dict[str, Callable[["Shell", List[str]], None]] = {}

# Builtins that should NOT have their --help intercepted by the
# universal handler — these forward --help to an underlying tool
# (python's argparse, pip's cli, the C compilers' -h output, …) and
# their built-in help is more authoritative than a short docstring.
_FORWARD_HELP = {
    "python", "python3", "pip", "pip3",
    "pip-install", "pip-uninstall", "pip-list", "pip-show",
    "pip-freeze", "pip-check",
    "cc", "gcc", "clang", "c++", "g++", "clang++",
    "gfortran", "f77", "f90", "f95",
    "pdflatex", "latex", "tex", "pdftex",
    "git",
}


def builtin(name: str):
    def deco(fn):
        BUILTINS[name] = fn
        return fn
    return deco


# Tokens that ANY builtin should treat as a request for help. Includes
# common typos / abbreviations users reach for on a phone keyboard where
# exact flag spelling is easy to fat-finger: --h (shortened --help),
# -help (the Java-ish single-dash form), -H, and a bare `help`.
# _is_help_tok(x) is the authoritative check — use it everywhere instead
# of hardcoded tuples so we don't fragment the set as new builtins land.
_HELP_TOKENS = {"--help", "-h", "--h", "-H", "-help", "help", "-?", "/?"}


def _is_help_tok(s: str) -> bool:
    """True if `s` looks like a request for help. Case-sensitive — keep
    `-h` as the short flag but treat `-H`, `--help`, `--h`, `-help`,
    `help`, `-?`, `/?` as synonyms. Everything except a plain `-h` gets
    a `--help`-style long match."""
    return s in _HELP_TOKENS


def _normalize_help_arg(argv: list) -> list:
    """If the first arg is a help synonym (--h, -H, etc.), rewrite it
    to the canonical `--help` before delegating to an underlying tool
    (pip, git, python-with-its-own-CLI, compilers). The tool's own
    argparse / getopt recognises `--help` and `-h` but not the broader
    CodeBench-accepted set, so we do the mapping here."""
    if not argv:
        return argv
    if argv[0] in _HELP_TOKENS and argv[0] not in ("--help", "-h"):
        return ["--help"] + argv[1:]
    return argv


def _print_builtin_help(name: str) -> None:
    """Pretty-print a builtin's docstring. Called by run_line when the
    user types `<cmd> --help` / `<cmd> -h`. Falls back to a stub if
    there's no docstring yet."""
    fn = BUILTINS.get(name)
    if fn is None:
        print(f"{RED}help:{RESET} no such command: {name}")
        return
    doc = (fn.__doc__ or "").strip()
    print(f"{BOLD}{GRN}{name}{RESET}")
    if doc:
        for line in doc.splitlines():
            print(f"  {line}")
    else:
        print(f"  {DIM}(no documentation){RESET}")
        print(f"  {DIM}Try `help` to see the full command overview.{RESET}")


@builtin("help")
def _help(sh: Shell, argv: List[str]) -> None:
    """help [command]  — list all builtins, or print detailed docs for one."""

    # `help <name>` — detailed docs for a single builtin.
    if argv:
        name = argv[0]
        fn = BUILTINS.get(name)
        if fn is None:
            # Accept aliases too (they're expanded in run_line before
            # BUILTINS lookup, but explicit `help cls` should still work).
            alias_target = sh.aliases.get(name, "").split(" ", 1)[0]
            fn = BUILTINS.get(alias_target) if alias_target else None
            if fn is None:
                print(f"{RED}help:{RESET} no such command: {name}")
                print(f"{DIM}  try `help` with no args for the full list{RESET}")
                return
            print(f"{DIM}({name} is an alias for {alias_target}){RESET}\n")
        doc = (fn.__doc__ or "").strip()
        if not doc:
            doc = f"{name}  — no documentation available."
        print(f"{BOLD}{GRN}{name}{RESET}")
        for line in doc.splitlines():
            print(f"  {line}")
        return

    # ── Full overview ─────────────────────────────────────────────

    # Group builtins by category for a nicer overview.
    categories = [
        ("Filesystem",
         ["ls", "ll", "la", "cat", "head", "tail", "pwd", "cd", "mkdir", "rmdir",
          "rm", "touch", "cp", "mv", "find", "tree", "grep", "stat", "wc", "which"]),
        ("Disk usage",
         ["du", "df", "ncdu"]),
        ("System monitor",
         ["top", "htop"]),
        ("Terminal",
         ["clear", "cls", "date", "uptime", "echo", "env", "export",
          "history", "man", "help"]),
        ("Python / packages",
         ["python", "python3", "pip", "pip3",
          "pip-install", "pip-uninstall", "pip-list", "pip-show",
          "pip-freeze", "pip-check"]),
        ("Compile / run",
         ["cc", "gcc", "clang", "c++", "g++", "clang++",
          "gfortran", "f77", "f90", "f95"]),
        ("LaTeX",
         ["pdflatex", "latex", "tex", "pdftex"]),
        ("AI",
         ["ai"]),
        ("Network / source",
         ["git"]),
        ("Session",
         ["exit", "quit"]),
    ]

    print(f"{BOLD}CodeBench shell{RESET} — "
          f"{DIM}type `help <command>` for details on a specific command{RESET}\n")

    col_w = 16
    for cat_name, cmds in categories:
        avail = [c for c in cmds if c in BUILTINS]
        if not avail:
            continue
        print(f"{BOLD}{CYN}{cat_name}{RESET}")
        # Print commands in rows of 4, aligned.
        per_row = 4
        for i in range(0, len(avail), per_row):
            chunk = avail[i:i + per_row]
            line = "  " + "".join(f"{GRN}{c:<{col_w}}{RESET}" for c in chunk)
            print(line)
        print()

    # Mention builtins in BUILTINS we haven't categorized above
    # so `help` stays honest as commands get added.
    known = {c for _, cs in categories for c in cs}
    rest = [c for c in sorted(BUILTINS) if c not in known]
    if rest:
        print(f"{BOLD}{CYN}Other{RESET}")
        for i in range(0, len(rest), per_row):
            chunk = rest[i:i + per_row]
            line = "  " + "".join(f"{GRN}{c:<{col_w}}{RESET}" for c in chunk)
            print(line)
        print()

    print(f"{BOLD}Fall-through{RESET}")
    print(f"  Anything that's not a builtin is evaluated as Python. Examples:\n")
    print(f"    {CYN}2 + 2{RESET}                  → evaluate Python expression")
    print(f"    {CYN}import numpy as np{RESET}     → persistent import binding")
    print(f"    {CYN}for i in range(3): print(i){RESET} → Python statement")
    print(f"    {CYN}%print('raw py'){RESET}       → force Python eval (bypass shell)")
    print()
    print(f"{BOLD}Aliases{RESET}")
    if sh.aliases:
        for a, t in sorted(sh.aliases.items()):
            print(f"  {CYN}{a:<8}{RESET} → {t}")
    print()
    print(f"{DIM}Line editing: ↑/↓ history, ←/→ cursor, Ctrl-A/E home/end,{RESET}")
    print(f"{DIM}              Ctrl-U/K/W delete, Ctrl-C cancel, Ctrl-L clear.{RESET}")


@builtin("pwd")
def _pwd(sh: Shell, argv: List[str]) -> None:
    """pwd  — print the current working directory (absolute path)."""
    print(os.getcwd())


@builtin("cd")
def _cd(sh: Shell, argv: List[str]) -> None:
    """cd [path]  — change the current working directory.

    Special targets:
        cd         → go to $HOME (~/Documents)
        cd ~       → same
        cd -       → go to the previous directory ($OLDPWD)
        cd /tmp    → redirected to the app's writable tmp dir

    iOS sandbox: you can only cd into paths under $HOME, $TMPDIR, or
    the app container root. Attempting to leave that prints a friendly
    one-liner instead of the kernel's raw EPERM."""
    import tempfile

    if not argv or argv[0] == "~":
        target = sh.home
    elif argv[0] == "-":
        target = os.environ.get("OLDPWD", sh.home)
    else:
        target = os.path.expanduser(os.path.expandvars(argv[0]))
        # iOS: /tmp → per-app writable tmp dir.
        if target in ("/tmp", "/private/var/tmp"):
            target = tempfile.gettempdir()

    # Resolve to an absolute, normalized path so downstream checks and
    # error messages show a real path (not "..").
    try:
        current = os.getcwd()
    except OSError:
        current = sh.home
    abs_target = os.path.normpath(
        target if os.path.isabs(target) else os.path.join(current, target)
    )

    # Compute the iOS sandbox root — everything the app can freely
    # chdir into lives under one of these prefixes. If the resolved
    # target isn't under any of them, refuse with a friendly one-liner
    # instead of firing a raw EPERM error from the kernel.
    _sandbox_roots = []
    for _env in ("HOME", "TMPDIR"):
        _v = os.environ.get(_env)
        if _v:
            _sandbox_roots.append(os.path.realpath(_v))
    # The user's Documents folder is typically Home; the app container
    # root is one level up. Add the container root too so `cd ..` from
    # Documents lands somewhere readable.
    try:
        _container = os.path.dirname(os.path.realpath(sh.home))
        if _container and _container not in _sandbox_roots:
            _sandbox_roots.append(_container)
    except OSError:
        pass
    _real_abs = os.path.realpath(abs_target)
    in_sandbox = any(
        _real_abs == r or _real_abs.startswith(r + os.sep)
        for r in _sandbox_roots
    )

    if not in_sandbox:
        # Don't even try chdir — iOS would raise EPERM with a long
        # realpath error that looks scary. Print a clean hint instead,
        # referring to the sandbox roots by short names. If the path
        # doesn't even exist on disk, say that instead of blaming
        # the sandbox.
        exists = False
        try:
            exists = os.path.exists(abs_target)
        except OSError:
            exists = False
        if not exists:
            print(f"{RED}cd:{RESET} no such directory: {argv[0] if argv else target}")
        else:
            print(f"{RED}cd:{RESET} can't leave the app sandbox")
            print(f"{DIM}    (try `cd ~`, `cd ~/Documents`, or `cd $TMPDIR`){RESET}")
        return

    prev = current
    try:
        os.chdir(abs_target)
        # Verify we can actually READ the new cwd. On iOS you can
        # sometimes chdir into a directory (the kernel permits the
        # syscall) but then getcwd() fails because the resolver can't
        # walk the parent chain. If that happens, chdir back to the
        # previous dir so the REPL doesn't get stuck printing
        # "permission denied" on every subsequent prompt.
        try:
            _ = os.getcwd()
        except OSError:
            try:
                os.chdir(prev)
            except OSError:
                try:
                    os.chdir(sh.home)
                except OSError:
                    pass
            print(f"{RED}cd:{RESET} can't read that directory (iOS sandbox)")
            return
        os.environ["OLDPWD"] = prev
        os.environ["PWD"] = os.getcwd()
    except FileNotFoundError:
        print(f"{RED}cd:{RESET} no such directory: {argv[0] if argv else target}")
    except NotADirectoryError:
        print(f"{RED}cd:{RESET} not a directory: {argv[0] if argv else target}")
    except PermissionError:
        print(f"{RED}cd:{RESET} permission denied: {argv[0] if argv else target}")
    except OSError as e:
        # Catch-all — single clean line, never a traceback.
        msg = e.strerror or str(e)
        print(f"{RED}cd:{RESET} {msg}: {argv[0] if argv else target}")


def _list_entries(path: Path, show_hidden: bool) -> List[Path]:
    try:
        entries = list(path.iterdir())
    except (OSError, PermissionError) as e:
        print(f"{RED}ls:{RESET} {e.strerror}: {path}")
        return []
    if not show_hidden:
        entries = [e for e in entries if not e.name.startswith(".")]
    entries.sort(key=lambda p: (not p.is_dir(), p.name.lower()))
    return entries


@builtin("ls")
def _ls(sh: Shell, argv: List[str]) -> None:
    """ls [-l] [-a] [-h] [path…]  — list directory contents.

    Flags:
        -l    long form: permissions, size, mtime, name
        -a    include hidden (dotfile) entries
        -h    human-readable sizes (only meaningful with -l)

    Aliases:  ll = ls -lah    la = ls -a

    Directory names are shown in blue with a trailing /, regular files
    in the default color, executables are highlighted green."""
    long = "l" in "".join(a for a in argv if a.startswith("-") and not a.startswith("--"))
    show_hidden = "a" in "".join(a for a in argv if a.startswith("-"))
    human = "h" in "".join(a for a in argv if a.startswith("-"))
    paths = [a for a in argv if not a.startswith("-")] or ["."]
    for idx, p in enumerate(paths):
        base = Path(os.path.expanduser(p))
        if not base.exists():
            print(f"{RED}ls:{RESET} no such path: {p}")
            continue
        if base.is_file():
            _print_one(base, long=long, human=human)
            continue
        if len(paths) > 1:
            if idx: print()
            print(f"{BOLD}{base}:{RESET}")
        for entry in _list_entries(base, show_hidden):
            _print_one(entry, long=long, human=human)


def _print_one(p: Path, *, long: bool, human: bool) -> None:
    color = _color(p)
    name = p.name + ("/" if p.is_dir() else "")
    if not long:
        print(f"{color}{name}{RESET}")
        return
    try:
        st = p.lstat()
    except OSError:
        print(f"{color}{name}{RESET}"); return
    perms = _stat.filemode(st.st_mode)
    size = _fmt_size(st.st_size) if human else f"{st.st_size:>8d}"
    mtime = time.strftime("%b %d %H:%M", time.localtime(st.st_mtime))
    print(f"{GRAY}{perms}{RESET}  {size}  {GRAY}{mtime}{RESET}  {color}{name}{RESET}")


@builtin("cat")
def _cat(sh: Shell, argv: List[str]) -> None:
    """cat <file…>  — dump file contents to the terminal.

    Concatenates one or more files and prints them. Binary files are
    detected (via null-byte sniff) and replaced with a short summary
    instead of dumping gibberish into the terminal. For large files
    over ~1 MB, only the first/last 64 KB are shown with a truncation
    notice in the middle."""
    if not argv:
        print(f"{RED}cat:{RESET} usage: cat <file> [<file> …]")
        return
    for arg in argv:
        path = Path(os.path.expanduser(arg))
        try:
            data = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError) as e:
            print(f"{RED}cat:{RESET} {e}")
            continue
        # No syntax highlighting here — Pygments is optional.
        sys.stdout.write(data)
        if not data.endswith("\n"):
            sys.stdout.write("\n")


@builtin("head")
def _head(sh: Shell, argv: List[str]) -> None:
    """head [-n N] <file…>  — print the first N lines (default 10)."""
    n = 10
    args: List[str] = []
    it = iter(argv)
    for a in it:
        if a == "-n":
            try: n = int(next(it))
            except (StopIteration, ValueError):
                print(f"{RED}head:{RESET} -n needs an integer"); return
        elif a.startswith("-") and a[1:].isdigit():
            n = int(a[1:])
        else:
            args.append(a)
    if not args:
        print(f"{RED}head:{RESET} usage: head [-n N] <file>"); return
    for p in args:
        try:
            with open(os.path.expanduser(p)) as f:
                for i, line in enumerate(f):
                    if i >= n: break
                    sys.stdout.write(line)
        except OSError as e:
            print(f"{RED}head:{RESET} {e}")


@builtin("tail")
def _tail(sh: Shell, argv: List[str]) -> None:
    """tail [-n N] <file…>  — print the last N lines (default 10)."""
    n = 10
    args: List[str] = []
    it = iter(argv)
    for a in it:
        if a == "-n":
            try: n = int(next(it))
            except (StopIteration, ValueError):
                print(f"{RED}tail:{RESET} -n needs an integer"); return
        elif a.startswith("-") and a[1:].isdigit():
            n = int(a[1:])
        else:
            args.append(a)
    if not args:
        print(f"{RED}tail:{RESET} usage: tail [-n N] <file>"); return
    for p in args:
        try:
            with open(os.path.expanduser(p)) as f:
                lines = f.readlines()[-n:]
                sys.stdout.write("".join(lines))
        except OSError as e:
            print(f"{RED}tail:{RESET} {e}")


@builtin("mkdir")
def _mkdir(sh: Shell, argv: List[str]) -> None:
    """mkdir [-p] <dir…>  — create directories.

    Flags:
        -p    create intermediate directories as needed (no error if
              the leaf already exists)."""
    recursive = "-p" in argv
    args = [a for a in argv if not a.startswith("-")]
    for a in args:
        path = Path(os.path.expanduser(a))
        try:
            path.mkdir(parents=recursive, exist_ok=recursive)
        except OSError as e:
            print(f"{RED}mkdir:{RESET} {e}")


# ---------------------------------------------------------------------------
# Tombstone for deleted Workspace starter files
#
# Mirror of `FilesBrowserViewController.markStarterDeleted` on the Swift
# side. When the user deletes a direct child of ~/Documents/Workspace/
# (pip_demo.py, torch_test_all.py, etc.) we append the basename to
# `<Workspace>/.codebench_deleted`, and `ensureTorchTestTemplates` checks
# this set before re-seeding on next launch. Without this the files
# reappear after app restart — confusing and the frequent bug report.

def _mark_workspace_deletion(path: str) -> None:
    """If `path` is a direct child of ~/Documents/Workspace, append its
    basename to the tombstone so it won't be re-seeded on next launch.
    Silent no-op for paths outside Workspace or subdirectories of it.
    """
    try:
        abspath = os.path.abspath(os.path.expanduser(path))
    except OSError:
        return
    ws = os.path.abspath(os.path.expanduser("~/Documents/Workspace"))
    if os.path.dirname(abspath) != ws:
        return
    tomb = os.path.join(ws, ".codebench_deleted")
    name = os.path.basename(abspath)
    # Skip tombstone files themselves (current and legacy names) so
    # deleting the tombstone doesn't add itself to its successor.
    if not name or name.startswith(".codebench") or name.startswith(".offlinai"):
        return
    existing = ""
    try:
        with open(tomb, "r", encoding="utf-8") as f:
            existing = f.read()
    except OSError:
        pass
    names = {line.strip() for line in existing.splitlines() if line.strip()}
    if name in names:
        return
    sep = "" if (not existing or existing.endswith("\n")) else "\n"
    try:
        with open(tomb, "a", encoding="utf-8") as f:
            f.write(sep + name + "\n")
    except OSError:
        pass


@builtin("rm")
def _rm(sh: Shell, argv: List[str]) -> None:
    """rm [-r] [-f] <path…>  — remove files (or directories with -r).

    Flags:
        -r / -R   recurse into directories
        -f        don't error on missing files
        -rf       combined (also -fr)

    Caution: this is a permanent delete — the iOS sandbox has no
    Trash / Recycle Bin."""
    recursive = any(a in ("-r", "-rf", "-R", "-fr") for a in argv)
    force = any("f" in a for a in argv if a.startswith("-"))
    args = [a for a in argv if not a.startswith("-")]
    if not args:
        print(f"{RED}rm:{RESET} usage: rm [-rf] <path> …"); return
    for a in args:
        path = Path(os.path.expanduser(a))
        try:
            if path.is_dir() and not path.is_symlink():
                if not recursive:
                    print(f"{RED}rm:{RESET} {a} is a directory (use -r)"); continue
                shutil.rmtree(path)
            else:
                path.unlink()
            _mark_workspace_deletion(str(path))
        except FileNotFoundError:
            if not force:
                print(f"{RED}rm:{RESET} no such file: {a}")
        except OSError as e:
            print(f"{RED}rm:{RESET} {e}")


@builtin("rmdir")
def _rmdir(sh: Shell, argv: List[str]) -> None:
    """rmdir <dir…>  — remove empty directories.

    Fails if the directory is non-empty; use `rm -r` for that."""
    for a in argv:
        try:
            os.rmdir(os.path.expanduser(a))
            _mark_workspace_deletion(a)
        except OSError as e:
            print(f"{RED}rmdir:{RESET} {e}")


@builtin("touch")
def _touch(sh: Shell, argv: List[str]) -> None:
    """touch <file…>  — create empty files, or update mtime if they exist."""
    for a in argv:
        path = Path(os.path.expanduser(a))
        try:
            path.touch(exist_ok=True)
        except OSError as e:
            print(f"{RED}touch:{RESET} {e}")


@builtin("cp")
def _cp(sh: Shell, argv: List[str]) -> None:
    """cp [-r] <src…> <dst>  — copy files or directories.

    Flags:
        -r / -R   copy directories recursively

    Preserves mtime and mode where the iOS sandbox permits."""
    recursive = any(a in ("-r", "-R") for a in argv)
    args = [a for a in argv if not a.startswith("-")]
    if len(args) < 2:
        print(f"{RED}cp:{RESET} usage: cp [-r] <src> <dst>"); return
    *srcs, dst = (os.path.expanduser(a) for a in args)
    for src in srcs:
        try:
            if os.path.isdir(src):
                if not recursive:
                    print(f"{RED}cp:{RESET} {src} is a directory (use -r)"); continue
                shutil.copytree(src, dst)
            else:
                shutil.copy2(src, dst)
        except OSError as e:
            print(f"{RED}cp:{RESET} {e}")


@builtin("mv")
def _mv(sh: Shell, argv: List[str]) -> None:
    """mv <src…> <dst>  — move or rename a file/directory.

    If `dst` is an existing directory, `src` is moved into it (same
    as Unix mv). Otherwise `src` is renamed to `dst`."""
    if len(argv) < 2:
        print(f"{RED}mv:{RESET} usage: mv <src> <dst>"); return
    *srcs, dst = (os.path.expanduser(a) for a in argv)
    for src in srcs:
        try:
            shutil.move(src, dst)
        except OSError as e:
            print(f"{RED}mv:{RESET} {e}")


@builtin("echo")
def _echo(sh: Shell, argv: List[str]) -> None:
    """echo <args…>  — print arguments to stdout, space-separated."""
    print(" ".join(argv))


@builtin("env")
def _env(sh: Shell, argv: List[str]) -> None:
    """env  — print all environment variables, one per line (sorted)."""
    for k in sorted(os.environ):
        print(f"{CYN}{k}{RESET}={os.environ[k]}")


@builtin("export")
def _export(sh: Shell, argv: List[str]) -> None:
    """export NAME=VALUE [NAME=VALUE …]  — set environment variables.

    Only affects this session (and any Python code subsequently run
    in this interpreter). Doesn't persist across app restarts."""
    for a in argv:
        if "=" not in a:
            print(f"{RED}export:{RESET} expected NAME=VALUE, got {a!r}"); continue
        k, _, v = a.partition("=")
        os.environ[k] = v


@builtin("which")
def _which(sh: Shell, argv: List[str]) -> None:
    """which <name…>  — locate a command or module.

    Reports whether each name is a shell builtin, an alias, or a
    loaded Python module (with the module's __file__ path)."""
    for name in argv:
        if name in BUILTINS:
            print(f"{name}: shell builtin")
        elif name in sh.aliases:
            print(f"{name}: aliased to {sh.aliases[name]!r}")
        elif (mod := sys.modules.get(name)) is not None:
            src = getattr(mod, "__file__", "built-in")
            print(f"{name}: Python module at {src}")
        else:
            print(f"{RED}which:{RESET} {name} not found")


@builtin("date")
def _date(sh: Shell, argv: List[str]) -> None:
    """date  — print the current date and time in local timezone."""
    print(time.strftime("%a %b %d %H:%M:%S %Z %Y"))


@builtin("uptime")
def _uptime(sh: Shell, argv: List[str]) -> None:
    """uptime  — how long the shell REPL has been running."""
    d = int(time.time() - sh.start_time)
    h, d = divmod(d, 3600)
    m, s = divmod(d, 60)
    print(f"shell up {h}h {m}m {s}s")


@builtin("clear")
@builtin("cls")
def _clear(sh: Shell, argv: List[str]) -> None:
    """clear | cls  — wipe the terminal screen AND scrollback buffer.

    Sends ESC[3J ESC[2J ESC[H — same behaviour as macOS Terminal.app
    and iTerm2, which both clear scrollback on this sequence."""
    sys.stdout.write("\x1b[3J\x1b[2J\x1b[H")
    sys.stdout.flush()


@builtin("grep")
def _grep(sh: Shell, argv: List[str]) -> None:
    """grep [-i] <pattern> <file…>  — search for a regex in files.

    Flags:
        -i    case-insensitive match

    Output format: file:line_no: matching_line"""
    if len(argv) < 2:
        print(f"{RED}grep:{RESET} usage: grep [-i] <pattern> <file> …"); return
    import re
    flags = 0
    pat_args = list(argv)
    if pat_args and pat_args[0].startswith("-"):
        opt = pat_args.pop(0)
        if "i" in opt: flags |= re.IGNORECASE
    if len(pat_args) < 2:
        print(f"{RED}grep:{RESET} missing files"); return
    pattern = re.compile(pat_args[0], flags)
    for path in pat_args[1:]:
        try:
            with open(os.path.expanduser(path)) as f:
                for i, line in enumerate(f, 1):
                    if pattern.search(line):
                        sys.stdout.write(f"{BLU}{path}{RESET}:{GRN}{i}{RESET}: {line}")
        except OSError as e:
            print(f"{RED}grep:{RESET} {e}")


@builtin("find")
def _find(sh: Shell, argv: List[str]) -> None:
    """find [path] [-name] <pattern>  — recursively list matching files.

    Examples:
        find .                       # everything under cwd
        find . '*.py'                # every .py file
        find src -name '*.h'         # every .h file under src/"""
    if not argv:
        root, pattern = ".", "*"
    elif len(argv) == 1:
        root, pattern = argv[0], "*"
    else:
        root = argv[0]
        if argv[1] == "-name" and len(argv) >= 3:
            pattern = argv[2]
        else:
            pattern = argv[1]
    try:
        for base, dirs, files in os.walk(os.path.expanduser(root)):
            for name in dirs + files:
                if fnmatch.fnmatch(name, pattern):
                    print(os.path.join(base, name))
    except OSError as e:
        print(f"{RED}find:{RESET} {e}")


@builtin("tree")
def _tree(sh: Shell, argv: List[str]) -> None:
    """tree [path]  — display a directory as an ASCII tree.

    Hidden entries (dotfiles) are skipped. Directories come first,
    files second, both alphabetically sorted."""
    root = Path(os.path.expanduser(argv[0])) if argv else Path(".")

    def _walk(p: Path, prefix: str) -> None:
        try:
            entries = sorted(p.iterdir(), key=lambda x: (not x.is_dir(), x.name.lower()))
        except OSError:
            return
        entries = [e for e in entries if not e.name.startswith(".")]
        for i, entry in enumerate(entries):
            last = i == len(entries) - 1
            connector = "└── " if last else "├── "
            print(f"{prefix}{GRAY}{connector}{RESET}{_color(entry)}{entry.name}{RESET}")
            if entry.is_dir() and not entry.is_symlink():
                ext = "    " if last else "│   "
                _walk(entry, prefix + ext)

    print(f"{_color(root)}{root}{RESET}")
    _walk(root, "")


@builtin("wc")
def _wc(sh: Shell, argv: List[str]) -> None:
    """wc <file…>  — count lines, words, and characters.

    Output columns: lines, words, chars, filename."""
    for p in argv or ["-"]:
        try:
            text = (sys.stdin.read() if p == "-" else Path(os.path.expanduser(p)).read_text())
        except (OSError, UnicodeDecodeError) as e:
            print(f"{RED}wc:{RESET} {e}"); continue
        lines = text.count("\n")
        words = len(text.split())
        chars = len(text)
        print(f"  {lines:7d}  {words:7d}  {chars:7d}  {p}")


@builtin("history")
def _history(sh: Shell, argv: List[str]) -> None:
    """history  — reminder that arrow keys walk the command history.

    The actual history buffer lives in Swift's LineBuffer (so it
    survives even if Python is restarted). Use ↑/↓ in the terminal
    to navigate through previous commands."""
    print("History: press ↑ or ↓ in the terminal to recall previous commands.")


@builtin("exit")
@builtin("quit")
def _exit(sh: Shell, argv: List[str]) -> None:
    """exit | quit [CODE]  — close the CodeBench app.

    Optional CODE is the exit status (default 0). Calls `os._exit()`
    so the process actually terminates — Python's regular `sys.exit()`
    only raises SystemExit, which our REPL loop catches and ignores
    (because users hit Ctrl+D / type `exit` accidentally all the time
    and we don't want the shell to die from that).

    Note: Apple's HIG discourages apps quitting themselves; iOS
    normally expects users to background apps via the home gesture.
    This is a developer/power-user convenience — calling it from a
    public release won't pass App Store review.
    """
    code = 0
    if argv:
        try: code = int(argv[0])
        except ValueError:
            print(f"{RED}{argv[0]}{RESET}: not a numeric exit code"); return
    print(f"{DIM}(closing CodeBench…){RESET}")
    sys.stdout.flush()
    sys.stderr.flush()
    # _exit (vs sys.exit) bypasses SystemExit handling AND skips the
    # at-exit / finalizer chain — important on iOS because some
    # bundled C extensions (cairo, pango) crash inside their finalizers
    # when the runtime tears down. _exit is the surgical strike.
    os._exit(code)


# ---------------------------------------------------------------------------
# Running Python scripts: `python foo.py`

@builtin("python")
@builtin("python3")
def _python(sh: Shell, argv: List[str]) -> None:
    """Run a .py file, a -c snippet, or query the interpreter.

    Flags supported:
      -V, --version        → "Python X.Y.Z"
      -VV                  → full sys.version (build info, compiler, date)
      -c "<code>"          → execute the code string
      -m <module> [args…]  → run module as __main__
      -h, --help           → this help
      <file.py> [args…]    → run script
    Bare `python` with no args shows the version banner + a nudge to
    pass a script / -c. (No interactive REPL — the shell IS the
    Python REPL; typing bare Python executes it directly.)"""
    # Version flags — accept before any other processing. Real CPython
    # treats -V/--version as terminal: prints and exits. Match that.
    if argv and argv[0] in ("-V", "--version"):
        print(f"Python {sys.version.split()[0]}")
        return
    if argv and argv[0] == "-VV":
        # Real -VV shows sys.version (multi-line with compile info)
        # plus the build platform. Match CPython's output shape.
        print(sys.version)
        return

    # Bare `python` — show banner. Don't error; the user's reaching
    # for info, not trying to run something yet.
    if not argv:
        print(f"Python {sys.version.split()[0]} (in-process, "
              f"{sys.implementation.name})")
        print(f"{DIM}  Type Python at the shell prompt to run it directly — "
              f"the REPL is already here.{RESET}")
        print(f"{DIM}  `python <file.py>`, `python -c \"<code>\"`, "
              f"or `python --help` for more.{RESET}")
        return

    if _is_help_tok(argv[0]):
        print("usage: python [flag] <file.py> [arg …]")
        print("           | python -c \"<code>\" [arg …]")
        print("           | python -m <module> [arg …]")
        print()
        print("flags:")
        print("  -V, --version        print version and exit")
        print("  -VV                  verbose version (build info + compiler)")
        print("  -c <cmd>             run a single command")
        print("  -m <mod>             run a module as __main__")
        print("  -h, --help           this help")
        print()
        print(f"{DIM}Note: this is the in-process interpreter — the shell")
        print(f"itself is Python. No -i, -O, -S etc. (they don't apply).{RESET}")
        return

    if argv[0] == "-c":
        if len(argv) < 2:
            print(f"{RED}python -c:{RESET} expected argument"); return
        # Real Python: `python -c "code" arg1 arg2` exposes args as
        # sys.argv[0]="-c", sys.argv[1:]=["arg1", "arg2"]. Match that
        # so scripts that read sys.argv behave identically.
        code_str = argv[1]
        old_argv = sys.argv[:]
        sys.argv = ["-c", *argv[2:]]
        try:
            sh._run_python(code_str)
        finally:
            sys.argv = old_argv
        return

    if argv[0] == "-m":
        if len(argv) < 2:
            print(f"{RED}python -m:{RESET} expected module name"); return
        mod = argv[1]
        old_argv = sys.argv[:]
        sys.argv = [mod, *argv[2:]]
        try:
            runpy.run_module(mod, run_name="__main__", alter_sys=True)
        except SystemExit as e:
            code_ = e.code if isinstance(e.code, int) else (1 if e.code else 0)
            if code_:
                print(f"{DIM}[exit {code_}]{RESET}")
        except BaseException:
            traceback.print_exc()
        finally:
            sys.argv = old_argv
        return

    # Flags we accept-and-silently-ignore because they don't apply
    # to an in-process REPL but scripts / tooling still pass them.
    # Strip any such leading flags and retry with the remainder.
    IGNORED_FLAGS = {"-u", "-B", "-E", "-I", "-S", "-s", "-q",
                     "-O", "-OO", "-b", "-bb"}
    if argv[0] in IGNORED_FLAGS:
        _python(sh, argv[1:])
        return
    # Flag we reject loudly so the user isn't confused about why
    # their `python -i foo.py` didn't drop them at a prompt.
    if argv[0] == "-i":
        print(f"{RED}python -i:{RESET} interactive mode unavailable — "
              f"the shell already is the REPL.")
        return
    if argv[0].startswith("-"):
        print(f"{RED}python:{RESET} unsupported flag {argv[0]!r}. "
              f"See `python --help`.")
        return

    # Script path
    script = os.path.expanduser(argv[0])
    if not os.path.isfile(script):
        print(f"{RED}python:{RESET} no such file: {script}"); return
    old_argv = sys.argv[:]
    sys.argv = [script, *argv[1:]]
    try:
        runpy.run_path(script, run_name="__main__")
    except SystemExit as e:
        # Show exit code only if non-zero — keep output clean on success
        code_ = e.code if isinstance(e.code, int) else (1 if e.code else 0)
        if code_:
            print(f"{DIM}[exit {code_}]{RESET}")
    except BaseException:
        traceback.print_exc()
    finally:
        sys.argv = old_argv


# ---------------------------------------------------------------------------
# Running JavaScript: `js` REPL or `js -e "code"` or `js script.js`
#
# Backed by Swift's JSEngine (JavaScriptCore.framework). All JS runs in
# a long-lived JSContext so globals persist across REPL inputs the same
# way Node.js' interactive mode does. Communication uses the same file-
# IPC channel LaTeXEngine uses — write a request file with a unique id,
# wait for $TMPDIR/latex_signals/js_eval_resp_<id>.txt to appear.

def _js_eval(src: str, *, reset: bool = False, timeout: float = 30.0
             ) -> tuple[bool, str, str, str]:
    """Submit `src` to the Swift JSEngine and block until it answers.

    Returns (ok, stdout, result_or_empty, error_message).
    `result_or_empty` is the JSON-encoded return value (last expression),
    matching what `JSON.stringify(value, null, 2)` would produce. Empty
    string when ok is False.
    """
    import json as _json, tempfile as _tempfile, time as _time, uuid as _uuid
    sig_dir = os.path.join(_tempfile.gettempdir(), "latex_signals")
    os.makedirs(sig_dir, exist_ok=True)
    eval_id = _uuid.uuid4().hex
    req_path  = os.path.join(sig_dir, "js_eval_request.txt")
    resp_path = os.path.join(sig_dir, f"js_eval_resp_{eval_id}.txt")
    payload = _json.dumps({"id": eval_id, "src": src, "reset": reset})
    # Atomic write — the watcher polls every 50 ms and consumes whole files.
    tmp = req_path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        f.write(payload)
    os.replace(tmp, req_path)
    # Poll for the response file. 50 ms is the watcher's interval; sleep
    # 20 ms so we never miss a write window. Bail with a clear timeout
    # message if Swift never responds (engine not initialized, etc.).
    deadline = _time.time() + timeout
    while _time.time() < deadline:
        if os.path.exists(resp_path):
            try:
                with open(resp_path, "r", encoding="utf-8") as f:
                    resp = _json.load(f)
                os.remove(resp_path)
            except (OSError, _json.JSONDecodeError) as e:
                return False, "", "", f"failed to read response: {e}"
            ok = bool(resp.get("ok"))
            return (ok,
                    str(resp.get("stdout", "")),
                    str(resp.get("result", "")) if ok else "",
                    "" if ok else
                    f"{resp.get('error', '')}\n{resp.get('stack', '')}".rstrip())
        _time.sleep(0.02)
    return False, "", "", (
        "JS eval timed out — is JSEngine initialized? "
        "(JSEngine.shared.initialize() runs from GameViewController.viewDidLoad)")


@builtin("js")
@builtin("node")
def _js(sh: Shell, argv: List[str]) -> None:
    """js [script.js | -e "code" | --reset]  — JavaScript REPL / runner.

    Backed by JavaScriptCore (no JIT but plenty fast for scripting).
    A single long-lived JSContext per app launch — globals from one REPL
    input are visible to the next, same as Node's interactive mode.

    Available globals:
      console.{log,info,debug,warn,error}    — stdout/stderr
      fetch(url, opts)                       — sync (semaphore-blocked) HTTP
      fs.{readFileSync, writeFileSync,
          existsSync, readdirSync, unlinkSync}— scoped to ~/Documents
      setTimeout / setInterval / clear*      — uses the iOS RunLoop
      __documents__                          — absolute path to ~/Documents
      process.{platform, version, env, cwd()}— Node-shaped shim

    Flags:
      -e "<code>"      run a single expression / statement, print the result
      --reset          rebuild the JSContext (clears all globals)
      -h, --help       this help

    No args: drops into a multi-line REPL. Press Enter on a blank line to
    submit; `.exit` or Ctrl-D to leave.
    """
    if argv and _is_help_tok(argv[0]):
        print("usage: js [flag] <script.js> [arg …]")
        print("           | js -e \"<code>\"")
        print("           | js --reset")
        print("           | js              (interactive REPL)")
        print()
        print("flags:")
        print("  -e <code>      run a one-liner")
        print("  --reset        clear all JS globals (rebuilds JSContext)")
        print("  -h, --help     this help")
        print()
        print(f"{DIM}Backed by JavaScriptCore.framework — no JIT (iOS restriction),")
        print(f"but interpreted execution is plenty fast for REPL work.{RESET}")
        return

    if argv and argv[0] == "--reset":
        ok, _, _, err = _js_eval("", reset=True)
        if ok:
            print(f"{DIM}js: context reset — globals cleared{RESET}")
        else:
            print(f"{RED}js: reset failed:{RESET} {err}")
        return

    if argv and argv[0] == "-e":
        if len(argv) < 2:
            print(f"{RED}js -e:{RESET} expected code argument"); return
        ok, out, result, err = _js_eval(argv[1])
        if out:
            sys.stdout.write(out)
            if not out.endswith("\n"):
                sys.stdout.write("\n")
        if ok:
            if result and result not in ("undefined", "null"):
                print(result)
        else:
            print(f"{RED}{err}{RESET}")
        return

    if argv:
        # Treat as script file. Path resolution mirrors `python foo.py`:
        # absolute paths used as-is, relative paths resolved against the
        # shell's CWD.
        path = argv[0]
        if not os.path.isabs(path):
            path = os.path.join(os.getcwd(), path)
        if not os.path.exists(path):
            print(f"{RED}js:{RESET} file not found: {argv[0]}"); return
        try:
            with open(path, "r", encoding="utf-8") as f:
                src = f.read()
        except OSError as e:
            print(f"{RED}js:{RESET} {e}"); return
        ok, out, result, err = _js_eval(src)
        if out:
            sys.stdout.write(out)
            if not out.endswith("\n"):
                sys.stdout.write("\n")
        if not ok:
            print(f"{RED}{err}{RESET}")
        return

    # ─ Interactive REPL ─
    print(f"{DIM}js (JavaScriptCore — no JIT). Blank line submits, "
          f"`.exit` or Ctrl-D to quit.{RESET}")
    buffer: list[str] = []
    line_no = 1
    while True:
        try:
            prompt = f"{CYN if not buffer else DIM}js[{line_no}]{RESET}> "
            line = input(prompt) if not buffer else input(f"{DIM}     ... {RESET}")
        except (EOFError, KeyboardInterrupt):
            print()
            break
        stripped = line.strip()
        if not buffer and stripped in (".exit", ".quit"):
            break
        if not buffer and stripped == ".reset":
            ok, _, _, err = _js_eval("", reset=True)
            print(f"{DIM}context reset{RESET}" if ok else f"{RED}{err}{RESET}")
            line_no += 1
            continue
        if line == "":
            if not buffer:
                line_no += 1
                continue
            src = "\n".join(buffer)
            buffer.clear()
            ok, out, result, err = _js_eval(src)
            if out:
                sys.stdout.write(out)
                if not out.endswith("\n"):
                    sys.stdout.write("\n")
            if ok:
                if result and result not in ("undefined", "null"):
                    print(f"{DIM}=>{RESET} {result}")
            else:
                print(f"{RED}{err}{RESET}")
            line_no += 1
            continue
        buffer.append(line)


# ---------------------------------------------------------------------------
# pip runner — reuses the same in-process pip that the Packages tab uses.

def _canonicalize(name: str) -> str:
    """PEP 503 name normalization (lowercase, underscore/dot → dash)."""
    import re as _re
    return _re.sub(r"[-_.]+", "-", name).lower()


def _pkg_footprint(dist) -> tuple:
    """Walk the actual install directory of a dist and return
    (total_bytes, n_py, n_so, n_other, native_extensions_list).

    `Distribution.files` is unreliable — it reads RECORD which many
    installers omit (manim shows 3 files here; it actually has ~1800).
    Walk the filesystem instead, mirroring what `du -sh <pkg>` would do.
    """
    site_root = str(dist.locate_file("") or "")
    # Top-level packages + the .dist-info dir itself
    tops = set()
    try:
        tl = dist.read_text("top_level.txt") or ""
        for t in tl.splitlines():
            t = t.strip()
            if t: tops.add(t)
    except Exception:
        pass
    if not tops:
        # Fallback: assume the canonical package name is the top-level
        tops.add(_canonicalize(dist.metadata.get("Name") or "").replace("-", "_"))

    walk_dirs = []
    for t in tops:
        p = os.path.join(site_root, t)
        if os.path.isdir(p):
            walk_dirs.append(p)
        elif os.path.isfile(p + ".py"):
            walk_dirs.append(p + ".py")  # single-file module
    # Add the .dist-info dir
    try:
        di = str(getattr(dist, "_path", "")) or ""
        if di and os.path.isdir(di):
            walk_dirs.append(di)
    except Exception:
        pass

    total = n_py = n_so = n_other = 0
    sos = []
    for d in walk_dirs:
        if os.path.isfile(d):
            try:
                sz = os.path.getsize(d)
                total += sz
                if d.endswith(".py"): n_py += 1
                else: n_other += 1
            except OSError:
                pass
            continue
        for dp, _, fs in os.walk(d):
            # Skip __pycache__ — it's generated, not install footprint
            if os.path.basename(dp) == "__pycache__":
                continue
            for f in fs:
                fp = os.path.join(dp, f)
                try:
                    total += os.path.getsize(fp)
                except OSError:
                    continue
                if f.endswith(".py"):     n_py += 1
                elif f.endswith(".pyc"):  continue
                elif f.endswith((".so", ".dylib")):
                    n_so += 1
                    rel = os.path.relpath(fp, site_root)
                    sos.append(rel)
                else:
                    n_other += 1
    return total, n_py, n_so, n_other, sos


def _filter_and_bucket_requires(requires: list) -> tuple:
    """Parse PEP 508 requirement strings and split into (core, by_extra).

    - core: list of dep names that apply on the current runtime with no
      extras enabled. Deduplicated by canonical name.
    - by_extra: dict[extra_name] → list of dep names that are only
      pulled in when the user installs `pkg[<extra>]`.

    Uses `packaging.markers` / `packaging.requirements` when available;
    falls back to lightweight string parsing otherwise. The markers are
    evaluated against the actual runtime so e.g. `numpy>=...; python_version
    >= "3.10"` and `numpy<...; python_version < "3.10"` dedupe to one
    entry — matching uv's `evaluate_markers(&markers, &[])` behavior.
    """
    core_names = []
    seen_core = set()
    by_extra = {}
    try:
        from packaging.requirements import Requirement
        from packaging.markers import default_environment
    except ImportError:
        # Lightweight fallback — no marker eval, just bucket by "extra ==" substring
        for req in requires:
            head, _, marker = req.partition(";")
            dep = head.strip()
            for sep in (" ", ">", "<", "=", "!", "~", "["):
                dep = dep.split(sep, 1)[0]
            dep = dep.strip()
            if not dep:
                continue
            if 'extra ==' in marker:
                import re as _re
                m = _re.search(r"extra\s*==\s*['\"]([^'\"]+)['\"]", marker)
                if m:
                    by_extra.setdefault(m.group(1), []).append(dep)
                continue
            cn = _canonicalize(dep)
            if cn not in seen_core:
                seen_core.add(cn)
                core_names.append(dep)
        return core_names, by_extra

    base_env = default_environment()
    for req in requires:
        try:
            r = Requirement(req)
        except Exception:
            continue
        if r.marker is None:
            # No marker → unconditional dependency
            cn = _canonicalize(r.name)
            if cn not in seen_core:
                seen_core.add(cn)
                core_names.append(r.name)
            continue
        # Evaluate with no extras — catches core deps guarded by only
        # platform/python markers (e.g. "colorama; platform_system ==
        # 'Windows'" → drops on non-Windows)
        env_no_extra = {**base_env, "extra": ""}
        if r.marker.evaluate(env_no_extra):
            cn = _canonicalize(r.name)
            if cn not in seen_core:
                seen_core.add(cn)
                core_names.append(r.name)
            continue
        # Not a core dep → might be an extra. Parse the marker looking
        # for `extra == "<name>"` clauses and evaluate under each.
        marker_str = str(r.marker)
        import re as _re
        for extra in _re.findall(r"extra\s*==\s*['\"]([^'\"]+)['\"]", marker_str):
            env_with_extra = {**base_env, "extra": extra}
            if r.marker.evaluate(env_with_extra):
                by_extra.setdefault(extra, []).append(r.name)
                break
    # Dedup per-extra buckets too (same package under multiple markers)
    for k in list(by_extra):
        seen = set()
        uniq = []
        for n in by_extra[k]:
            cn = _canonicalize(n)
            if cn not in seen:
                seen.add(cn)
                uniq.append(n)
        by_extra[k] = uniq
    return core_names, by_extra


def _wrap_comma_list(names: list, indent: int = 4, width: int = 76) -> str:
    """Render a comma-separated list of names wrapped at `width` cols."""
    if not names:
        return ""
    out_lines = []
    cur = " " * indent
    prefix = " " * indent
    for i, n in enumerate(names):
        piece = n + ("," if i < len(names) - 1 else "")
        if cur != prefix and len(cur) + 1 + len(piece) > width:
            out_lines.append(cur.rstrip())
            cur = prefix
        if cur == prefix:
            cur += piece
        else:
            cur += " " + piece
    if cur.strip():
        out_lines.append(cur.rstrip())
    return "\n".join(out_lines)


def _pip_show_rich(argv: List[str]) -> bool:
    """Enhanced `pip show` that fixes three bugs in the default output:

    1. **Real on-disk size** — walks the actual install directory rather
       than trusting RECORD (which is incomplete for many wheels, giving
       absurd numbers like "11.2K / 3 files" for manim).
    2. **Marker-filtered dependencies** — `numpy >= X; python_version >=
       "3.10"` and `numpy < X; python_version < "3.10"` collapse to one
       entry, matching what actually applies on this runtime. Mirrors
       uv's `evaluate_markers` pattern.
    3. **Extras bucketed separately** — `[dev]`, `[jupyterlab]`, `[gui]`
       optional deps get their own section so the core Requires list
       isn't polluted.

    Called from the `pip` builtin when the verb is `show`. Returns True
    when it handled the command, False to let pip's native handler run
    (for example when the user passed flags we don't understand).
    """
    # Only handle the plain `pip show <pkg...>` form. If the user passed
    # flags like `-f` / `-v`, let pip's default handler run.
    pkgs = []
    for a in argv:
        if a.startswith("-"):
            return False
        pkgs.append(a)
    if not pkgs:
        return False

    try:
        from importlib import metadata as _md
    except ImportError:
        return False

    user_site = os.path.expanduser("~/Documents/site-packages")

    def is_bundled(location: str) -> bool:
        if not location:
            return False
        loc = os.path.realpath(location)
        return user_site not in loc and "/Documents/site-packages" not in loc

    # PyPI distribution name → Python module import name. Needed because
    # bundled iOS packages often ship as raw source dirs without proper
    # `.dist-info` metadata, so `importlib.metadata.distribution()` can't
    # find them — but they ARE importable. When dist lookup fails we fall
    # back to `find_spec()`, and for packages where the dist name differs
    # from the module name we consult this table.
    _DIST_TO_MODULE = {
        "pillow":             "PIL",
        "pyav":                "av",
        "pycairo":             "cairo",
        "mapbox-earcut":       "mapbox_earcut",
        "skia-pathops":        "pathops",
        "beautifulsoup4":      "bs4",
        "typing-extensions":   "typing_extensions",
        "huggingface-hub":     "huggingface_hub",
        "markdown-it-py":      "markdown_it",
        "charset-normalizer":  "charset_normalizer",
        "pyyaml":              "yaml",
        "google-api-python-client": "googleapiclient",
        "python-dateutil":     "dateutil",
        "opencv-python":       "cv2",
    }

    def dep_status(name: str) -> tuple:
        """Resolve a dependency's install status.

        Returns (status, version, kind) where status is 'ok' | 'missing' |
        'error'. Tries three locators in order:

          1. `importlib.metadata.distribution(name)` — works for anything
             installed with a real `.dist-info` dir.
          2. `importlib.util.find_spec(module_name)` — works for packages
             bundled as raw source without metadata (manimpango, pycairo,
             mapbox_earcut, skia_pathops as bundled in CodeBench).
          3. Falls back to 'missing'.

        The module-name fallback is critical on iOS where many packages
        ship without dist-info: manim's Requires-Dist lists `pycairo` but
        the bundle only has `cairo/` with no metadata — we still want to
        report that as installed, not missing.
        """
        # Step 1: dist-info lookup (gets us version + native/pure info)
        try:
            dist = _md.distribution(name)
            ver = dist.version or "?"
            site_root = str(dist.locate_file("") or "")
            tops = set()
            try:
                tl = dist.read_text("top_level.txt") or ""
                for t in tl.splitlines():
                    if t.strip(): tops.add(t.strip())
            except Exception:
                pass
            has_native = False
            for t in tops:
                p = os.path.join(site_root, t)
                if not os.path.isdir(p):
                    continue
                for dp, _, fs in os.walk(p):
                    if any(f.endswith((".so", ".dylib")) for f in fs):
                        has_native = True
                        break
                if has_native:
                    break
            return ("ok", ver, "native" if has_native else "pure python")
        except _md.PackageNotFoundError:
            pass
        except Exception:
            return ("error", None, None)

        # Step 2: module-level check — covers bundled-without-metadata
        # packages. Try the PEP 503 name directly, the underscored form,
        # and the known PyPI→module aliases.
        import importlib.util as _iu
        canonical = _canonicalize(name)
        candidates = [
            name,
            canonical.replace("-", "_"),
            _DIST_TO_MODULE.get(canonical, ""),
        ]
        for cand in candidates:
            if not cand:
                continue
            try:
                spec = _iu.find_spec(cand)
            except (ValueError, ImportError, ModuleNotFoundError):
                continue
            if spec is None:
                continue
            # Module resolvable. Try to detect native extensions in its dir.
            has_native = False
            kind = "pure python"
            origin = getattr(spec, "origin", None) or ""
            if origin.endswith((".so", ".dylib")):
                kind = "native"
            elif spec.submodule_search_locations:
                for loc in spec.submodule_search_locations:
                    try:
                        for fname in os.listdir(loc):
                            if fname.endswith((".so", ".dylib")):
                                has_native = True
                                break
                    except OSError:
                        pass
                    if has_native:
                        break
                if has_native:
                    kind = "native"
            return ("ok", None, f"{kind} (no dist-info)")

        return ("missing", None, None)

    def reverse_deps(pkg: str) -> list:
        """Who depends on <pkg>? Walks every installed distribution and
        checks its Requires-Dist list. Uses PEP 503 name canonicalization
        to match 'typing_extensions' and 'typing-extensions' together.
        """
        target = _canonicalize(pkg)
        try:
            from packaging.requirements import Requirement
        except ImportError:
            Requirement = None
        users = []
        for d in _md.distributions():
            for r in (d.requires or []):
                if Requirement is not None:
                    try:
                        head = Requirement(r).name
                    except Exception:
                        head = r
                else:
                    head = r.split(";", 1)[0].split("[", 1)[0]
                    for sep in (" ", ">", "<", "=", "!", "~"):
                        head = head.split(sep, 1)[0]
                if _canonicalize(head) == target:
                    users.append(d.metadata.get("Name") or "?")
                    break
        # Dedup + sort by canonical name
        out = []
        seen = set()
        for u in sorted(users, key=lambda x: _canonicalize(x)):
            cu = _canonicalize(u)
            if cu not in seen:
                seen.add(cu)
                out.append(u)
        return out

    for pkg in pkgs:
        try:
            dist = _md.distribution(pkg)
        except _md.PackageNotFoundError:
            print(f"{RED}pip show: package '{pkg}' is not installed{RESET}")
            continue
        meta = dist.metadata
        name = meta.get("Name") or pkg
        version = meta.get("Version") or dist.version or "?"
        summary = meta.get("Summary") or ""

        # Collect Project-URLs for a richer links section
        project_urls = {}
        for pu in (meta.get_all("Project-URL") or []):
            if "," in pu:
                label, url = pu.split(",", 1)
                project_urls[label.strip()] = url.strip()
        home = meta.get("Home-page") or project_urls.get("Homepage") \
               or project_urls.get("Home") or ""
        docs = project_urls.get("Documentation") or project_urls.get("Docs") or ""
        source = (project_urls.get("Repository") or project_urls.get("Source")
                  or project_urls.get("Source Code") or "")
        issues = project_urls.get("Bug Tracker") or project_urls.get("Issues") or ""

        author = meta.get("Author") or ""
        author_email = meta.get("Author-email") or ""
        if author_email and author:
            author_line = f"{author} <{author_email}>"
        elif author_email:
            author_line = author_email
        else:
            author_line = author
        license_ = meta.get("License") or meta.get("License-Expression") or ""
        license_ = license_.split("\n")[0][:80] if license_ else ""
        python_req = meta.get("Requires-Python") or "—"
        metadata_version = meta.get("Metadata-Version") or "?"
        location = str(dist.locate_file("") or "")

        # Accurate filesystem footprint (fixes the "3 files / 11.2K" bug)
        total_sz, n_py, n_so, n_other, sos = _pkg_footprint(dist)
        total_files = n_py + n_so + n_other

        # Marker-evaluated, deduped requires + extras buckets
        core_deps, extras = _filter_and_bucket_requires(dist.requires or [])
        rev = reverse_deps(name)

        # Entry points grouped by their group name
        grouped = {}
        for ep in dist.entry_points:
            grouped.setdefault(ep.group, []).append((ep.name, ep.value))

        # ── Render ────────────────────────────────────────────────
        bundled = is_bundled(location)
        tag = f"{GRN}bundled{RESET}" if bundled else f"{CYN}user-site{RESET}"

        # Header: "name version" with summary underneath
        print(f"{BOLD}{CYN}{name}{RESET} {BOLD}{version}{RESET}  {DIM}({tag}){RESET}")
        if summary:
            print(f"  {summary}")
        # Metadata line: license · Python requirement · metadata version
        bits = []
        if license_: bits.append(license_)
        if python_req and python_req != "—": bits.append(f"Python {python_req}")
        bits.append(f"Metadata {metadata_version}")
        print(f"  {DIM}{' · '.join(bits)}{RESET}")
        print()

        # URLs — only show lines that have a value
        url_rows = [
            ("Home", home),
            ("Docs", docs),
            ("Source", source),
            ("Issues", issues),
        ]
        url_rows = [(l, v) for l, v in url_rows if v]
        if url_rows or author_line:
            for label, val in url_rows:
                print(f"  {BOLD}{label:<8}{RESET} {val}")
            if author_line:
                print(f"  {BOLD}{'Author':<8}{RESET} {author_line}")
            print()

        # Install location + real filesystem footprint
        print(f"  {BOLD}{'Location':<8}{RESET} {location}")
        size_str = _human_bytes(total_sz)
        file_str = f"{total_files:,} files"
        breakdown = []
        if n_py:    breakdown.append(f"{n_py} py")
        if n_so:    breakdown.append(f"{n_so} native")
        if n_other: breakdown.append(f"{n_other} data")
        bd = f"  ({', '.join(breakdown)})" if breakdown else ""
        print(f"  {BOLD}{'Size':<8}{RESET} {size_str} in {file_str}{DIM}{bd}{RESET}")
        if sos:
            # Show up to 3 native extensions inline; full list under -v
            show_sos = sos[:3]
            more = f" … +{len(sos) - 3}" if len(sos) > 3 else ""
            print(f"  {DIM}         {', '.join(show_sos)}{more}{RESET}")
        print()

        # Core dependencies — names only, comma-wrapped. Marker filtering
        # means numpy/scipy/etc. appear exactly once. Resolve each dep's
        # install status ONCE and tint missing ones red.
        if core_deps:
            tagged = []
            missing_count = 0
            for d in core_deps:
                status, _ver, _kind = dep_status(d)
                if status == "missing":
                    missing_count += 1
                    tagged.append(f"{RED}{d}{RESET}")
                elif status == "error":
                    tagged.append(f"{YLW}{d}{RESET}")
                else:
                    tagged.append(d)
            suffix = f"  {DIM}({missing_count} missing){RESET}" if missing_count else ""
            print(f"  {BOLD}Requires ({len(core_deps)}){RESET}{suffix}")
            print(_wrap_comma_list(tagged, indent=4, width=76))
            print()
        else:
            print(f"  {BOLD}Requires{RESET}   {DIM}(none){RESET}")
            print()

        # Extras — one compact line per extra, sorted
        if extras:
            for extra in sorted(extras):
                names = extras[extra]
                label = f"Optional [{extra}]"
                line = _wrap_comma_list(names, indent=4, width=76)
                print(f"  {BOLD}{label}{RESET}  {DIM}({len(names)}){RESET}")
                print(line)
                print()

        # Reverse deps
        if rev:
            print(f"  {BOLD}Required-by ({len(rev)}){RESET}")
            print(_wrap_comma_list(rev, indent=4, width=76))
            print()
        else:
            print(f"  {BOLD}Required-by{RESET}  {DIM}(none — leaf package){RESET}")
            print()

        # Entry points
        if grouped:
            print(f"  {BOLD}Entry points{RESET}")
            for group, items in grouped.items():
                if group != "console_scripts":
                    print(f"    {DIM}[{group}]{RESET}")
                for n, v in items:
                    print(f"    {n:<24} = {v}")
            print()

    return True


@builtin("pip")
@builtin("pip3")
def _write_bundled_constraints_file(user_site: str) -> Optional[str]:
    """Generate a pip constraints file listing every bundled
    distribution at its bundled version, so pip's resolver treats
    the bundle as the source of truth instead of trying to upgrade
    native-extension libs that have no installable iOS wheel.

    "Bundled" = found via importlib.metadata but NOT in the user's
    writable site-packages dir. That covers app_packages/site-packages
    (the BeeWare-installed Python libs shipped with the binary) plus
    any stdlib distributions that report metadata.

    Cached at $TMPDIR/codebench_bundled_constraints.txt and only
    regenerated when the bundle's manifest mtime changes. Returns
    the absolute path, or None if metadata enumeration fails.
    """
    try:
        import importlib.metadata as _md
    except Exception:
        return None
    try:
        cache_dir = os.environ.get("TMPDIR", "/tmp")
        out_path = os.path.join(cache_dir, "codebench_bundled_constraints.txt")
        lines: List[str] = [
            "# Auto-generated by offlinai_shell._write_bundled_constraints_file.",
            "# Pins every bundled distribution to its bundled version so pip's",
            "# resolver doesn't try to upgrade native-extension libs that have",
            "# no installable iOS wheel. Regenerated on every `pip install`.",
            "",
        ]
        seen = set()
        for dist in _md.distributions():
            try:
                name = dist.metadata["Name"]
                version = dist.version
            except Exception:
                continue
            if not name or not version:
                continue
            key = name.lower().replace("_", "-")
            if key in seen:
                continue
            try:
                loc = str(dist.locate_file("") or "")
            except Exception:
                loc = ""
            # Skip user-installed packages — they're free to upgrade.
            if user_site and user_site in loc:
                continue
            if "/Documents/site-packages" in loc:
                continue
            seen.add(key)
            lines.append(f"{name}=={version}")
        with open(out_path, "w", encoding="utf-8") as f:
            f.write("\n".join(lines) + "\n")
        return out_path
    except Exception:
        return None


def _pip(sh: Shell, argv: List[str]) -> None:
    os.environ.setdefault("PIP_DISABLE_PIP_VERSION_CHECK", "1")
    os.environ.setdefault("PIP_NO_CACHE_DIR", "1")
    # Rich's auto-terminal detection causes pip to buffer and drop short
    # output (pip list, pip show) when running under our capture pipeline.
    # Turning color off puts pip on a plain text writer that streams.
    os.environ["PIP_NO_COLOR"]    = "1"
    os.environ["PYTHONUNBUFFERED"] = "1"

    user_site = os.path.expanduser("~/Documents/site-packages")
    os.makedirs(user_site, exist_ok=True)
    if user_site not in sys.path:
        sys.path.insert(0, user_site)

    try:
        from pip._internal.cli.main import main as pip_main
    except Exception as e:
        print(f"{RED}pip:{RESET} not available: {e}")
        return

    # Normalise help synonyms (--h, -H, help, -?, …) to --help before
    # handing off to pip's own argparse, which only recognises --help/-h.
    args = _normalize_help_arg(list(argv))

    # `pip install X` — three things to handle before delegating to pip:
    #   1) Skip packages that are already on sys.path (bundled or
    #      previously pip-installed). Using `--target user_site` makes
    #      pip blind to packages outside that dir, so it would otherwise
    #      re-download torch / numpy / matplotlib etc. that ship with
    #      the app.
    #   2) Don't auto-inject `--upgrade` — that turned every install
    #      into a force-redownload even when the user just wanted the
    #      current version. Only honour `-U`/`--upgrade` when the user
    #      actually typed it.
    #   3) Still inject `--target user_site` so pip writes to a
    #      writable dir (the app bundle is read-only).
    if args and args[0] == "install":
        rest = list(args[1:])
        wants_upgrade = ("-U" in rest or "--upgrade" in rest)
        wants_force = ("--force-reinstall" in rest)

        # Split flags from positional package specs (best-effort).
        # Anything starting with '-' (and the value following short
        # flags like `-r FILE`) is a flag/value; the rest are reqs.
        flags_with_value = {"-r", "--requirement", "-c", "--constraint",
                            "-i", "--index-url", "--extra-index-url",
                            "-f", "--find-links", "--target", "-t",
                            "--prefix", "--root", "--platform",
                            "--python-version", "--implementation",
                            "--abi", "--no-binary", "--only-binary",
                            "--report"}
        pkgs: List[str] = []
        i = 0
        while i < len(rest):
            tok = rest[i]
            if tok in flags_with_value:
                i += 2; continue
            if tok.startswith("-"):
                i += 1; continue
            pkgs.append(tok)
            i += 1

        # Check each spec against installed metadata. Strip the version
        # specifier so 'torch==2.1' still matches our 'torch-2.1.0'
        # dist-info — version-pinned installs always go through pip.
        if pkgs and not wants_upgrade and not wants_force:
            try:
                import importlib.metadata as _md
            except ImportError:
                _md = None  # very old python — fall through
            already: List[tuple] = []   # (display_name, version)
            missing: List[str] = []
            for spec in pkgs:
                # Pin / extras / URL → defer to pip, can't shortcut.
                if any(c in spec for c in "=<>!~ @"):
                    missing.append(spec); continue
                # `pkg[extra1,extra2]` → check the bare name.
                bare = spec.split("[", 1)[0].strip()
                if not bare:
                    missing.append(spec); continue
                try:
                    if _md is None:
                        raise ModuleNotFoundError("no importlib.metadata")
                    dist = _md.distribution(bare)
                    # Where does this dist-info live? Decides whether the
                    # "already satisfied" message says "bundled with
                    # CodeBench" (true) or "previously installed via pip"
                    # (also true, but doesn't lie about provenance). The
                    # earlier code labelled EVERYTHING bundled, which was
                    # wrong: a user-installed httpx in
                    # ~/Documents/site-packages/ was confusingly tagged
                    # as a CodeBench bundled lib.
                    try:
                        loc = str(dist.locate_file("") or "")
                    except Exception:
                        loc = ""
                    is_user_site = (user_site in loc) or ("/Documents/site-packages" in loc)
                    already.append((dist.metadata["Name"] or bare,
                                    dist.version, is_user_site))
                except Exception:
                    # PackageNotFoundError extends ModuleNotFoundError →
                    # ImportError, NOT LookupError. Catching `Exception` is
                    # the safe move — any failure during the metadata lookup
                    # just means "treat it as missing, defer to pip", which
                    # is the same behavior we want for genuine cache misses
                    # AND for unexpected errors (corrupted dist-info, etc.).
                    missing.append(spec)

            for name, ver, is_user_site in already:
                # Match real-pip's wording for the leading text so scripts
                # that grep for it keep working. Distinguish bundled-app
                # vs user-installed in the trailing comment.
                origin = ("previously installed via pip"
                          if is_user_site else "bundled with CodeBench")
                print(f"Requirement already satisfied: {name} ({ver}) "
                      f"{DIM}— {origin}{RESET}")

            if not missing:
                # Every requested package is already on sys.path —
                # nothing to do. Short-circuit so pip doesn't fire.
                return
            # Some packages still need installing — narrow the install
            # to just those. Preserve the original flags / positions.
            new_rest = []
            i = 0
            while i < len(rest):
                tok = rest[i]
                if tok in flags_with_value:
                    new_rest += [tok, rest[i + 1] if i + 1 < len(rest) else ""]
                    i += 2; continue
                if tok.startswith("-"):
                    new_rest.append(tok); i += 1; continue
                if tok in missing:
                    new_rest.append(tok)
                i += 1
            rest = new_rest

        if "--target" not in rest and "-t" not in rest:
            rest = ["--target", user_site, "--no-warn-script-location"] + rest

        # Force binary-only resolution unless the user explicitly opted
        # into building from source. iOS can't fork/exec or run a C/Rust
        # compiler, so any sdist install will hit
        # `[Errno 45] ios does not support processes` deep inside pip's
        # build-isolation step — wasting bandwidth + a confusing error
        # message. With `--only-binary :all:`, pip refuses to fall back
        # to sdists and gives a fast, clear "Could not find a version
        # that satisfies the requirement" if no wheel is available.
        # Power users who really want to try (e.g. a pure-Python sdist)
        # can pass `--no-binary :all:` to override.
        if not any(t == "--no-binary" or t == "--only-binary" for t in rest):
            rest = ["--only-binary", ":all:"] + rest

        # Auto-inject --upgrade when --target is in play. With --target
        # set, pip refuses to overwrite existing files in that directory
        # unless --upgrade is present — without it you get a wall of
        # `WARNING: Target directory ... already exists. Specify
        # --upgrade to force replacement.` lines on every re-install.
        # We're already shoving everything into ~/Documents/site-packages
        # (the only writable location), so the user almost always wants
        # the new copy to replace whatever's there. Skip if the user
        # already passed -U/--upgrade explicitly (avoids duplicating).
        if "--upgrade" not in rest and "-U" not in rest:
            rest = ["--upgrade"] + rest

        # Suppress pip's "dependency conflicts" final report. Bundled
        # libs sometimes carry stricter version pins in their METADATA
        # than they actually need at runtime — manim 0.19.0 declares
        # `av<14.0.0` but works fine with our bundled av 17.0.1; same
        # story for several huggingface/torch deps. The warnings are
        # noisy for users who can't downgrade the bundled versions
        # anyway. They're not silenced for legitimate user-installed
        # conflicts because pip still raises them at *resolve* time
        # (the post-install summary is what we hide here).
        if "--no-warn-conflicts" not in rest:
            rest = ["--no-warn-conflicts"] + rest

        # Bundled-deps constraints file. iOS can't compile from sdist
        # and most native-extension wheels (numpy, scipy, torch, av,
        # manim, sklearn, …) ship bundled with the app — there's
        # literally no way to upgrade them at runtime. When a newly-
        # requested package's resolver wants a different version,
        # without constraints pip wastes time downloading huge tarballs
        # only to fail at install. Generate a constraints file pinning
        # every bundled distribution to its bundled version so pip's
        # resolver respects the bundle as the source of truth and only
        # fetches what's actually missing.
        if "-c" not in rest and "--constraint" not in rest:
            constraints_path = _write_bundled_constraints_file(user_site)
            if constraints_path:
                rest = ["-c", constraints_path] + rest

        args = [args[0], *rest]

    # `pip show <pkg>` — intercept plain form (no flags) and render our
    # richer view that includes disk size, file counts, native-.so list,
    # dep health markers, reverse deps, and entry points. Power users
    # passing flags like `-f` or `--files` fall through to native pip.
    if args and args[0] == "show":
        if _pip_show_rich(args[1:]):
            return

    # pip's root logger keeps a stale StreamHandler between calls in a
    # long-lived interpreter, so subsequent calls print nothing. Wipe
    # every pip-owned logger's handler list so pip re-attaches fresh
    # handlers targeting our captured stdout/stderr.
    import logging
    for _name in list(logging.Logger.manager.loggerDict):
        if _name.startswith("pip"):
            _lg = logging.getLogger(_name)
            _lg.handlers.clear()
            _lg.propagate = True
    logging.getLogger("pip").setLevel(logging.INFO)

    # For "read" commands that produce small one-shot output (pip list,
    # show, freeze, check, config, debug, help, --version), also capture
    # stdout/stderr explicitly so anything pip writes through its internal
    # rich.Console or click.echo reaches our terminal even if it doesn't
    # go through the real sys.stdout.
    capture_cmds = {
        "list", "show", "freeze", "check", "config", "debug",
        "help", "hash", "completion", "--version", "-V",
    }
    should_capture = bool(args) and (args[0] in capture_cmds or args[0].startswith("-"))

    rc = 0
    if should_capture:
        import io, contextlib
        buf, errbuf = io.StringIO(), io.StringIO()
        try:
            with contextlib.redirect_stdout(buf), contextlib.redirect_stderr(errbuf):
                rc = pip_main(args)
        except SystemExit as e:
            rc = int(e.code) if e.code is not None else 0
        except KeyboardInterrupt:
            # Flush whatever pip had printed up to the interrupt so the
            # user sees partial progress, then re-raise so the REPL can
            # surface its ^C indicator.
            out, err = buf.getvalue(), errbuf.getvalue()
            if out: sys.stdout.write(out)
            if err: sys.stderr.write(err)
            sys.stdout.flush(); sys.stderr.flush()
            raise
        out, err = buf.getvalue(), errbuf.getvalue()
        if out:
            sys.stdout.write(out)
            if not out.endswith("\n"):
                sys.stdout.write("\n")
        if err:
            sys.stderr.write(err)
            if not err.endswith("\n"):
                sys.stderr.write("\n")
        if not out and not err and rc == 0:
            # No output at all — show a friendly note so the user knows
            # the command actually ran.
            print(f"{DIM}(pip {' '.join(args)} produced no output){RESET}")
    else:
        # Streaming commands (install, download, wheel, uninstall): let
        # pip write directly so the progress bar + per-step log lines
        # reach the terminal live.
        try:
            rc = pip_main(args)
        except SystemExit as e:
            rc = int(e.code) if e.code is not None else 0
        except KeyboardInterrupt:
            sys.stdout.flush(); sys.stderr.flush()
            raise

    sys.stdout.flush()
    sys.stderr.flush()

    if rc:
        print(f"{YLW}pip exited with code {rc}{RESET}")

    # Refresh import caches so freshly-installed packages become
    # visible without restarting the interpreter.
    try:
        import importlib
        importlib.invalidate_caches()
    except Exception:
        pass


# ---------------------------------------------------------------------------
# Disk usage — du, df, ncdu, stat

def _human_bytes(n: int) -> str:
    """Pretty-print a byte count like `du -h` does."""
    if n < 1024: return f"{n}B"
    units = ["K", "M", "G", "T", "P"]
    x = float(n)
    for u in units:
        x /= 1024
        if x < 1024:
            return f"{x:.1f}{u}"
    return f"{x:.1f}P"


def _dir_size(path: str) -> int:
    """Total bytes under `path` (files + subdir files). Silent on
    permission errors — iOS has many."""
    total = 0
    try:
        with os.scandir(path) as it:
            for entry in it:
                try:
                    if entry.is_symlink():
                        continue
                    if entry.is_file(follow_symlinks=False):
                        total += entry.stat(follow_symlinks=False).st_size
                    elif entry.is_dir(follow_symlinks=False):
                        total += _dir_size(entry.path)
                except OSError:
                    continue
    except OSError:
        pass
    return total


@builtin("du")
def _du(sh: Shell, argv: List[str]) -> None:
    """du [-s] [-h] [path]  — disk usage of directories.
    -s  summary (just the grand total, not per-subdir)
    -h  human-readable sizes (default on)
    """
    summary_only = "-s" in argv
    targets = [a for a in argv if not a.startswith("-")] or ["."]

    for tgt in targets:
        p = os.path.abspath(os.path.expanduser(tgt))
        if not os.path.exists(p):
            print(f"{RED}du:{RESET} no such path: {tgt}")
            continue
        if os.path.isfile(p):
            try:
                print(f"{_human_bytes(os.path.getsize(p)):>8}  {tgt}")
            except OSError as e:
                print(f"{RED}du:{RESET} {e.strerror}: {tgt}")
            continue

        total = 0
        if not summary_only:
            try:
                with os.scandir(p) as it:
                    for entry in sorted(it, key=lambda e: e.name):
                        if entry.name.startswith("."):
                            continue
                        try:
                            if entry.is_dir(follow_symlinks=False):
                                sz = _dir_size(entry.path)
                            elif entry.is_file(follow_symlinks=False):
                                sz = entry.stat(follow_symlinks=False).st_size
                            else:
                                continue
                            total += sz
                            print(f"{_human_bytes(sz):>8}  {entry.name}")
                        except OSError:
                            continue
            except OSError as e:
                print(f"{RED}du:{RESET} {e.strerror}: {tgt}")
                continue
        else:
            total = _dir_size(p)
        print(f"{BOLD}{_human_bytes(total):>8}{RESET}  {tgt}")


@builtin("df")
def _df(sh: Shell, argv: List[str]) -> None:
    """df — free space on the app sandbox filesystem."""
    import shutil
    paths = [a for a in argv if not a.startswith("-")] or [sh.home]
    for p in paths:
        try:
            usage = shutil.disk_usage(os.path.expanduser(p))
        except OSError as e:
            print(f"{RED}df:{RESET} {e.strerror}: {p}")
            continue
        print(f"{BOLD}Filesystem      Size   Used   Free  Use%  Mounted on{RESET}")
        used_pct = (usage.used * 100 / usage.total) if usage.total else 0
        print(f"iOS sandbox  {_human_bytes(usage.total):>6} "
              f"{_human_bytes(usage.used):>6} "
              f"{_human_bytes(usage.free):>6} "
              f"{used_pct:>4.0f}%  {p}")


def _ncdu_scan(path: str, show_hidden: bool, sort_mode: str) -> List[tuple]:
    """Scan a directory → list of (size, name, is_dir, mtime).
    Sort modes: 'size' (desc), 'name' (asc), 'mtime' (desc)."""
    entries: List[tuple] = []
    try:
        with os.scandir(path) as it:
            for entry in it:
                if not show_hidden and entry.name.startswith("."):
                    continue
                try:
                    st = entry.stat(follow_symlinks=False)
                    if entry.is_dir(follow_symlinks=False):
                        sz = _dir_size(entry.path)
                        entries.append((sz, entry.name, True, st.st_mtime))
                    elif entry.is_file(follow_symlinks=False):
                        entries.append((st.st_size, entry.name, False, st.st_mtime))
                except OSError:
                    continue
    except OSError:
        pass
    if sort_mode == "name":
        entries.sort(key=lambda e: e[1].lower())
    elif sort_mode == "mtime":
        entries.sort(key=lambda e: e[3], reverse=True)
    else:
        entries.sort(reverse=True)
    return entries


def _ncdu_human_mib(n: int) -> str:
    """Format bytes using the KiB/MiB/GiB convention real ncdu uses."""
    if n < 1024:
        return f"{n:>5.0f}   B"
    x = float(n) / 1024
    for unit in ("KiB", "MiB", "GiB", "TiB", "PiB"):
        if x < 1024:
            return f"{x:>5.1f} {unit}"
        x /= 1024
    return f"{x:>5.1f} PiB"


# Terminal width — used to size the bar column so the status bars
# and selected-row inverse-video stripe extend across the viewport.
_NCDU_WIDTH = 80


def _ncdu_draw(path: str, entries: List[tuple], show_hidden: bool,
               parent_ok: bool, sort_mode: str, selected: int,
               page_start: int, rows: int) -> None:
    """Pixel-for-pixel match to real ncdu 2.x visual layout.

    Layout:
        ┌─ inverse video ─────────────────────────────────────────────┐
        │ ncdu 1.x ~ Use the arrow keys to navigate, press ? for help │
        └─────────────────────────────────────────────────────────────┘
        --- /path/here -------------------------------------------
          SIZE UNIT [##########] name-or-/dirname
          …
        ┌─ inverse video ─────────────────────────────────────────────┐
        │ *Total disk usage:  X MiB  Apparent size: Y MiB  Items: N  │
        └─────────────────────────────────────────────────────────────┘
    """
    sys.stdout.write("\x1b[2J\x1b[H")

    # ── Top status bar (inverse video) ──
    title = "ncdu 1.1 ~ Use the arrow keys to navigate, press ? for help"
    sys.stdout.write(f"\x1b[7m {title:<{_NCDU_WIDTH - 1}}\x1b[0m\r\n")

    # ── Path separator ──
    dash_path = f"--- {path} "
    if len(dash_path) < _NCDU_WIDTH:
        dash_path = dash_path + "-" * (_NCDU_WIDTH - len(dash_path))
    else:
        # Path too long — truncate keeping the tail visible
        head = f"--- ..."
        tail_len = _NCDU_WIDTH - len(head) - 1
        dash_path = head + path[-tail_len:] + " "
    sys.stdout.write(f"{dash_path}\r\n")

    # ── Entries ──
    if not entries:
        sys.stdout.write(" (empty directory)\r\n")
    else:
        max_sz = max((e[0] for e in entries), default=0) or 1
        bar_w = 20
        end = min(page_start + rows, len(entries))
        for idx in range(page_start, end):
            sz, name, is_dir, _mt = entries[idx]
            bar_len = int(bar_w * sz / max_sz) if max_sz else 0
            bar = "#" * bar_len + " " * (bar_w - bar_len)
            # Real ncdu prefix convention: "/name" for directories,
            # bare "name" for files, leading two spaces for alignment.
            label = ("/" + name) if is_dir else ("  " + name)
            line = f" {_ncdu_human_mib(sz)} [{bar}] {label}"
            # Pad to full width so inverse-video stripe extends edge-to-edge
            if len(line) < _NCDU_WIDTH:
                line = line + " " * (_NCDU_WIDTH - len(line))
            if idx == selected:
                sys.stdout.write(f"\x1b[7m{line}\x1b[0m\r\n")
            else:
                sys.stdout.write(f"{line}\r\n")
        if end < len(entries):
            more = f" ... {len(entries) - end} more below ..."
            sys.stdout.write(f"{more}\r\n")

    # ── Pad vertical space so footer stays at the bottom of
    # the viewport — approximation for fixed 24-row terminal. ──
    rendered_rows = 2 + (min(len(entries), rows) if entries else 1) + (
        1 if entries and page_start + rows < len(entries) else 0
    )
    # Fill remaining lines up to row 22 so status bar stays "pinned"
    fill = max(0, 22 - rendered_rows)
    for _ in range(fill):
        sys.stdout.write("\r\n")

    # ── Bottom status bar (inverse video) ──
    total = sum(e[0] for e in entries) if entries else 0
    # "Apparent size" ≈ total for our purposes (we don't use st_blocks).
    footer = (f"*Total disk usage: {_ncdu_human_mib(total).strip()}   "
              f"Apparent size: {_ncdu_human_mib(total).strip()}   "
              f"Items: {len(entries)}")
    if len(footer) < _NCDU_WIDTH:
        footer = footer + " " * (_NCDU_WIDTH - len(footer))
    sys.stdout.write(f"\x1b[7m{footer}\x1b[0m\r\n")

    # No extra hint line — real ncdu doesn't have one. The top status
    # bar already says "press ? for help". We now have real raw-mode
    # arrow-key input so users don't need a line-mode cheat sheet.
    sys.stdout.flush()


# ── TUI raw-mode helpers ──────────────────────────────────────────
# Swift's LineBuffer is line-buffered by default (cooked mode). TUI
# apps that need instant keystrokes write our private OSC sequence
# to switch Swift into raw mode, then switch back on exit. Always
# wrap with try/finally so a crash restores cooked mode.

_TUI_RAW_MODE = "\x1b]codebench;raw\x1b\\"
_TUI_COOKED_MODE = "\x1b]codebench;cooked\x1b\\"


def tui_enter_raw() -> None:
    sys.stdout.write(_TUI_RAW_MODE)
    sys.stdout.flush()


def tui_exit_raw() -> None:
    sys.stdout.write(_TUI_COOKED_MODE)
    sys.stdout.flush()


def _tui_read_key() -> str:
    """Read one keypress in raw mode. Returns a symbolic name:
    'up' 'down' 'left' 'right' 'enter' 'esc' 'backspace' 'tab'
    or the single character for printable keys. Parses CSI escape
    sequences for arrow keys + Home/End/Delete."""
    try:
        b = os.read(0, 1)
    except OSError:
        return ""
    if not b:
        return ""
    c = b[0]
    if c == 0x1B:
        # Escape sequence: read up to 8 more bytes non-blocking-ish
        # (under raw mode all arrive together in a single read burst).
        seq = b""
        for _ in range(8):
            try:
                nx = os.read(0, 1)
            except OSError:
                break
            if not nx:
                break
            seq += nx
            # CSI final byte in 0x40..0x7E terminates
            if seq and 0x40 <= seq[-1] <= 0x7E and len(seq) > 1:
                break
            # Single-char SS3 (ESC O X) or bare ESC
            if len(seq) >= 2:
                break
        if not seq:
            return "esc"
        if seq[:1] == b"[":
            tail = seq[1:]
            if tail == b"A": return "up"
            if tail == b"B": return "down"
            if tail == b"C": return "right"
            if tail == b"D": return "left"
            if tail == b"H": return "home"
            if tail == b"F": return "end"
            if tail == b"3~": return "delete"
            if tail == b"5~": return "pageup"
            if tail == b"6~": return "pagedown"
            return "esc[" + tail.decode("ascii", errors="ignore")
        if seq[:1] == b"O":
            tail = seq[1:2]
            if tail == b"A": return "up"
            if tail == b"B": return "down"
            if tail == b"C": return "right"
            if tail == b"D": return "left"
        return "esc"
    if c == 0x0D or c == 0x0A:
        return "enter"
    if c == 0x7F or c == 0x08:
        return "backspace"
    if c == 0x09:
        return "tab"
    if c == 0x03:
        return "ctrl-c"
    if c == 0x04:
        return "ctrl-d"
    if c < 0x20:
        return f"ctrl-{chr(c + 0x40).lower()}"
    # UTF-8: read continuation bytes if the lead indicates multi-byte
    if c >= 0xC0:
        extra = 1 if c < 0xE0 else (2 if c < 0xF0 else 3)
        rest = b""
        for _ in range(extra):
            try:
                nx = os.read(0, 1)
            except OSError:
                break
            if not nx:
                break
            rest += nx
        try:
            return (bytes([c]) + rest).decode("utf-8", errors="replace")
        except Exception:
            return ""
    return chr(c)


@builtin("ncdu")
def _ncdu(sh: Shell, argv: List[str]) -> None:
    """ncdu [path]  — real ncurses-style interactive disk-usage browser
    with raw-mode arrow-key navigation (matches real ncdu behavior).

    Keys:
      ↑↓ or j/k        move cursor            ←/h   parent directory
      →/enter/l        open dir / info        d     delete (confirm)
      i                info (stat)            r     recalculate
      s                cycle sort order       .     toggle hidden
      b                shell at cwd           q     quit
    """
    import sys as _sys
    start = os.path.abspath(os.path.expanduser(argv[0])) if argv else os.getcwd()
    if not os.path.isdir(start):
        print(f"{RED}ncdu:{RESET} not a directory: {start}")
        return

    show_hidden = False
    try:
        sandbox_root = os.path.realpath(sh.home)
    except OSError:
        sandbox_root = start

    path = start
    sort_modes = ("size", "name", "mtime")
    sort_idx = 0
    selected = 0
    page_start = 0
    rows = 18

    def scan():
        return _ncdu_scan(path, show_hidden, sort_modes[sort_idx])

    entries = scan()

    # Switch to the alternate screen buffer so ncdu's frames don't
    # flood scrollback, exactly like real ncdu / vim / less do. On
    # exit we restore, so the user's original terminal content comes
    # back unchanged.
    _sys.stdout.write("\x1b[?1049h\x1b[?25l")
    _sys.stdout.flush()
    # Enter raw mode so arrow keys reach us as escape sequences.
    # Wrap in try/finally so a crash always restores cooked mode AND
    # the main screen buffer.
    tui_enter_raw()
    try:
        while True:
            parent = os.path.dirname(path)
            parent_ok = (parent != path) and (
                parent == sandbox_root or parent.startswith(sandbox_root + os.sep)
            )
            if not entries:
                selected = 0
            else:
                selected = max(0, min(selected, len(entries) - 1))
            if selected < page_start:
                page_start = selected
            if selected >= page_start + rows:
                page_start = selected - rows + 1

            _ncdu_draw(path, entries, show_hidden, parent_ok,
                       sort_modes[sort_idx], selected, page_start, rows)

            key = _tui_read_key()

            if key in ("q", "ctrl-c", "ctrl-d"):
                break
            elif key in ("down", "j"):
                selected += 1
            elif key in ("up", "k"):
                selected -= 1
            elif key in ("pagedown",):
                selected += rows
            elif key in ("pageup",):
                selected -= rows
            elif key == "home":
                selected = 0
            elif key == "end":
                selected = max(0, len(entries) - 1)
            elif key in ("left", "h", "backspace"):
                # 'h' as a key here = parent dir, matches real ncdu.
                if parent_ok:
                    path = parent
                    entries = scan()
                    selected, page_start = 0, 0
            elif key in ("right", "enter", "l"):
                if not entries:
                    continue
                sz, name, is_dir, _mt = entries[selected]
                if is_dir:
                    path = os.path.join(path, name)
                    entries = scan()
                    selected, page_start = 0, 0
                else:
                    # Exit raw mode temporarily to show stat + wait
                    tui_exit_raw()
                    _sys.stdout.write("\x1b[2J\x1b[H")
                    _stat_cmd(sh, [os.path.join(path, name)])
                    _sys.stdout.write(f"\n{DIM}(press any key to return){RESET} ")
                    _sys.stdout.flush()
                    tui_enter_raw()
                    _tui_read_key()
            elif key == "i":
                if not entries:
                    continue
                _, name, _id, _mt = entries[selected]
                tui_exit_raw()
                _sys.stdout.write("\x1b[2J\x1b[H")
                _stat_cmd(sh, [os.path.join(path, name)])
                _sys.stdout.write(f"\n{DIM}(press any key to return){RESET} ")
                _sys.stdout.flush()
                tui_enter_raw()
                _tui_read_key()
            elif key == "r":
                entries = scan()
            elif key == "s":
                sort_idx = (sort_idx + 1) % len(sort_modes)
                entries = scan()
            elif key == ".":
                show_hidden = not show_hidden
                entries = scan()
                selected, page_start = 0, 0
            elif key == "d":
                if not entries:
                    continue
                _, name, is_dir, _mt = entries[selected]
                target = os.path.join(path, name)
                # Inline confirmation prompt in raw mode — read one key.
                tui_exit_raw()
                _sys.stdout.write(
                    f"\r\n{RED}Delete {'dir ' if is_dir else 'file '}{name}? "
                    f"(y/N): {RESET}"
                )
                _sys.stdout.flush()
                tui_enter_raw()
                ck = _tui_read_key()
                if ck == "y":
                    import shutil
                    try:
                        if is_dir:
                            shutil.rmtree(target)
                        else:
                            os.unlink(target)
                        _mark_workspace_deletion(target)
                        entries = scan()
                        if selected >= len(entries):
                            selected = max(0, len(entries) - 1)
                    except OSError as e:
                        tui_exit_raw()
                        _sys.stdout.write(f"\r\n{RED}delete failed: {e}{RESET}\r\n")
                        _sys.stdout.write(f"{DIM}(press any key){RESET} ")
                        _sys.stdout.flush()
                        tui_enter_raw()
                        _tui_read_key()
            elif key == "b":
                saved = os.getcwd()
                try: os.chdir(path)
                except OSError: pass
                tui_exit_raw()
                _sys.stdout.write("\x1b[2J\x1b[H")
                print(f"{DIM}(mini-shell at {path}; type `exit` to return to ncdu){RESET}")
                while True:
                    try:
                        _sys.stdout.write(f"{BOLD}ncdu:shell>{RESET} ")
                        _sys.stdout.flush()
                        s = _sys.stdin.readline()
                    except (EOFError, KeyboardInterrupt):
                        break
                    if s == "" or s.strip().lower() in ("exit", "quit"):
                        break
                    sh.run_line(s.rstrip("\n"))
                tui_enter_raw()
                try: os.chdir(saved)
                except OSError: pass
                entries = scan()
    finally:
        tui_exit_raw()
        # Show cursor + leave alt screen (scrollback unchanged).
        _sys.stdout.write("\x1b[?25h\x1b[?1049l")
        _sys.stdout.flush()
        print(f"{DIM}(ncdu exited — last path: {path}){RESET}")


@builtin("stat")
def _stat_cmd(sh: Shell, argv: List[str]) -> None:
    """stat <path>  — size / mtime / permissions of a single file."""
    if not argv:
        print("usage: stat <path>")
        return
    import time as _time
    # NB: don't use the name `_stat` here — line 34 binds the stat
    # MODULE to that name at module scope, and a local `_stat` binding
    # inside this function that shadowed the module was previously
    # used as the function name via @builtin("stat"), which overwrote
    # the module-level `_stat` variable and broke `ls`'s file-color
    # logic (AttributeError: 'function' object has no attribute 'S_ISDIR').
    for p in argv:
        path = os.path.abspath(os.path.expanduser(p))
        try:
            s = os.lstat(path)
        except OSError as e:
            print(f"{RED}stat:{RESET} {e.strerror}: {p}")
            continue
        mode = _stat.filemode(s.st_mode)
        mtime = _time.strftime("%Y-%m-%d %H:%M:%S", _time.localtime(s.st_mtime))
        print(f"{BOLD}{path}{RESET}")
        print(f"  type   : {'dir' if _stat.S_ISDIR(s.st_mode) else 'file' if _stat.S_ISREG(s.st_mode) else 'other'}")
        print(f"  size   : {_human_bytes(s.st_size)} ({s.st_size} bytes)")
        print(f"  perms  : {mode}")
        print(f"  mtime  : {mtime}")


# ---------------------------------------------------------------------------
# man — abbreviated help for a single command

@builtin("man")
def _man(sh: Shell, argv: List[str]) -> None:
    if not argv:
        print("usage: man <command>")
        return
    name = argv[0]
    fn = BUILTINS.get(name)
    if fn is None:
        print(f"{RED}man:{RESET} no entry for {name}")
        return
    doc = (fn.__doc__ or "").strip() or "(no documentation)"
    print(f"{BOLD}{name}{RESET}")
    for line in doc.splitlines():
        print(f"  {line}")


# ---------------------------------------------------------------------------
# Native-compiler commands — C, C++, Fortran
#
# The app bundles in-process interpreters (CRuntime, CppRuntime,
# FortranRuntime in Swift). We can't fork/exec on iOS, so these
# builtins drop a SIGNAL FILE into the shared tmp dir that Swift
# picks up, runs the source through the right runtime, writes the
# output back, and this function polls for it. If the Swift handler
# isn't wired up (older build), we show a short explanation.

def _run_native_source(kind: str, source_path: str, argv_extra: list) -> None:
    """kind ∈ {'c', 'cpp', 'fortran'}. Wait up to 30 s for Swift to
    write the result file."""
    import tempfile, time as _time, json
    if not os.path.exists(source_path):
        print(f"{RED}{kind}:{RESET} no such file: {source_path}")
        return
    try:
        source = open(source_path, "r", encoding="utf-8", errors="replace").read()
    except OSError as e:
        print(f"{RED}{kind}:{RESET} {e.strerror}: {source_path}")
        return

    signal_dir = os.path.join(tempfile.gettempdir(), "native_signals")
    os.makedirs(signal_dir, exist_ok=True)
    request_id = f"{kind}_{os.getpid()}_{int(_time.time()*1000)}"
    req_file = os.path.join(signal_dir, f"{request_id}.request")
    res_file = os.path.join(signal_dir, f"{request_id}.response")

    payload = json.dumps({
        "kind": kind,
        "source": source,
        "source_path": source_path,
        "argv": argv_extra,
    })
    try:
        with open(req_file, "w", encoding="utf-8") as f:
            f.write(payload)
    except OSError as e:
        print(f"{RED}{kind}:{RESET} can't create request: {e}")
        return

    # Poll for response
    for _ in range(300):   # up to ~30 s
        if os.path.exists(res_file):
            try:
                with open(res_file, "r", encoding="utf-8") as f:
                    resp = json.load(f)
                stdout = resp.get("stdout", "")
                stderr = resp.get("stderr", "")
                if stdout:
                    print(stdout, end="" if stdout.endswith("\n") else "\n")
                if stderr:
                    print(f"{RED}{stderr}{RESET}", end="" if stderr.endswith("\n") else "\n")
            except Exception as e:
                print(f"{RED}{kind}:{RESET} can't parse response: {e}")
            finally:
                try: os.unlink(res_file)
                except OSError: pass
                try: os.unlink(req_file)
                except OSError: pass
            return
        _time.sleep(0.1)

    # Timed out waiting for Swift
    try: os.unlink(req_file)
    except OSError: pass
    print(f"{DIM}{kind}: Swift-side runtime didn't respond in 30 s.{RESET}")
    print(f"{DIM}  Likely this build doesn't wire up native_signals yet.{RESET}")
    print(f"{DIM}  Put your .{kind} file in the editor and press Run instead.{RESET}")


@builtin("cc")
@builtin("gcc")
@builtin("clang")
def _c_run(sh: Shell, argv: List[str]) -> None:
    """cc | gcc | clang <file.c> [args…]  — compile and run a C file
    in the bundled in-process C interpreter (no fork/exec)."""
    if not argv or _is_help_tok(argv[0]):
        print("usage: cc <file.c> [args...]")
        return
    _run_native_source("c", os.path.abspath(os.path.expanduser(argv[0])), argv[1:])


@builtin("c++")
@builtin("g++")
@builtin("clang++")
def _cpp_run(sh: Shell, argv: List[str]) -> None:
    """c++ | g++ | clang++ <file.cpp> [args…]  — compile and run a
    C++ file in the bundled in-process C++ interpreter."""
    if not argv or _is_help_tok(argv[0]):
        print("usage: c++ <file.cpp> [args...]")
        return
    _run_native_source("cpp", os.path.abspath(os.path.expanduser(argv[0])), argv[1:])


@builtin("gfortran")
@builtin("f77")
@builtin("f90")
@builtin("f95")
def _fortran_run(sh: Shell, argv: List[str]) -> None:
    """gfortran | f77 | f90 | f95 <file.f90> [args…]  — compile and
    run a Fortran file in the bundled in-process Fortran interpreter."""
    if not argv or _is_help_tok(argv[0]):
        print("usage: gfortran <file.f90> [args...]")
        return
    _run_native_source("fortran", os.path.abspath(os.path.expanduser(argv[0])), argv[1:])


# ---------------------------------------------------------------------------
# LaTeX — pdflatex, latex, tex, xelatex.
# The app bundles the pdftex C library (used by manim's math rendering),
# so we get real pdflatex / latex for free. xelatex isn't bundled
# (different engine) so it degrades to pdflatex with a warning.

def _run_latex_engine(sh: Shell, engine: str, argv: List[str]) -> None:
    """Compile a .tex file using pdftex via the ctypes bridge.

    pdftex's static state corrupts after one call per process. This
    means each app session gets ONE successful pdflatex invocation —
    after that you must restart the app. We track this via a flag in
    offlinai_latex and return a clear message on the second attempt.

    The LaTeX format is NOT preloaded from a .fmt file (version
    incompatible with the bundled 1.40.20 pdftex). Instead we invoke
    pdftex in ini mode against a small wrapper that inlines
    latex.ltx — the kernel loads at runtime (~10 s extra) and
    processing proceeds in the same single call."""
    if not argv or _is_help_tok(argv[0]):
        print(f"usage: {engine} <file.tex>")
        print(f"  Output written next to the .tex file. One compile per")
        print(f"  app session (restart the app between compiles).")
        return

    tex_path = os.path.abspath(os.path.expanduser(argv[0]))
    if not os.path.exists(tex_path):
        print(f"{RED}{engine}:{RESET} no such file: {argv[0]}")
        return

    # Only pdflatex (and its DVI-mode aliases latex/tex/pdftex) are
    # supported. xelatex is refused earlier in its builtin; keep
    # _run_latex_engine simple — no engine-specific special cases.

    try:
        import offlinai_latex as _latex_mod
    except ImportError as e:
        print(f"{RED}{engine}:{RESET} offlinai_latex module unavailable: {e}")
        return

    out_dir = os.path.dirname(tex_path)
    # On the WASM path (the default), track first-run via
    # `_wasm_first_run_done` — the native `_pdftex_called_this_session`
    # flag is never flipped in that codepath.
    first = not getattr(_latex_mod, "_wasm_first_run_done", False)
    # busytex is the default now (TL 2023, pdftex 1.40.25 + xetex +
    # luatex). swiftlatex remains as a fallback for anyone who sets
    # OFFLINAI_ENGINE=swiftlatex explicitly.
    backend = os.environ.get("OFFLINAI_ENGINE", "").lower()
    use_swiftlatex = backend in ("swiftlatex", "web")
    tag = "swiftlatex" if use_swiftlatex else "busytex TL 2023"
    print(f"{BOLD}Running{RESET} {engine} on {os.path.basename(tex_path)}"
          f"  {DIM}({tag}){RESET}")
    if first and engine in ("pdflatex", "latex"):
        if use_swiftlatex:
            print(f"{DIM}  First run: warming pdflatex format (~10-20 s)...{RESET}")
            print(f"{DIM}  Heavy packages (beamer/tikz) add another 20-40 s first time.{RESET}")
        else:
            print(f"{DIM}  First run: loading busytex WASM + TL 2023 bundle (~60-90 s){RESET}")
            print(f"{DIM}  Subsequent compiles reuse the in-memory texmf and are fast.{RESET}")

    output = _latex_mod.compile_tex(
        tex_path, output_dir=out_dir, engine=engine,
    )

    if output is None:
        print(f"{RED}{engine}: compilation failed{RESET}")
        log_path = os.path.join(
            out_dir,
            os.path.splitext(os.path.basename(tex_path))[0] + ".log",
        )
        if not os.path.exists(log_path):
            # No log means pdftex didn't even get to write one — either
            # the C library couldn't load or it crashed before opening.
            print(f"{RED}  No log file produced — pdftex didn't run{RESET}")
            print(f"{DIM}  Run `latex-diagnose` to check what's wrong.{RESET}")
            return
        print(f"{DIM}  log: {log_path}{RESET}")
        try:
            log_text = open(log_path, "r", encoding="utf-8",
                            errors="replace").read()
        except OSError:
            return
        import re as _re
        # Show the FIRST TeX error (`! ...`) and the surrounding lines.
        # Every pdflatex failure has one of these; showing it tells the
        # user *exactly* what broke without forcing them to open the
        # log. Second in priority: missing-file errors which are often
        # hidden behind downstream errors.
        err_iter = list(_re.finditer(r"^(!\s.*?)$", log_text, _re.MULTILINE))
        if err_iter:
            first = err_iter[0]
            # Show ~5 lines of context after the error for diagnostic
            # value — TeX logs the problematic source line right after.
            snippet_start = first.start()
            tail = log_text[snippet_start:snippet_start + 800]
            lines = tail.splitlines()[:8]
            print(f"{RED}  First error:{RESET}")
            for line in lines:
                print(f"    {line}")
        missing_pkgs = sorted({
            m.group(1) for m in _re.finditer(
                r"File [`'\"]([\w\-]+\.(?:sty|cls|def|tex|cfg|fd))['\"]? not found",
                log_text)
        })
        if missing_pkgs:
            print(f"{RED}  Missing files:{RESET} "
                  f"{', '.join(missing_pkgs)}")
            print(f"{DIM}  Bundle ships ~140 common packages (base,{RESET}")
            print(f"{DIM}  amsmath, amsthm, mathtools, hyperref, lmodern,{RESET}")
            print(f"{DIM}  cleveref, xcolor, geometry, booktabs, tikz, pgf,{RESET}")
            print(f"{DIM}  beamer, translator, etc.){RESET}")
            print(f"{DIM}  Not shipped: babel, fontspec, biblatex,{RESET}")
            print(f"{DIM}  minted, pythontex — need full TeX Live.{RESET}")
        # Detect "Undefined control sequence" patterns, which usually
        # mean pdftex 1.40.20 is missing a primitive added in a later
        # version (e.g. \pdffeedback in expl3). Tell the user.
        if _re.search(r"Undefined control sequence.*\\pdf", log_text):
            print(f"{YLW}  Hint:{RESET} an \\pdf* primitive is undefined.")
            print(f"{DIM}  The bundled pdftex is v1.40.20 (2019) while the{RESET}")
            print(f"{DIM}  shipped latex.ltx / expl3 files are from 2024 and{RESET}")
            print(f"{DIM}  may use newer pdftex primitives. Consider using{RESET}")
            print(f"{DIM}  `swiftmath` (math formulas only) as an alternative.{RESET}")
        return

    sz = os.path.getsize(output) if os.path.exists(output) else 0
    print(f"{GRN}{BOLD}✓ Output:{RESET} {output}  ({_human_bytes(sz)})")
    # Drop a signal file that Swift's LaTeXEngine picks up on its 100ms
    # poll — triggers the editor's output preview panel to load the
    # newly generated PDF. Same protocol used for manim GIFs / figures.
    try:
        import tempfile as _tmp
        signal_dir = os.path.join(_tmp.gettempdir(), "latex_signals")
        os.makedirs(signal_dir, exist_ok=True)
        preview_signal = os.path.join(signal_dir, "preview_request.txt")
        with open(preview_signal, "w", encoding="utf-8") as f:
            f.write(output + "\n")
    except OSError:
        pass


@builtin("pdflatex")
def _pdflatex(sh: Shell, argv: List[str]) -> None:
    """pdflatex <file.tex>  — compile a LaTeX file to PDF.

    Uses the bundled pdftex C library in "pdflatex" mode (LaTeX format
    auto-loaded). Output `<stem>.pdf` is written next to the input.

    Bundled packages (~134 .sty files):
      Classes:   article, book, report, letter (+ AMS classes)
      Math:      amsmath, amssymb, amsfonts, amsthm, mathtools (+ mhsetup),
                 eucal, eufrak, latexsym
      Tables:    array, tabular, booktabs, float
      Lists:     enumitem, enumerate
      Graphics:  graphicx, xcolor, graphics (with hpdftex/hdvipdfm drivers)
      Layout:    geometry, caption, subcaption, fleqn, leqno
      Refs:      hyperref (full), cleveref, url, nameref, refcount
      Plumbing:  etoolbox, kvoptions, kvsetkeys, ltxcmds, iftex,
                 atbegshi, atveryend, rerunfilecheck, pdftexcmds,
                 infwarerr, kvdefinekeys, intcalc, pdfescape, bitset,
                 bigintcalc, gettitlestring, hycolor, letltxmacro,
                 auxhook, etexcmds
      Base:      inputenc, fontenc, textcomp, ifthen, makeidx,
                 l3kernel, l3backend
      Fonts:     Computer Modern + AMS extra glyphs

    What's still NOT bundled:
      • tikz / pgf (heavy), beamer (needs tikz), babel (non-English)
      • fontspec / xelatex (different engine)
      • biblatex + biber (biber needs subprocess)
      • \\write18 shell-escape
      If your document fails with "File 'X.sty' not found", that's X
      not being shipped.

    Caveats:
      • pdftex on iOS is NOT re-entrant — static C state corrupts
        after ~2 compiles per app session. Restart the app if it
        starts failing silently.
      • The bundle has no pre-built .fmt files. First compile of each
        session rebuilds the LaTeX format from latex.ltx at runtime
        (~5-10 s extra). The bundle is read-only so the format can't
        be cached between app launches."""
    _run_latex_engine(sh, "pdflatex", argv)


@builtin("latex")
def _latex(sh: Shell, argv: List[str]) -> None:
    """latex <file.tex>  — compile a LaTeX file to DVI.

    Uses the bundled pdftex C library with the LaTeX format loaded but
    outputting DVI (traditional workflow — usually followed by dvipdf
    or dvisvgm). Output `<stem>.dvi` is written next to the input."""
    _run_latex_engine(sh, "latex", argv)


@builtin("tex")
@builtin("pdftex")
def _tex(sh: Shell, argv: List[str]) -> None:
    """tex | pdftex <file.tex>  — compile plain TeX (no LaTeX format).

    The lowest-level TeX command. If your file starts with
    `\\documentclass{…}` you want `pdflatex` or `latex` instead."""
    _run_latex_engine(sh, "pdftex", argv)


@builtin("xelatex")
def _xelatex(sh: Shell, argv: List[str]) -> None:
    """xelatex <file.tex>  — not supported on iOS.

    We don't bundle xelatex (or the fontspec/fontconfig plumbing it
    needs, or the CJK/system fonts it expects). Run pdflatex on your
    document instead; most docs that don't explicitly use fontspec's
    system-font features compile cleanly."""
    print(f"{RED}xelatex: not supported on iOS.{RESET} "
          f"{DIM}Use pdflatex instead.{RESET}")


# ---------------------------------------------------------------------------
# ai — interactive AI coding CLI
# Delegates the whole REPL to offlinai_ai.run(). We do a lazy import
# so the shell itself doesn't pay the module's startup cost unless the
# user actually invokes `ai`.

@builtin("ai")
def _ai_builtin(sh: Shell, argv: List[str]) -> None:
    """ai [<file> | <subcommand>]  — interactive AI coding CLI.

    Opens a REPL that can read, reason about, and edit source files via
    a locally-downloaded GGUF model (llama.cpp backend).

    Subcommands (no REPL):
      ai pull [<name>]       download a model (no arg → list the registry)
      ai run <name> [<file>] download if needed, load, enter REPL
      ai ls                  list cached GGUFs
      ai load <path>         load a GGUF already on disk

    With a path argument that's not a subcommand, edits that file.
    With no argument, edits whatever file is currently open in the editor.

    Slash commands inside the REPL:
      /help                list all commands
      /pull [<name>]       download a model (or list registry)
      /run <name>          alias of /pull — Ollama-style
      /load <path>         load an already-downloaded .gguf
      /model [<name>]      show active model (or load one)
      /models              list cached GGUFs
      /file [<path>]       show or switch edit target
      /show [<path>]       print a file
      /ls [<dir>]          list files
      /mode [<mode>]       permission mode (see below)
      /usage               session stats
      /reset               wipe conversation history
      /clear               clear terminal
      /quit | /exit | /q   leave

    Examples:
      ai run qwen2.5:0.5b          # download + load + chat
      ai pull llama3.2:1b          # download only (for later)
      ai load ~/Documents/Models/foo.gguf
      ai                           # REPL with last-loaded model

    Permission modes:
      nothing   — read-only, every write refused
      allow     — show each edit as a diff, prompt y/n  (default)
      plan      — write a numbered plan first; user edits it; then apply
      auto      — apply small edits (<5 lines) automatically; large ones prompt
      bypass    — apply every edit automatically; no prompts

    Cached models live in ~/Documents/Models/ and are visible in the
    iOS Files app for manual inspection. Every write appends to
    $TMPDIR/latex_signals/ai_audit.log."""
    try:
        import offlinai_ai
    except ImportError as e:
        print(f"{RED}ai:{RESET} offlinai_ai module unavailable: {e}")
        return
    offlinai_ai.run(argv)


@builtin("latex-diagnose")
def _latex_diagnose(sh: Shell, argv: List[str]) -> None:
    """latex-diagnose  — check the bundled LaTeX setup.

    Reports which parts are present and which paths are visible to
    pdftex. Useful when `pdflatex foo.tex` fails: run this to see if
    the problem is a missing package, a missing format file, or a
    runtime path issue."""
    try:
        import offlinai_latex as _latex_mod
    except ImportError as e:
        print(f"{RED}offlinai_latex module not available:{RESET} {e}")
        return

    # Big-picture status.
    print(f"{BOLD}LaTeX compilation status{RESET}")
    print(f"  {GRN}Ready:{RESET} pdflatex is reentrant — compile as many times as you like.")
    print(f"  {DIM}Engine: SwiftLaTeX WASM (pdftex 1.40.20) running in a hidden WKWebView.{RESET}")
    print(f"  {DIM}First compile warms the .fmt (~10-20 s); subsequent compiles are fast.{RESET}")
    print(f"  {DIM}Big packages (beamer + pgf + tikz) can add 20-40 s on first use because{RESET}")
    print(f"  {DIM}the engine XHRs ~500 texmf files through the offlinai-tex:// scheme.{RESET}")
    print()

    # Locate the bundled texmf root via the module's private path.
    texmf = getattr(_latex_mod, "_texmf_dir", None)
    fw = getattr(_latex_mod, "_fw_dir", None)
    print(f"{BOLD}Bundle layout{RESET}")
    print(f"  pdftex framework : {fw}")
    print(f"  texmf root       : {texmf}")
    print(f"  pdftex loaded    : "
          f"{'yes' if getattr(_latex_mod, '_pdftex_available', False) else 'no'}")

    if not texmf or not os.path.isdir(texmf):
        print(f"{RED}  texmf dir missing — bundle is broken.{RESET}")
        return

    print(f"\n{BOLD}Format files{RESET} (built at runtime by WASM engine)")
    print(f"  {DIM}The SwiftLaTeX WASM engine builds its own .fmt in-memory{RESET}")
    print(f"  {DIM}on first compile and caches it for the app session — no{RESET}")
    print(f"  {DIM}pre-built .fmt files are shipped. `missing` below is OK.{RESET}")
    fmt_dir = os.path.join(texmf, "web2c", "pdftex")
    for name in ("pdflatex.fmt", "latex.fmt", "pdftex.fmt", "etex.fmt"):
        p = os.path.join(fmt_dir, name)
        if os.path.exists(p):
            sz = os.path.getsize(p)
            print(f"  {GRN}✓{RESET} {name:<15} ({_human_bytes(sz)})")
        else:
            print(f"  {RED}✗{RESET} {name:<15} (missing)")

    print(f"\n{BOLD}Packages bundled{RESET}")
    pkg_root = os.path.join(texmf, "tex", "latex")
    if os.path.isdir(pkg_root):
        pkgs = sorted(d for d in os.listdir(pkg_root)
                      if os.path.isdir(os.path.join(pkg_root, d)))
        # 4-column grid
        col_w = 16
        for i in range(0, len(pkgs), 4):
            row = "  " + "".join(f"{CYN}{p:<{col_w}}{RESET}"
                                 for p in pkgs[i:i + 4])
            print(row)

    print(f"\n{BOLD}Counts{RESET}")
    n_sty = sum(1 for _, _, fs in os.walk(texmf) for f in fs if f.endswith(".sty"))
    n_def = sum(1 for _, _, fs in os.walk(texmf) for f in fs if f.endswith(".def"))
    n_cls = sum(1 for _, _, fs in os.walk(texmf) for f in fs if f.endswith(".cls"))
    n_fmt = sum(1 for _, _, fs in os.walk(texmf) for f in fs if f.endswith(".fmt"))
    n_tfm = sum(1 for _, _, fs in os.walk(texmf) for f in fs if f.endswith(".tfm"))
    n_pfb = sum(1 for _, _, fs in os.walk(texmf) for f in fs if f.endswith(".pfb"))
    print(f"  .sty files : {n_sty}")
    print(f"  .def files : {n_def}")
    print(f"  .cls files : {n_cls}")
    print(f"  .fmt files : {n_fmt}")
    print(f"  .tfm files : {n_tfm}  (font metrics)")
    print(f"  .pfb files : {n_pfb}  (Type 1 fonts for PDF embedding)")

    # Sanity check: critical runtime kernel files must be present.
    # The bundle is now TL 2019 (fmtversion 2020-02-02), which predates
    # the kernel-integrated l3backend-pdftex.def and latex-firstaid
    # packages — those are intentionally absent for this era, not bugs.
    print(f"\n{BOLD}Runtime kernel prerequisites{RESET}")
    critical = [
        ("tex/latex/base/latex.ltx",            "LaTeX kernel"),
        ("tex/latex/l3kernel/expl3.ltx",        "expl3 loader"),
        ("tex/latex/l3kernel/expl3-code.tex",   "expl3 code"),
        ("tex/latex/base/hyphen.ltx",           "hyphenation loader"),
        ("tex/generic/hyphen/hyphen.tex",       "US-English patterns"),
        ("tex/generic/pdftex/glyphtounicode.tex",
                                                "glyph→Unicode map"),
        ("tex/latex/lm/lmodern.sty",            "Latin Modern"),
        ("fonts/map/pdftex/updmap/pdftex.map",  "PDF font map"),
        ("tex/latex/l3packages/xparse/xparse.sty",
                                                "xparse (for NewDocumentCommand)"),
    ]
    all_ok = True
    for rel, desc in critical:
        p = os.path.join(texmf, rel)
        if os.path.exists(p):
            print(f"  {GRN}✓{RESET} {desc}")
        else:
            print(f"  {RED}✗{RESET} {desc} — missing {rel}")
            all_ok = False
    if not all_ok:
        print(f"{RED}  One or more prerequisites are missing — rebuild the app.{RESET}")

    if n_fmt == 0:
        print(f"\n{DIM}No .fmt files bundled — we avoid pre-built formats{RESET}")
        print(f"{DIM}and load latex.ltx at runtime in ini mode instead.{RESET}")

    print(f"\n{BOLD}Paths{RESET}")
    print(f"  {GRN}✓{RESET}  MathTex / Tex inside a manim scene "
          f"(SwiftMath, unlimited calls)")
    print(f"  {GRN}✓{RESET}  f(x) LaTeX preview button in the editor "
          f"(SwiftMath)")
    print(f"  {GRN}✓{RESET}  pdflatex / latex / tex at the shell "
          f"(reentrant, unlimited compiles per session)")


