def _apple_device_info():
    """Returns (product_name, chip_name) for the current iOS device.
    Falls back to the raw identifier if we don't recognize it."""
    import platform
    ident = ""
    try:
        ident = platform.machine() or ""
    except Exception:
        pass
    entry = _APPLE_DEVICE_TABLE.get(ident)
    if entry:
        return entry
    # Heuristic fallbacks by family
    if ident.startswith("iPad"):
        return (f"iPad (model {ident})",   "Apple silicon (unrecognized)")
    if ident.startswith("iPhone"):
        return (f"iPhone (model {ident})", "Apple silicon (unrecognized)")
    return (ident or "unknown device", "unknown chip")


def _darwin_compressed_pages() -> tuple:
    """Return (compressor_bytes, total_bytes) by reading the Mach
    host_statistics64/HOST_VM_INFO64 interface directly.

    On iOS psutil.swap_memory() returns zero (no disk swap file), so
    we go to the kernel ourselves. The XNU memory-compressor pool —
    the thing macOS and iOS both call "swap" in their UI — surfaces
    as `vm_statistics64.compressor_page_count` (pages currently
    holding compressed RAM) and `total_uncompressed_pages_in_compressor`
    (what those pages would occupy if decompressed). Multiply by the
    hardware page size to get byte counts.

    Returns (0, 0) on any failure so the caller treats it as "no swap
    info available" and falls back silently.
    """
    import ctypes
    import ctypes.util
    try:
        libSystem = ctypes.CDLL(ctypes.util.find_library("System") or
                                "/usr/lib/libSystem.dylib")
    except OSError:
        return 0, 0

    # Mach types — host port is uint, count is uint.
    mach_port_t = ctypes.c_uint
    kern_return_t = ctypes.c_int
    integer_t = ctypes.c_int
    host_flavor_t = integer_t
    mach_msg_type_number_t = ctypes.c_uint

    class vm_statistics64(ctypes.Structure):
        # struct layout from <mach/vm_statistics.h>. Only fields we
        # care about are extracted by offset so layout drift at the
        # end of the struct is safe.
        _fields_ = [
            ('free_count',                              ctypes.c_uint32),
            ('active_count',                            ctypes.c_uint32),
            ('inactive_count',                          ctypes.c_uint32),
            ('wire_count',                              ctypes.c_uint32),
            ('zero_fill_count',                         ctypes.c_uint64),
            ('reactivations',                           ctypes.c_uint64),
            ('pageins',                                 ctypes.c_uint64),
            ('pageouts',                                ctypes.c_uint64),
            ('faults',                                  ctypes.c_uint64),
            ('cow_faults',                              ctypes.c_uint64),
            ('lookups',                                 ctypes.c_uint64),
            ('hits',                                    ctypes.c_uint64),
            ('purges',                                  ctypes.c_uint64),
            ('purgeable_count',                         ctypes.c_uint32),
            ('speculative_count',                       ctypes.c_uint32),
            ('decompressions',                          ctypes.c_uint64),
            ('compressions',                            ctypes.c_uint64),
            ('swapins',                                 ctypes.c_uint64),
            ('swapouts',                                ctypes.c_uint64),
            ('compressor_page_count',                   ctypes.c_uint32),
            ('throttled_count',                         ctypes.c_uint32),
            ('external_page_count',                     ctypes.c_uint32),
            ('internal_page_count',                     ctypes.c_uint32),
            ('total_uncompressed_pages_in_compressor',  ctypes.c_uint64),
        ]

    HOST_VM_INFO64 = 4
    HOST_VM_INFO64_COUNT = ctypes.sizeof(vm_statistics64) // ctypes.sizeof(integer_t)

    try:
        libSystem.mach_host_self.restype = mach_port_t
        libSystem.host_statistics64.restype = kern_return_t
        libSystem.host_statistics64.argtypes = [
            mach_port_t, host_flavor_t,
            ctypes.POINTER(vm_statistics64),
            ctypes.POINTER(mach_msg_type_number_t),
        ]
    except AttributeError:
        return 0, 0

    stat = vm_statistics64()
    count = mach_msg_type_number_t(HOST_VM_INFO64_COUNT)
    try:
        host = libSystem.mach_host_self()
        rc = libSystem.host_statistics64(
            host, HOST_VM_INFO64,
            ctypes.byref(stat), ctypes.byref(count)
        )
    except Exception:
        return 0, 0
    if rc != 0:
        return 0, 0

    # Page size via sysconf (POSIX — doesn't need Mach-specific call).
    try:
        pagesize = os.sysconf("SC_PAGE_SIZE")
    except (OSError, ValueError):
        pagesize = 16384  # arm64 iOS default
    if pagesize <= 0:
        pagesize = 16384

    compressor_bytes = int(stat.compressor_page_count) * pagesize
    uncompressed_bytes = int(stat.total_uncompressed_pages_in_compressor) * pagesize
    return compressor_bytes, uncompressed_bytes


def _darwin_gpu_info() -> dict:
    """Probe the Metal framework for GPU info. Returns {} on any
    failure. iOS sandbox blocks IOKit so we can't read utilization
    or temperature, but Metal exposes plenty: device name, memory
    allocated vs budget, unified-memory / low-power flags,
    supported feature families (Apple1..Apple9, MetalN).

    Implementation: ctypes → /usr/lib/libobjc.dylib + the Metal
    framework. `MTLCreateSystemDefaultDevice()` is a C entry point;
    property access goes through `objc_msgSend` with the correct
    return-type signature per-call."""
    import ctypes
    import ctypes.util
    from ctypes import c_void_p, c_char_p, c_uint64, c_bool

    try:
        objc = ctypes.CDLL("/usr/lib/libobjc.dylib")
        metal = ctypes.CDLL(
            "/System/Library/Frameworks/Metal.framework/Metal")
    except OSError:
        return {}

    # MTLCreateSystemDefaultDevice returns an autoreleased
    # id<MTLDevice> — we can keep the raw pointer since the default
    # device lives for the whole process lifetime.
    try:
        metal.MTLCreateSystemDefaultDevice.restype = c_void_p
        device = metal.MTLCreateSystemDefaultDevice()
    except Exception:
        return {}
    if not device:
        return {}

    # objc_msgSend is variadic — its signature changes per call.
    # Cast to a concrete CFUNCTYPE per return-type to get the right
    # ABI. Without this ctypes defaults to `int` which silently
    # truncates 64-bit return values.
    try:
        objc.sel_registerName.argtypes = [c_char_p]
        objc.sel_registerName.restype = c_void_p
    except Exception:
        return {}

    def _sel(name):
        return objc.sel_registerName(name.encode("utf-8"))

    def _send_id(obj, sel_name):
        fn = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(c_void_p, c_void_p, c_void_p))
        return fn(obj, _sel(sel_name))

    def _send_uint64(obj, sel_name):
        fn = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(c_uint64, c_void_p, c_void_p))
        return fn(obj, _sel(sel_name))

    def _send_bool(obj, sel_name):
        fn = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(c_bool, c_void_p, c_void_p))
        return fn(obj, _sel(sel_name))

    def _send_bool_ulong(obj, sel_name, arg):
        # `supportsFamily:(MTLGPUFamily)family` — takes NSInteger.
        fn = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(c_bool, c_void_p, c_void_p,
                             ctypes.c_long))
        return fn(obj, _sel(sel_name), arg)

    def _responds(obj, sel_name):
        """True if `obj` accepts the Obj-C message `sel_name`. MUST
        guard every property access — unrecognized-selector raises
        NSInvalidArgumentException, which is an Obj-C exception that
        aborts the whole process without any chance of Python's
        try/except catching it."""
        try:
            fn = ctypes.cast(
                objc.objc_msgSend,
                ctypes.CFUNCTYPE(c_bool, c_void_p, c_void_p, c_void_p))
            return bool(fn(obj, _sel("respondsToSelector:"),
                           _sel(sel_name)))
        except Exception:
            return False

    def _nsstring_to_str(ptr):
        if not ptr:
            return ""
        fn = ctypes.cast(
            objc.objc_msgSend,
            ctypes.CFUNCTYPE(c_char_p, c_void_p, c_void_p))
        cstr = fn(ptr, _sel("UTF8String"))
        return cstr.decode("utf-8") if cstr else ""

    info: dict = {}
    # Every call below is gated by `_responds()` — on iOS the GPU
    # class is AGXGxxDevice, on macOS it's a different private class,
    # and their property surfaces don't fully match. Skipping
    # unsupported selectors prevents an NSInvalidArgumentException
    # that would tear down the process.
    if _responds(device, "name"):
        try: info["name"] = _nsstring_to_str(_send_id(device, "name"))
        except Exception: pass
    if _responds(device, "currentAllocatedSize"):
        try: info["allocated"] = int(
            _send_uint64(device, "currentAllocatedSize"))
        except Exception: pass
    if _responds(device, "recommendedMaxWorkingSetSize"):
        try: info["budget"] = int(
            _send_uint64(device, "recommendedMaxWorkingSetSize"))
        except Exception: pass
    if _responds(device, "maxBufferLength"):
        try: info["max_buffer"] = int(
            _send_uint64(device, "maxBufferLength"))
        except Exception: pass
    if _responds(device, "maxThreadgroupMemoryLength"):
        try: info["max_threadgroup_memory"] = int(
            _send_uint64(device, "maxThreadgroupMemoryLength"))
        except Exception: pass
    if _responds(device, "hasUnifiedMemory"):
        try: info["unified_memory"] = bool(
            _send_bool(device, "hasUnifiedMemory"))
        except Exception: pass
    # `isLowPowerDevice` and `isHeadless` are macOS-only — the iOS
    # GPU class genuinely doesn't have them. Don't probe.
    if _responds(device, "registryID"):
        try: info["registry_id"] = int(
            _send_uint64(device, "registryID"))
        except Exception: pass

    # Feature-set family. MTLGPUFamily values from <Metal/MTLDevice.h>:
    #   Apple1..Apple9 = 1001..1009, Mac2 = 2002, Common1..3 = 3001..3003,
    #   Metal3 = 5001, Metal4 = 5002. Apple CPUs have climbed through
    #   these over the years; we probe the highest-numbered family
    #   that returns true so users see "Apple9" on M3 / A17 Pro hw.
    # Gated on `supportsFamily:` because older iOS only had
    # `supportsFeatureSet:` — probing an unsupported selector would
    # crash the process.
    if _responds(device, "supportsFamily:"):
        try:
            highest_family = None
            for fam_name, fam_num in (
                    ("Apple9", 1009), ("Apple8", 1008), ("Apple7", 1007),
                    ("Apple6", 1006), ("Apple5", 1005), ("Apple4", 1004)):
                try:
                    if _send_bool_ulong(device, "supportsFamily:", fam_num):
                        highest_family = fam_name
                        break
                except Exception:
                    continue
            if highest_family:
                info["family"] = highest_family
        except Exception:
            pass
        try:
            metal_level = None
            # Try highest-first so we end up with the top level.
            for lbl, num in (("Metal4", 5002), ("Metal3", 5001)):
                try:
                    if _send_bool_ulong(device, "supportsFamily:", num):
                        metal_level = lbl
                        break
                except Exception:
                    continue
            if metal_level:
                info["metal_version"] = metal_level
        except Exception:
            pass

    return info


@builtin("top")
@builtin("htop")
def _top(sh: Shell, argv: List[str]) -> None:
    """top | htop  — live CPU / memory / GPU monitor with auto-refresh.

    Shows overall CPU, per-core bars, RAM usage, our Python process's
    resident set + thread count, and a best-effort GPU device name
    (iOS doesn't expose GPU utilization to sandboxed apps, but we show
    the device model).

    Keys (raw-mode input while running):
        q / Ctrl-C  quit
        space / r   refresh now (skip the 1 s wait)
        +           increase refresh interval
        -           decrease refresh interval
    """
    import sys as _sys, time as _time
    try:
        import psutil
    except ImportError:
        print(f"{RED}top:{RESET} psutil not available — can't show system stats")
        return

    # Parse args: -d <sec> sets initial delay.
    delay = 1.0
    if "-d" in argv:
        try:
            i = argv.index("-d")
            delay = max(0.2, float(argv[i + 1]))
        except (ValueError, IndexError):
            pass

    # Prime psutil's per-core cpu_percent (first call is always 0.0).
    try: psutil.cpu_percent(interval=None, percpu=True)
    except Exception: pass

    try: proc = psutil.Process(os.getpid())
    except Exception: proc = None

    # Cache device/chip info — these don't change during the session.
    product_name, chip_name = _apple_device_info()

    # Previous-frame caches so we can show RATES (bytes/sec, ctx/sec)
    # for counters that only give cumulative totals. Each is set on
    # the first frame if the call works, and delta-d on later frames.
    _prev_t = None
    _prev_net_bytes_sent = None
    _prev_net_bytes_recv = None
    _prev_ctx_switches = None
    _prev_interrupts = None
    _prev_proc_read = None
    _prev_proc_write = None

    width = 72
    # Streaming-frames mode (was alt-screen). Real top / htop / vim
    # use \x1b[?1049h to save the user's pre-tool scrollback and draw
    # over a clean canvas — nice for desktop terminals where the user
    # can already see the full live frame. But on iOS / SwiftTerm the
    # in-app terminal is small and the user wants to SCROLL UP to see
    # earlier frames (CPU spikes that happened 10 seconds ago, the
    # process list before they grew). Alt-screen makes that
    # impossible: on exit, scrollback is restored to whatever was
    # there pre-top, all frames are gone.
    #
    # New behavior: don't switch to alt-screen. Each refresh prints a
    # full frame separated by a divider line, so the entire history
    # accumulates in SwiftTerm's scrollback. Cursor stays hidden so
    # the redraw doesn't flicker the input caret.
    sys.stdout.write("\x1b[?25l")
    sys.stdout.flush()
    tui_enter_raw()

    try:
        first = True
        while True:
            # ── Collect stats (keep it fast — this runs each frame) ──
            try:
                cpu_total = psutil.cpu_percent(interval=None)
                cpu_each = psutil.cpu_percent(interval=None, percpu=True) or []
            except Exception:
                cpu_total = 0.0
                cpu_each = []
            # Split each psutil call so one failure doesn't zero out
            # its neighbours — on iOS, swap_memory / getloadavg /
            # io_counters may or may not exist depending on sandbox.
            try:
                vm = psutil.virtual_memory()
                mem_used = vm.used
                mem_total = vm.total
                mem_pct = vm.percent
            except Exception:
                mem_used = mem_total = mem_pct = 0

            # "Swap" on iOS is the XNU memory-compressor pool
            # (no disk swap file). Try psutil first; if it reports
            # nothing (iOS commonly returns all-zeros), fall back to
            # reading host_statistics64 directly via Mach. The latter
            # gives us the REAL compressor stats — "compressed"
            # (bytes currently held) and "saved" (uncompressed
            # equivalent the compressor is standing in for).
            swap_total = swap_used = 0
            swap_pct = 0.0
            swap_compressor = swap_uncompressed = 0
            try:
                sw = psutil.swap_memory()
                swap_used = sw.used
                swap_total = sw.total
                swap_pct = sw.percent
            except Exception:
                pass
            try:
                swap_compressor, swap_uncompressed = _darwin_compressed_pages()
            except Exception:
                pass

            try:
                core_count = psutil.cpu_count(logical=True) or len(cpu_each) or 1
            except Exception:
                core_count = len(cpu_each) or 1

            # Load average (1/5/15 min) — not guaranteed on iOS
            load1 = load5 = load15 = 0.0
            try:
                load1, load5, load15 = psutil.getloadavg()
            except Exception:
                pass

            proc_rss = 0
            proc_threads = 0
            if proc is not None:
                try:
                    mi = proc.memory_info()
                    proc_rss = mi.rss
                except Exception:
                    pass
                try:
                    proc_threads = proc.num_threads()
                except Exception:
                    pass

            # ── Draw ──
            # Streaming mode (no alt-screen) — print a divider above
            # each frame so the user can scroll back through the
            # history and visually pick out where each refresh begins.
            # First frame skips the divider so the very first frame
            # isn't preceded by an empty line.
            if not first:
                _sys.stdout.write(
                    f"\r\n{DIM}{'─' * width}{RESET}\r\n\r\n")

            # Top status bar
            stamp = _time.strftime("%H:%M:%S")
            title = f" top — live system monitor   ({stamp},  refresh {delay:.1f}s)"
            _sys.stdout.write(
                f"\x1b[7m{title:<{width}}\x1b[0m\r\n\r\n"
            )

            # Overall CPU
            _sys.stdout.write(
                f"  {BOLD}CPU total{RESET}  "
                f"[{_bar_colored(cpu_total / 100, 32)}]  "
                f"{cpu_total:>5.1f}%\r\n"
            )

            # Per-core bars
            if cpu_each:
                _sys.stdout.write(f"  {DIM}cores ({core_count}){RESET}\r\n")
                for i, p in enumerate(cpu_each):
                    _sys.stdout.write(
                        f"    {DIM}#{i:<2}{RESET}     "
                        f"[{_bar_colored(p / 100, 32)}]  "
                        f"{p:>5.1f}%\r\n"
                    )

            # Load average — only show if psutil.getloadavg worked.
            if load1 > 0 or load5 > 0 or load15 > 0:
                _sys.stdout.write(
                    f"  {BOLD}load avg {RESET}  "
                    f"{load1:>4.2f}  {load5:>4.2f}  {load15:>4.2f}   "
                    f"{DIM}(1m / 5m / 15m, {core_count} cores){RESET}\r\n"
                )

            _sys.stdout.write("\r\n")

            # Memory (RAM)
            _sys.stdout.write(
                f"  {BOLD}RAM      {RESET}  "
                f"[{_bar_colored(mem_pct / 100, 32)}]  "
                f"{mem_pct:>5.1f}%   "
                f"{_human_bytes(mem_used)} / {_human_bytes(mem_total)}\r\n"
            )
            # Compressed / swap. Prefer psutil's reading (has a real
            # total when macOS actually swaps to disk). Otherwise show
            # the XNU compressor pool direct from Mach — iOS's "swap".
            if swap_total > 0:
                _sys.stdout.write(
                    f"  {BOLD}Swap/cmp {RESET}  "
                    f"[{_bar_colored(swap_pct / 100, 32)}]  "
                    f"{swap_pct:>5.1f}%   "
                    f"{_human_bytes(swap_used)} / {_human_bytes(swap_total)}   "
                    f"{DIM}(iOS compressed memory){RESET}\r\n"
                )
            elif swap_compressor > 0:
                # Ratio of (compressor pool size) / (what it stands in
                # for uncompressed) tells you how hard the compressor
                # is working. Show it as a "saved" amount.
                saved = max(0, swap_uncompressed - swap_compressor)
                _sys.stdout.write(
                    f"  {BOLD}Compressed{RESET} "
                    f"{_human_bytes(swap_compressor)} held   "
                    f"({_human_bytes(swap_uncompressed)} uncompressed, "
                    f"{_human_bytes(saved)} saved)   "
                    f"{DIM}(iOS XNU memory compressor){RESET}\r\n"
                )

            _sys.stdout.write("\r\n")

            # ── Extended system section — all per-field try/except so
            # any psutil call that's unsupported on iOS just silently
            # drops its line instead of crashing the whole screen.

            # Uptime — always safe, computed from boot_time().
            try:
                _bt = psutil.boot_time()
                _up_s = max(0.0, _time.time() - _bt)
                _d = int(_up_s // 86400)
                _h = int((_up_s % 86400) // 3600)
                _m = int((_up_s % 3600) // 60)
                if _d > 0:
                    _up_str = f"{_d}d {_h}h {_m}m"
                elif _h > 0:
                    _up_str = f"{_h}h {_m}m"
                else:
                    _up_str = f"{_m}m"
                _sys.stdout.write(
                    f"  {BOLD}Uptime   {RESET}  {CYN}{_up_str}{RESET}\r\n")
            except BaseException:
                pass

            # Battery — iOS exposes %, charging state, and sometimes
            # time remaining. sensors_battery() returns None on
            # machines with no battery, so guard for that.
            try:
                _bat = psutil.sensors_battery()
                if _bat is not None:
                    _pct = getattr(_bat, "percent", None)
                    _plugged = getattr(_bat, "power_plugged", None)
                    _secs = getattr(_bat, "secsleft", None)
                    _parts = []
                    if _pct is not None:
                        _parts.append(f"{_pct:.0f}%")
                    if _plugged is True:
                        _parts.append(f"{GRN}charging{RESET}")
                    elif _plugged is False:
                        _parts.append(f"{DIM}on battery{RESET}")
                    if _secs is not None and _secs > 0 and _secs < 10**8:
                        _h = _secs // 3600
                        _m = (_secs % 3600) // 60
                        _parts.append(
                            f"{DIM}{_h}h{_m:02d}m left{RESET}")
                    if _parts:
                        _sys.stdout.write(
                            f"  {BOLD}Battery  {RESET}  "
                            f"{'  '.join(_parts)}\r\n")
            except BaseException:
                pass

            # CPU time breakdown — what the CPU is actually DOING.
            # cpu_times_percent() returns a named tuple of percentages
            # already, so we don't have to delta anything ourselves.
            try:
                _ct = psutil.cpu_times_percent(interval=None)
                _ct_parts = []
                # Conventional top/htop abbreviations: usr/sys/idl/wa/ni/hi.
                _ct_labels = {
                    "user": "usr", "system": "sys", "idle": "idl",
                    "iowait": "wa", "nice": "ni", "irq": "hi",
                    "softirq": "si", "steal": "st", "guest": "gu",
                }
                for _field, _lbl in _ct_labels.items():
                    _v = getattr(_ct, _field, None)
                    if _v is not None and _v > 0.1:
                        _ct_parts.append(f"{_lbl}={_v:.1f}%")
                if _ct_parts:
                    _sys.stdout.write(
                        f"  {BOLD}CPU time {RESET}  "
                        f"{DIM}{'  '.join(_ct_parts)}{RESET}\r\n")
            except BaseException:
                pass

            # Context switches / interrupts — as RATES per second, not
            # cumulative totals (a 30-day uptime total is useless).
            # On iOS the `interrupts` counter isn't monotonic (psutil
            # maps an iOS kstat that wraps / resets independently of
            # ctx_switches); a negative delta means the counter rolled,
            # so clamp to 0 and skip the irq column when that happens.
            try:
                _cs = psutil.cpu_stats()
                _now = _time.time()
                if _prev_t is not None and _prev_ctx_switches is not None:
                    _dt = max(1e-6, _now - _prev_t)
                    _ctx_rate = max(0.0,
                        (_cs.ctx_switches - _prev_ctx_switches) / _dt)
                    _raw_irq = (_cs.interrupts
                                - (_prev_interrupts or 0)) / _dt
                    _parts = []
                    if _ctx_rate > 0:
                        _parts.append(f"{_ctx_rate:,.0f} ctx/s")
                    if _raw_irq > 0:
                        _parts.append(f"{_raw_irq:,.0f} irq/s")
                    if _parts:
                        _sys.stdout.write(
                            f"  {BOLD}Kernel   {RESET}  "
                            f"{DIM}{'   '.join(_parts)}{RESET}\r\n")
                _prev_ctx_switches = _cs.ctx_switches
                _prev_interrupts = getattr(_cs, "interrupts", 0)
            except BaseException:
                pass

            # Disk usage for the app's writable home (Documents dir).
            # This is what the user cares about — "how much space does
            # my sandbox have left?" — not the whole device which iOS
            # doesn't let us see anyway.
            try:
                _du = psutil.disk_usage(str(Path.home() / "Documents"))
                _sys.stdout.write(
                    f"  {BOLD}Disk     {RESET}  "
                    f"[{_bar_colored(_du.percent / 100, 32)}]  "
                    f"{_du.percent:>5.1f}%   "
                    f"{_human_bytes(_du.used)} / "
                    f"{_human_bytes(_du.total)}   "
                    f"{DIM}(Documents){RESET}\r\n")
            except BaseException:
                pass

            # Network I/O — RATES, not totals. First frame shows nothing;
            # subsequent frames show bytes/sec.
            try:
                _nio = psutil.net_io_counters()
                _now = _time.time()
                if (_prev_t is not None
                        and _prev_net_bytes_sent is not None):
                    _dt = max(1e-6, _now - _prev_t)
                    _up = (_nio.bytes_sent
                           - _prev_net_bytes_sent) / _dt
                    _dn = (_nio.bytes_recv
                           - _prev_net_bytes_recv) / _dt
                    _sys.stdout.write(
                        f"  {BOLD}Net      {RESET}  "
                        f"{GRN}↓{_human_bytes(int(_dn))}/s{RESET}   "
                        f"{YEL}↑{_human_bytes(int(_up))}/s{RESET}   "
                        f"{DIM}total "
                        f"↓{_human_bytes(_nio.bytes_recv)} "
                        f"↑{_human_bytes(_nio.bytes_sent)}{RESET}\r\n")
                _prev_net_bytes_sent = _nio.bytes_sent
                _prev_net_bytes_recv = _nio.bytes_recv
            except BaseException:
                pass

            # This process's own disk I/O (read / written bytes).
            # Shows what YOUR code has been touching on disk.
            if proc is not None:
                try:
                    _pio = proc.io_counters()
                    _now = _time.time()
                    _parts = []
                    if (_prev_t is not None
                            and _prev_proc_read is not None):
                        _dt = max(1e-6, _now - _prev_t)
                        _r = (_pio.read_bytes - _prev_proc_read) / _dt
                        _w = (_pio.write_bytes
                              - _prev_proc_write) / _dt
                        if _r > 0:
                            _parts.append(
                                f"read {_human_bytes(int(_r))}/s")
                        if _w > 0:
                            _parts.append(
                                f"write {_human_bytes(int(_w))}/s")
                    _parts.append(
                        f"{DIM}total "
                        f"r{_human_bytes(_pio.read_bytes)} "
                        f"w{_human_bytes(_pio.write_bytes)}{RESET}")
                    _sys.stdout.write(
                        f"  {BOLD}Proc I/O {RESET}  "
                        f"{'   '.join(_parts)}\r\n")
                    _prev_proc_read = _pio.read_bytes
                    _prev_proc_write = _pio.write_bytes
                except BaseException:
                    pass

            # File descriptors / open files — shows how "busy" our
            # Python process is with I/O handles. num_fds is the
            # cheap count; open_files is richer but can be slow.
            if proc is not None:
                try:
                    _nfds = proc.num_fds()
                    _sys.stdout.write(
                        f"  {BOLD}FDs      {RESET}  {_nfds} open\r\n")
                except BaseException:
                    pass

            # Record this frame's timestamp for the next frame's deltas.
            _prev_t = _time.time()

            _sys.stdout.write("\r\n")

            # Device info — chip + product (cached, doesn't change).
            _sys.stdout.write(
                f"  {BOLD}Device   {RESET}  "
                f"{CYN}{product_name}{RESET}\r\n"
            )
            _sys.stdout.write(
                f"  {BOLD}Chip     {RESET}  "
                f"{CYN}{chip_name}{RESET}\r\n"
            )
            # GPU: iOS doesn't expose per-process utilization to
            # sandboxed apps (no public IOAccelerator API), but
            # Metal DOES expose device name, memory allocated vs
            # budget, feature family, and capability flags. Each
            # field is optional — if the Metal probe fails entirely
            # we fall back to the chip-name line.
            # The Metal probe goes through ctypes → objc_msgSend on the
            # real Metal framework. That C-boundary has been observed to
            # SIGSEGV with wild-address EXC_BAD_ACCESS on iOS — a try/
            # except around it can't catch a C-level segfault. Default
            # OFF; users who want GPU stats opt in with
            #   export CODEBENCH_PROBE_GPU=1
            # before invoking `top`. The chip name + "integrated" line
            # below still renders without the probe.
            _gpu = {}
            if os.environ.get("CODEBENCH_PROBE_GPU"):
                try:
                    _gpu = _darwin_gpu_info()
                except BaseException:
                    _gpu = {}
            _gpu_name = _gpu.get("name") or (
                chip_name.split(" ", 1)[-1] if " " in chip_name
                else chip_name) + " integrated"
            _sys.stdout.write(
                f"  {BOLD}GPU      {RESET}  {CYN}{_gpu_name}{RESET}\r\n"
            )
            # Memory allocated / budget — only show if Metal gave us
            # numbers. `recommendedMaxWorkingSetSize` is the amount
            # Metal recommends staying under before iOS starts evicting.
            if _gpu.get("budget", 0) > 0 and "allocated" in _gpu:
                _alloc = _gpu["allocated"]
                _budget = _gpu["budget"]
                _pct = (_alloc / _budget * 100) if _budget else 0.0
                _sys.stdout.write(
                    f"  {BOLD}GPU mem  {RESET}  "
                    f"[{_bar_colored(_pct / 100, 32)}]  "
                    f"{_pct:>5.1f}%   "
                    f"{_human_bytes(_alloc)} / "
                    f"{_human_bytes(_budget)}   "
                    f"{DIM}(Metal working set){RESET}\r\n")
            # Capability flags + feature family on a single dim line.
            _flags = []
            if _gpu.get("family"):
                _flags.append(_gpu["family"])
            if _gpu.get("metal_version"):
                _flags.append(_gpu["metal_version"])
            if _gpu.get("unified_memory"):
                _flags.append("unified-memory")
            if _gpu.get("low_power"):
                _flags.append("low-power")
            if _flags:
                _sys.stdout.write(
                    f"  {BOLD}GPU caps {RESET}  "
                    f"{DIM}{'  '.join(_flags)}{RESET}   "
                    f"{DIM}(utilisation not exposed on iOS){RESET}\r\n")
            else:
                _sys.stdout.write(
                    f"  {DIM}(utilisation not exposed on iOS){RESET}\r\n")

            _sys.stdout.write("\r\n")

            # This process — pid, RSS, thread count.
            _sys.stdout.write(
                f"  {BOLD}Python   {RESET}  "
                f"pid={os.getpid()}   "
                f"rss={_human_bytes(proc_rss)}   "
                f"threads={proc_threads}\r\n"
            )

            # Footer hint (reverse video)
            _sys.stdout.write("\r\n")
            footer = " q quit   space refresh   +/- adjust interval"
            _sys.stdout.write(
                f"\x1b[7m{footer:<{width}}\x1b[0m\r\n"
            )
            _sys.stdout.flush()

            # ── Wait for keypress or timeout ──
            # We can't do select() on a pipe FD safely here, so use a
            # short-polling loop: sleep in small chunks and peek for
            # input (os.read is blocking unless we set O_NONBLOCK).
            # PTYBridge already sets masterFD = pipe write-end, so
            # fd 0 is the read-end which IS non-blocking.
            import fcntl as _fcntl, errno as _errno
            # Set fd 0 non-blocking for the polling loop.
            flags = _fcntl.fcntl(0, _fcntl.F_GETFL)
            _fcntl.fcntl(0, _fcntl.F_SETFL, flags | os.O_NONBLOCK)
            try:
                deadline = _time.time() + delay
                refreshed = False
                while _time.time() < deadline:
                    try:
                        chunk = os.read(0, 16)
                    except OSError as e:
                        if e.errno in (_errno.EAGAIN, _errno.EWOULDBLOCK):
                            chunk = b""
                        else:
                            raise
                    if chunk:
                        if b"q" in chunk or b"\x03" in chunk or b"\x04" in chunk:
                            return
                        if b" " in chunk or b"r" in chunk:
                            refreshed = True
                            break
                        if b"+" in chunk or b"=" in chunk:
                            delay = min(10.0, delay + 0.5)
                            break
                        if b"-" in chunk or b"_" in chunk:
                            delay = max(0.2, delay - 0.5)
                            break
                    _time.sleep(0.05)
            finally:
                _fcntl.fcntl(0, _fcntl.F_SETFL, flags)  # restore blocking

            first = False
    finally:
        tui_exit_raw()
        # Show cursor again. We never switched to the alt-screen
        # buffer (see entry comment) — every frame went straight to
        # the normal scrollback so the user can scroll up after exit
        # and review the history.
        _sys.stdout.write("\x1b[?25h")
        _sys.stdout.flush()


# ---------------------------------------------------------------------------
# git clone — works via the code-hosting provider's zipball endpoint.
# iOS blocks fork/exec so we can't run real `git`. But the 99% use case
# (download a public repo to work with) is covered by fetching the repo's
# archive over HTTPS and unzipping it. Supports GitHub, GitLab, Bitbucket,
# Codeberg / Gitea / Forgejo instances.

def _parse_git_url(url: str):
    """Parse a git URL into (host, user, repo, ref). `ref` defaults to
    empty — the provider serves the default branch when unspecified.

    Handles:
      https://github.com/user/repo
      https://github.com/user/repo.git
      git@github.com:user/repo.git   (SSH form)
      https://gitlab.com/user/repo
      https://bitbucket.org/user/repo
      https://codeberg.org/user/repo
    """
    import re
    url = url.strip().rstrip("/")
    if url.endswith(".git"):
        url = url[:-4]

    # SSH form: git@host:user/repo
    m = re.match(r"git@([^:]+):([^/]+)/(.+)$", url)
    if m:
        return m.group(1), m.group(2), m.group(3), ""

    # HTTPS / HTTP form
    m = re.match(r"https?://([^/]+)/([^/]+)/([^/]+?)(?:/tree/([^/]+))?$", url)
    if m:
        return m.group(1), m.group(2), m.group(3), m.group(4) or ""

    return None


def _git_zipball_url(host: str, user: str, repo: str, ref: str) -> str:
    """Given a parsed URL, return the zipball download URL for the
    appropriate provider."""
    host_l = host.lower()
    ref = ref or ""  # empty → provider default
    if "github.com" in host_l:
        return (f"https://api.github.com/repos/{user}/{repo}/zipball"
                + (f"/{ref}" if ref else ""))
    if "gitlab.com" in host_l:
        # GitLab: /api/v4/projects/:id/repository/archive.zip?sha=ref
        # Use the public name-based endpoint:
        slug = f"{user}%2F{repo}"
        return (f"https://gitlab.com/api/v4/projects/{slug}/"
                f"repository/archive.zip" + (f"?sha={ref}" if ref else ""))
    if "bitbucket.org" in host_l:
        return (f"https://bitbucket.org/{user}/{repo}/get/"
                f"{ref or 'HEAD'}.zip")
    if "codeberg.org" in host_l or "forgejo" in host_l or "gitea" in host_l:
        return (f"https://{host}/{user}/{repo}/archive/"
                f"{ref or 'HEAD'}.zip")
    # Generic fallback — try GitHub's API shape (won't work for most
    # private-host setups but is a reasonable guess).
    return f"https://{host}/{user}/{repo}/archive/{ref or 'HEAD'}.zip"


@builtin("git")
def _git(sh: Shell, argv: List[str]) -> None:
    """git clone <url> [dir]  — fetch a remote repo over HTTPS.

    iOS blocks fork/exec so we can't run the real `git` binary. This
    builtin downloads the repo's zipball from the provider's archive
    endpoint (GitHub / GitLab / Bitbucket / Codeberg / generic Gitea)
    and unzips it into `dir` (or `<repo>/` by default). Missing features
    vs. real git: no `.git/` metadata, no history, no pushes — but
    enough to get a working-tree copy for reading / running code.

    Other subcommands (pull, push, commit, …) aren't supported and
    return a short 'not available on iOS' message.
    """
    if not argv or _is_help_tok(argv[0]):
        print("usage: git clone <url> [target-dir]")
        return

    sub = argv[0]
    if sub != "clone":
        print(f"{RED}git:{RESET} on iOS only `git clone` is supported "
              f"(no fork/exec available). Got: `{sub}`")
        print(f"{DIM}  Consider `pip install dulwich` for a pure-Python "
              f"git implementation that supports more operations.{RESET}")
        return

    if len(argv) < 2:
        print("usage: git clone <url> [target-dir]")
        return

    url = argv[1]
    parsed = _parse_git_url(url)
    if parsed is None:
        print(f"{RED}git:{RESET} can't parse URL: {url}")
        return
    host, user, repo, ref = parsed
    target = argv[2] if len(argv) >= 3 else repo

    target_path = os.path.abspath(os.path.expanduser(target))
    if os.path.exists(target_path):
        print(f"{RED}git:{RESET} target already exists: {target}")
        return

    zipball = _git_zipball_url(host, user, repo, ref)
    print(f"{BOLD}Cloning{RESET} {host}/{user}/{repo}"
          f"{(' @ ' + ref) if ref else ''} → {target}")
    print(f"{DIM}  via {zipball}{RESET}")

    try:
        import urllib.request as _ur, zipfile as _zf, io as _io, tempfile as _tf

        # Stream the zipball to a temp file so huge repos don't OOM.
        tmp_zip = _tf.NamedTemporaryFile(suffix=".zip", delete=False)
        tmp_zip_path = tmp_zip.name
        tmp_zip.close()
        req = _ur.Request(zipball, headers={
            "User-Agent": "CodeBench-iOS-Git-Clone/1.0",
            "Accept": "application/zip",
        })
        try:
            with _ur.urlopen(req, timeout=60) as resp:
                total_bytes = 0
                last_pct = -1
                content_length = int(resp.headers.get("Content-Length") or 0)
                with open(tmp_zip_path, "wb") as f:
                    while True:
                        chunk = resp.read(65536)
                        if not chunk:
                            break
                        f.write(chunk)
                        total_bytes += len(chunk)
                        if content_length > 0:
                            pct = int(100 * total_bytes / content_length)
                            if pct != last_pct and pct % 5 == 0:
                                last_pct = pct
                                print(f"{DIM}  downloaded {_human_bytes(total_bytes)} "
                                      f"/ {_human_bytes(content_length)} "
                                      f"({pct}%){RESET}")
                        else:
                            # Unknown size — print every 1 MB
                            if total_bytes // (1 << 20) != last_pct // (1 << 20) if last_pct > 0 else True:
                                last_pct = total_bytes
                                print(f"{DIM}  downloaded {_human_bytes(total_bytes)}{RESET}")
        except Exception as e:
            try: os.unlink(tmp_zip_path)
            except OSError: pass
            print(f"{RED}git:{RESET} download failed: {e}")
            return

        # Extract
        try:
            with _zf.ZipFile(tmp_zip_path) as zf:
                names = zf.namelist()
                if not names:
                    print(f"{RED}git:{RESET} empty archive")
                    return
                # Provider archives usually have a single top-level
                # directory like `user-repo-sha/`. Strip it so the user
                # gets `target/src/...` not `target/user-repo-sha/src/...`.
                top = names[0].split("/", 1)[0] + "/"
                strip_top = all(n == top[:-1] or n.startswith(top) for n in names)

                os.makedirs(target_path, exist_ok=True)
                for n in names:
                    # Security: reject any path with .. or absolute paths
                    if n.startswith("/") or ".." in n.split("/"):
                        continue
                    rel = n[len(top):] if strip_top else n
                    if not rel:
                        continue
                    out_path = os.path.join(target_path, rel)
                    if n.endswith("/"):
                        os.makedirs(out_path, exist_ok=True)
                        continue
                    os.makedirs(os.path.dirname(out_path) or target_path,
                                exist_ok=True)
                    with zf.open(n) as src, open(out_path, "wb") as dst:
                        while True:
                            buf = src.read(65536)
                            if not buf:
                                break
                            dst.write(buf)
        except Exception as e:
            print(f"{RED}git:{RESET} unzip failed: {e}")
            return
        finally:
            try: os.unlink(tmp_zip_path)
            except OSError: pass

        # Count what we got
        file_count = 0
        total_size = 0
        for root, _dirs, files in os.walk(target_path):
            for f in files:
                try:
                    total_size += os.path.getsize(os.path.join(root, f))
                    file_count += 1
                except OSError:
                    pass
        print(f"{GRN}{BOLD}✓ Cloned{RESET} {file_count} files, "
              f"{_human_bytes(total_size)} → {target}/")
    except Exception as e:
        print(f"{RED}git clone failed:{RESET} {e}")


# ---------------------------------------------------------------------------
# Module-level singleton

shell = Shell()


def run_line(line: str) -> None:
    """Public entry point used by Swift: `offlinai_shell.run_line(line)`."""
    shell.run_line(line)


def prompt() -> str:
    return shell.prompt()


def ps2() -> str:
    return shell.ps2()


def pending_continuation() -> bool:
    """Whether the shell is still collecting a multi-line Python block."""
    return bool(shell.pending)


# ---------------------------------------------------------------------------
# Blocking REPL loop — reads stdin line-by-line and dispatches.
#
# Run this on a background thread that sits on sys.stdin forever. When
# SwiftTerm is attached to the same PTY as this interpreter's stdin,
# the user types keystrokes into the terminal view, they arrive here
# as a line via input(), and we dispatch.
#
# Line-editing (backspace, arrow keys, etc.) is expected to happen on
# the SwiftTerm side — the TerminalView implements VT100 input-mode
# locally. If you want raw per-keystroke mode, send an ESC[?1h etc to
# the terminal. This REPL just reads complete lines.

class _LineEditor_UNUSED:
    """Old Python-side editor — kept here for reference. Line editing
    moved to Swift (PTYBridge.LineBuffer) because (a) Python wasn't
    running before the user tapped Run, so nothing could echo, and
    (b) a pipe's line buffering made single-char echoes pile up in
    sys.stdout. Swift-side editing is the correct 'cooked PTY' analog."""

    # Control bytes / escape sequence finals we recognize.
    _CSI_FINALS = set(range(0x40, 0x7F))  # @ A..Z [..` a..z {..~

    def __init__(self, history: list):
        self.history = history           # shared command history list
        self.history_index = 0
        self.buf = bytearray()           # current line bytes (UTF-8)
        self.pos = 0                     # byte offset of cursor in buf
        self._saved_pending = b""        # stash for history nav

    # ── raw output ──
    @staticmethod
    def _write(data):
        import sys
        try:
            if isinstance(data, str):
                sys.stdout.write(data)
            elif hasattr(sys.stdout, "buffer"):
                sys.stdout.buffer.write(data)
            else:
                sys.stdout.write(data.decode("utf-8", errors="replace"))
            sys.stdout.flush()
        except Exception:
            pass

    # ── editing primitives ──
    def _redraw_tail(self):
        """Redraw buffer from pos to end + clear rest of line + move
        cursor back to logical pos. Call after any mutation at pos."""
        tail = bytes(self.buf[self.pos:])
        self._write(tail + b"\x1b[K")
        if tail:
            self._write(f"\x1b[{len(tail)}D".encode())

    def insert(self, data: bytes):
        if not data:
            return
        self.buf[self.pos:self.pos] = data
        self.pos += len(data)
        rest = bytes(self.buf[self.pos:])
        self._write(data + rest)
        if rest:
            self._write(f"\x1b[{len(rest)}D".encode())

    def backspace(self):
        if self.pos == 0:
            return
        # Step back one UTF-8 code point (may be multi-byte).
        i = self.pos - 1
        while i > 0 and (self.buf[i] & 0xC0) == 0x80:
            i -= 1
        del self.buf[i:self.pos]
        moved = self.pos - i
        self.pos = i
        self._write(b"\x08" * moved)
        self._redraw_tail()

    def delete_forward(self):
        if self.pos >= len(self.buf):
            return
        # Step forward one UTF-8 code point.
        j = self.pos + 1
        while j < len(self.buf) and (self.buf[j] & 0xC0) == 0x80:
            j += 1
        del self.buf[self.pos:j]
        self._redraw_tail()

    def move_left(self):
        if self.pos == 0:
            return
        i = self.pos - 1
        while i > 0 and (self.buf[i] & 0xC0) == 0x80:
            i -= 1
        moved = self.pos - i
        self.pos = i
        self._write(f"\x1b[{moved}D".encode())

    def move_right(self):
        if self.pos >= len(self.buf):
            return
        j = self.pos + 1
        while j < len(self.buf) and (self.buf[j] & 0xC0) == 0x80:
            j += 1
        moved = j - self.pos
        self.pos = j
        self._write(f"\x1b[{moved}C".encode())

    def move_home(self):
        if self.pos > 0:
            self._write(f"\x1b[{self.pos}D".encode())
            self.pos = 0

    def move_end(self):
        if self.pos < len(self.buf):
            delta = len(self.buf) - self.pos
            self._write(f"\x1b[{delta}C".encode())
            self.pos = len(self.buf)

    def kill_line(self):
        """Ctrl-U: delete from beginning to cursor."""
        if self.pos == 0:
            return
        del self.buf[:self.pos]
        self._write(f"\x1b[{self.pos}D".encode())
        self.pos = 0
        self._redraw_tail()

    def kill_to_eol(self):
        """Ctrl-K: delete from cursor to end."""
        if self.pos >= len(self.buf):
            return
        del self.buf[self.pos:]
        self._write(b"\x1b[K")

    def kill_word(self):
        """Ctrl-W: delete previous word."""
        if self.pos == 0:
            return
        i = self.pos
        while i > 0 and self.buf[i - 1] == 0x20:
            i -= 1
        while i > 0 and self.buf[i - 1] != 0x20:
            i -= 1
        del self.buf[i:self.pos]
        moved = self.pos - i
        self.pos = i
        self._write(f"\x1b[{moved}D".encode())
        self._redraw_tail()

    def _replace_line(self, new: bytes):
        if self.pos > 0:
            self._write(f"\x1b[{self.pos}D".encode())
        self._write(b"\x1b[K")
        self.buf = bytearray(new)
        self.pos = len(new)
        self._write(new)

    def history_up(self):
        if not self.history:
            return
        if self.history_index == len(self.history):
            self._saved_pending = bytes(self.buf)
        if self.history_index > 0:
            self.history_index -= 1
            self._replace_line(self.history[self.history_index].encode("utf-8"))

    def history_down(self):
        if self.history_index < len(self.history):
            self.history_index += 1
            if self.history_index == len(self.history):
                self._replace_line(self._saved_pending)
            else:
                self._replace_line(
                    self.history[self.history_index].encode("utf-8"))

    def reset(self):
        self.buf.clear()
        self.pos = 0
        self.history_index = len(self.history)
        self._saved_pending = b""

    # ── main loop ──
    def read_line(self) -> str:
        """Read one complete line. Returns text (no newline).
        Raises KeyboardInterrupt on Ctrl-C, EOFError on Ctrl-D at BOL.
        """
        import os, sys, errno, time
        self.reset()

        while True:
            try:
                b = os.read(0, 1)
            except OSError as e:
                if e.errno in (errno.EAGAIN, errno.EINTR):
                    continue
                raise
            if not b:
                time.sleep(0.1)
                continue

            c = b[0]

            # Enter
            if c == 0x0d or c == 0x0a:
                self._write(b"\r\n")
                line = bytes(self.buf).decode("utf-8", errors="replace")
                if line.strip():
                    if not self.history or self.history[-1] != line:
                        self.history.append(line)
                return line

            # Ctrl-C
            if c == 0x03:
                self._write(b"^C\r\n")
                raise KeyboardInterrupt

            # Ctrl-D
            if c == 0x04:
                if len(self.buf) == 0:
                    self._write(b"\r\n")
                    raise EOFError
                self.delete_forward()
                continue

            # Backspace / BS
            if c == 0x7f or c == 0x08:
                self.backspace()
                continue

            # Ctrl-A / Ctrl-E / Ctrl-U / Ctrl-K / Ctrl-W / Ctrl-L
            if c == 0x01:
                self.move_home(); continue
            if c == 0x05:
                self.move_end(); continue
            if c == 0x15:
                self.kill_line(); continue
            if c == 0x0b:
                self.kill_to_eol(); continue
            if c == 0x17:
                self.kill_word(); continue
            if c == 0x0c:
                # Clear screen + redraw prompt and current line.
                # The caller re-prints the prompt on return from read_line,
                # but we're mid-read. Clear screen then redraw in place.
                self._write(b"\x1b[2J\x1b[H")
                # Prompt + current line — caller's repl() will handle it
                # on next iteration; here we just do a minimal redraw.
                try:
                    prompt_str = (shell.ps2() if shell.pending
                                  else shell.prompt())
                except Exception:
                    prompt_str = "$ "
                self._write(prompt_str)
                self._write(bytes(self.buf))
                if self.pos < len(self.buf):
                    delta = len(self.buf) - self.pos
                    self._write(f"\x1b[{delta}D".encode())
                continue

            # ESC — escape sequence (arrow keys, delete, home, end, …)
            if c == 0x1b:
                try:
                    b2 = os.read(0, 1)
                except OSError:
                    continue
                if b2 == b"[":
                    # CSI: read until final byte 0x40–0x7E
                    seq = bytearray()
                    for _ in range(10):  # bound the read
                        try:
                            nb = os.read(0, 1)
                        except OSError:
                            break
                        if not nb:
                            break
                        seq.extend(nb)
                        if nb[0] in self._CSI_FINALS:
                            break
                    s = bytes(seq)
                    if s == b"A":       self.history_up()
                    elif s == b"B":     self.history_down()
                    elif s == b"C":     self.move_right()
                    elif s == b"D":     self.move_left()
                    elif s == b"H":     self.move_home()
                    elif s == b"F":     self.move_end()
                    elif s == b"1~":    self.move_home()
                    elif s == b"4~":    self.move_end()
                    elif s == b"3~":    self.delete_forward()
                    elif s == b"7~":    self.move_home()
                    elif s == b"8~":    self.move_end()
                    # otherwise silently ignore unknown sequence
                elif b2 == b"O":
                    # SS3: App-mode arrows (some emulators send these)
                    try:
                        nb = os.read(0, 1)
                    except OSError:
                        continue
                    if nb == b"A":      self.history_up()
                    elif nb == b"B":    self.history_down()
                    elif nb == b"C":    self.move_right()
                    elif nb == b"D":    self.move_left()
                    elif nb == b"H":    self.move_home()
                    elif nb == b"F":    self.move_end()
                # else: bare ESC — ignore
                continue

            # Tab — for now, insert literal tab. (Could wire up
            # completion later via rlcompleter.)
            if c == 0x09:
                self.insert(b"    ")  # 4 spaces, readable default
                continue

            # Printable / UTF-8 byte
            if c >= 0x20 or c == 0x09:
                self.insert(bytes([c]))
                continue

            # Anything else (unknown control byte) — skip silently


# ---------------------------------------------------------------------------
# Extra builtins: network, archives, manim, misc Unix tools.
#
# These are intentionally implemented in pure Python (or via the bundled
# packages) — iOS sandbox forbids spawning child processes, so the
# upstream `ping` / `tar` / `unzip` binaries aren't an option even when
# bundled. Each handler is best-effort: if the user's request needs a
# capability iOS doesn't grant (raw ICMP sockets, /tmp writes,
# multicast …) we fail with a one-line explanation rather than a
# Python traceback.
# ---------------------------------------------------------------------------


def _human_bytes(n: float) -> str:
    """Compact human size — matches the `du`/`df` formatter used elsewhere."""
    for unit in ("B", "KiB", "MiB", "GiB", "TiB"):
        if abs(n) < 1024.0:
            return f"{n:.1f}{unit}"
        n /= 1024.0
    return f"{n:.1f}PiB"


@builtin("ping")
def _ping(sh: "Shell", argv: List[str]) -> None:
    """ping [-c N] [-p PORT] [-W SEC] <host>  — TCP-connect latency probe.

    iOS sandbox blocks raw ICMP sockets (real ping needs root + the
    raw-socket entitlement, neither of which an App Store app gets),
    so this opens a TCP connection to the host instead and reports
    the connect time. Default port is 443 (HTTPS) because almost
    every internet host accepts it; override with -p.

    Flags:
        -c N         number of probes (default 4)
        -p PORT      TCP port to dial (default 443)
        -W SEC       per-probe timeout in seconds (default 3)

    Examples:
        ping google.com
        ping 1.1.1.1
        ping -c 8 -p 80 example.com
        ping -p 22 github.com
    """
    import socket

    count, port, timeout = 4, 443, 3.0
    args = list(argv)
    while args and args[0].startswith("-"):
        flag = args.pop(0)
        if flag == "-c" and args:
            try: count = max(1, int(args.pop(0)))
            except ValueError: print(f"{RED}ping:{RESET} -c needs an integer"); return
        elif flag == "-p" and args:
            try: port = int(args.pop(0))
            except ValueError: print(f"{RED}ping:{RESET} -p needs a port"); return
        elif flag == "-W" and args:
            try: timeout = float(args.pop(0))
            except ValueError: print(f"{RED}ping:{RESET} -W needs a number"); return
        else:
            print(f"{RED}ping:{RESET} unknown flag {flag!r}"); return
    if not args:
        print(f"{RED}ping:{RESET} usage: ping [-c N] [-p PORT] [-W SEC] <host|url>")
        return
    target = args[0]

    # Accept full URLs too: `ping https://google.com/foo` should ping
    # google.com on 443. urlsplit handles scheme/host/port + auth +
    # path/query/fragment. If the user didn't pass `-p` explicitly,
    # let the URL's scheme pick the port (https→443, http→80, plain
    # custom scheme→fall through to current default).
    user_specified_port = "-p" in argv  # before we mutated `args`
    host = target
    if "://" in target:
        from urllib.parse import urlsplit
        parts = urlsplit(target)
        if parts.hostname:
            host = parts.hostname
        if not user_specified_port:
            if parts.port is not None:
                port = parts.port
            elif parts.scheme == "http":
                port = 80
            elif parts.scheme in ("https", "wss"):
                port = 443
            elif parts.scheme == "ssh":
                port = 22
            elif parts.scheme == "ftp":
                port = 21
            # else: leave whatever default the user already picked

    # Resolve via getaddrinfo so we transparently support both IPv4
    # and IPv6 (`getaddrinfo` returns both AF_INET and AF_INET6
    # entries when available; gethostbyname is IPv4-only and silently
    # fails on dual-stack-only hosts). This single call also drives
    # iOS's network-permission prompt once per app session — the
    # first network call of any kind triggers it.
    try:
        infos = socket.getaddrinfo(
            host, port, type=socket.SOCK_STREAM)
    except socket.gaierror as e:
        # Most common error in-app: "nodename nor servname provided"
        # = no network at all (airplane mode), or DNS blocked. We can't
        # tell which, so report both possibilities.
        print(f"{RED}ping:{RESET} DNS lookup failed for {host}: {e}")
        print(f"  {DIM}— check Wi-Fi / cellular, or that the hostname is correct{RESET}")
        return
    except OSError as e:
        print(f"{RED}ping:{RESET} resolver error: {e}"); return
    if not infos:
        print(f"{RED}ping:{RESET} no addresses returned for {host}"); return

    family, _, _, _, sockaddr = infos[0]
    ip = sockaddr[0]
    print(f"PING {host} ({ip}) tcp/{port} — "
          f"{DIM}ICMP requires root, falling back to TCP connect{RESET}")

    samples: List[float] = []
    losses = 0
    for i in range(count):
        t0 = time.perf_counter()
        sock = None
        try:
            sock = socket.socket(family, socket.SOCK_STREAM)
            sock.settimeout(timeout)
            sock.connect(sockaddr)
            ms = (time.perf_counter() - t0) * 1000
            samples.append(ms)
            print(f"  reply from {ip}: tcp_seq={i + 1} time={ms:.1f} ms")
        except socket.timeout:
            losses += 1
            print(f"  {YLW}timeout{RESET}     tcp_seq={i + 1}  (>{timeout:.0f}s)")
        except ConnectionRefusedError:
            # Host is up but nothing's listening on this port.
            ms = (time.perf_counter() - t0) * 1000
            samples.append(ms)  # the host did respond, just with RST
            print(f"  {YLW}refused{RESET}    tcp_seq={i + 1} time={ms:.1f} ms  "
                  f"{DIM}(host up, port closed){RESET}")
        except OSError as e:
            losses += 1
            print(f"  {RED}error{RESET}      tcp_seq={i + 1}: {e}")
        finally:
            if sock is not None:
                try: sock.close()
                except OSError: pass
        if i < count - 1:
            time.sleep(0.5)

    print(f"\n--- {host} ping statistics ---")
    pct = (losses / count) * 100
    print(f"{count} probes, {count - losses} replies, {pct:.0f}% loss")
    if samples:
        lo, hi = min(samples), max(samples)
        avg = sum(samples) / len(samples)
        print(f"rtt min/avg/max = {lo:.1f}/{avg:.1f}/{hi:.1f} ms")


def _http_fetch(method: str, url: str, headers: dict, data, follow: bool,
                out_path: Optional[str], silent: bool, max_show: int = 4096) -> int:
    """Shared HTTP transport for wget / curl. Returns exit code."""
    try:
        import requests
    except ImportError:
        print(f"{RED}http:{RESET} `requests` not available"); return 1
    try:
        r = requests.request(method.upper(), url, headers=headers,
                             data=data, allow_redirects=follow,
                             stream=bool(out_path), timeout=30)
    except requests.RequestException as e:
        print(f"{RED}http:{RESET} {e}"); return 1
    if not silent:
        print(f"{DIM}{r.status_code} {r.reason}  {len(r.content) if not out_path else r.headers.get('content-length','?')} bytes{RESET}")
    if out_path:
        try:
            written = 0
            with open(os.path.expanduser(out_path), "wb") as f:
                for chunk in r.iter_content(chunk_size=64 * 1024):
                    if chunk:
                        f.write(chunk); written += len(chunk)
            if not silent:
                print(f"  saved {_human_bytes(written)} → {out_path}")
        except OSError as e:
            print(f"{RED}http:{RESET} cannot write {out_path}: {e}"); return 1
    else:
        text = r.text if r.encoding else r.content.decode("utf-8", errors="replace")
        if len(text) > max_show:
            sys.stdout.write(text[:max_show])
            print(f"\n{DIM}… {len(text) - max_show} more chars truncated "
                  f"(use -O to save){RESET}")
        else:
            sys.stdout.write(text)
            if not text.endswith("\n"):
                sys.stdout.write("\n")
    return 0 if r.status_code < 400 else 1


@builtin("wget")
def _wget(sh: "Shell", argv: List[str]) -> None:
    """wget [-q] [-O FILE] <url>  — fetch a URL via HTTP.

    Default writes to a file derived from the URL path (like real
    wget). Use `-O -` to print to stdout, or `-O path` to save to a
    specific path. `-q` suppresses progress chatter.
    """
    silent, out_path = False, None
    args = list(argv)
    while args and args[0].startswith("-") and args[0] != "-":
        flag = args.pop(0)
        if flag == "-q":
            silent = True
        elif flag == "-O" and args:
            out_path = args.pop(0)
            if out_path == "-":
                out_path = None  # explicit stdout
        else:
            print(f"{RED}wget:{RESET} unknown flag {flag!r}"); return
    if not args:
        print(f"{RED}wget:{RESET} usage: wget [-q] [-O FILE|-] <url>"); return
    url = args[0]
    if out_path is None and "-O" not in argv:
        # Default behaviour: derive a filename from the URL.
        from urllib.parse import urlparse
        out_path = os.path.basename(urlparse(url).path) or "index.html"
    _http_fetch("GET", url, {}, None, follow=True,
                out_path=out_path, silent=silent)


@builtin("curl")
def _curl(sh: "Shell", argv: List[str]) -> None:
    """curl [-X METHOD] [-H 'K: V'] [-d DATA] [-o FILE] [-L] <url>

    Minimal curl: request method, headers, body, output file, and
    follow-redirects flag. By default prints the response body to
    stdout (capped at ~4 KiB — use -o to save full content).
    """
    method, headers, data = "GET", {}, None
    out_path, follow = None, False
    args = list(argv)
    while args and args[0].startswith("-") and args[0] != "-":
        flag = args.pop(0)
        if flag == "-X" and args:
            method = args.pop(0)
        elif flag == "-H" and args:
            h = args.pop(0)
            if ":" in h:
                k, _, v = h.partition(":")
                headers[k.strip()] = v.strip()
        elif flag in ("-d", "--data") and args:
            data = args.pop(0)
            if method == "GET":
                method = "POST"
        elif flag in ("-o", "--output") and args:
            out_path = args.pop(0)
        elif flag in ("-L", "--location"):
            follow = True
        elif flag == "-s":
            pass  # accepted but we're already terse
        else:
            print(f"{RED}curl:{RESET} unknown flag {flag!r}"); return
    if not args:
        print(f"{RED}curl:{RESET} usage: curl [opts] <url>"); return
    _http_fetch(method, args[0], headers, data, follow=follow,
                out_path=out_path, silent=False)


@builtin("zip")
def _zip(sh: "Shell", argv: List[str]) -> None:
    """zip <archive.zip> <path…>  — create a zip archive.

    Each path is added recursively (directories are walked). The
    archive is opened in store-or-deflate mode depending on what's
    available.
    """
    if len(argv) < 2:
        print(f"{RED}zip:{RESET} usage: zip <archive.zip> <path…>"); return
    import zipfile
    out = os.path.expanduser(argv[0])
    inputs = [os.path.expanduser(p) for p in argv[1:]]
    try:
        comp = zipfile.ZIP_DEFLATED
    except Exception:
        comp = zipfile.ZIP_STORED
    added = 0
    try:
        with zipfile.ZipFile(out, "w", compression=comp) as zf:
            for src in inputs:
                if not os.path.exists(src):
                    print(f"{YLW}zip:{RESET} skip (not found) {src}"); continue
                if os.path.isfile(src):
                    arcname = os.path.basename(src)
                    zf.write(src, arcname)
                    added += 1
                    print(f"  + {arcname}  {DIM}{_human_bytes(os.path.getsize(src))}{RESET}")
                else:
                    base = os.path.dirname(os.path.abspath(src)) + os.sep
                    for root, _, files in os.walk(src):
                        for f in files:
                            full = os.path.join(root, f)
                            arc = os.path.relpath(full, base)
                            zf.write(full, arc)
                            added += 1
                            print(f"  + {arc}  {DIM}{_human_bytes(os.path.getsize(full))}{RESET}")
    except OSError as e:
        print(f"{RED}zip:{RESET} {e}"); return
    print(f"{GRN}wrote{RESET} {out}  ({added} entries, "
          f"{_human_bytes(os.path.getsize(out))})")


@builtin("unzip")
def _unzip(sh: "Shell", argv: List[str]) -> None:
    """unzip [-l] [-d DIR] <archive.zip>  — extract or list a zip.

    Flags:
        -l         list contents instead of extracting
        -d DIR     extract into DIR (default: current directory)
    """
    if not argv:
        print(f"{RED}unzip:{RESET} usage: unzip [-l] [-d DIR] <archive.zip>"); return
    import zipfile
    list_only, dest = False, "."
    args = list(argv)
    while args and args[0].startswith("-"):
        flag = args.pop(0)
        if flag == "-l": list_only = True
        elif flag == "-d" and args: dest = args.pop(0)
        else: print(f"{RED}unzip:{RESET} unknown flag {flag!r}"); return
    if not args:
        print(f"{RED}unzip:{RESET} no archive given"); return
    src = os.path.expanduser(args[0])
    try:
        with zipfile.ZipFile(src) as zf:
            if list_only:
                print(f"{BOLD}Length{RESET}      {BOLD}Date{RESET}              {BOLD}Name{RESET}")
                total = 0
                for info in zf.infolist():
                    dt = "%04d-%02d-%02d %02d:%02d" % info.date_time[:5]
                    print(f"{info.file_size:>9}  {dt}  {info.filename}")
                    total += info.file_size
                print(f"{DIM}{'-' * 9}{RESET}")
                print(f"{total:>9}  {DIM}({len(zf.infolist())} files){RESET}")
                return
            os.makedirs(os.path.expanduser(dest), exist_ok=True)
            count = 0
            for info in zf.infolist():
                zf.extract(info, os.path.expanduser(dest))
                count += 1
                print(f"  ↳ {info.filename}")
            print(f"{GRN}extracted{RESET} {count} entries into {dest}")
    except (OSError, zipfile.BadZipFile) as e:
        print(f"{RED}unzip:{RESET} {e}")


@builtin("tar")
def _tar(sh: "Shell", argv: List[str]) -> None:
    """tar -c|-x|-t [-z|-j] [-f FILE] [path…]

    Subset of tar(1) covering the common cases:
        tar -czf out.tar.gz dir1 dir2     # create gzipped
        tar -xzf in.tar.gz                # extract gzipped
        tar -tf  in.tar                   # list contents
        tar -xf  in.tar -C target/        # extract to a directory

    `-j` selects bzip2; default is uncompressed. `-C DIR` changes
    the extraction destination.
    """
    if not argv:
        print(f"{RED}tar:{RESET} usage: tar -c|-x|-t [-z|-j] [-f FILE] [paths…]"); return
    import tarfile
    mode_op = None       # 'c', 'x', or 't'
    compress = ""        # '', 'gz', or 'bz2'
    archive = None
    chdir = None
    paths: List[str] = []

    args = list(argv)
    # Allow combined flags: tar -czf foo.tgz src/   (parses c, z, f)
    if args and args[0].startswith("-") and len(args[0]) > 2 and not args[0].startswith("--"):
        combined = args.pop(0)[1:]
        for ch in combined:
            if ch in "cxt": mode_op = ch
            elif ch == "z":  compress = "gz"
            elif ch == "j":  compress = "bz2"
            elif ch == "f":
                if args: archive = args.pop(0)
                else: print(f"{RED}tar:{RESET} -f needs a filename"); return
            elif ch == "v": pass
            else: print(f"{RED}tar:{RESET} unknown flag char {ch!r}"); return
    while args and args[0].startswith("-"):
        flag = args.pop(0)
        if flag in ("-c","-x","-t"): mode_op = flag[1]
        elif flag == "-z": compress = "gz"
        elif flag == "-j": compress = "bz2"
        elif flag == "-f" and args: archive = args.pop(0)
        elif flag == "-C" and args: chdir = args.pop(0)
        elif flag == "-v": pass
        else: print(f"{RED}tar:{RESET} unknown flag {flag!r}"); return
    paths.extend(args)

    if mode_op is None:
        print(f"{RED}tar:{RESET} need one of -c, -x, -t"); return
    if archive is None:
        print(f"{RED}tar:{RESET} no archive (-f) given"); return
    archive = os.path.expanduser(archive)
    suffix = {"": "", "gz": ":gz", "bz2": ":bz2"}[compress]

    try:
        if mode_op == "c":
            if not paths:
                print(f"{RED}tar:{RESET} no input files for create"); return
            with tarfile.open(archive, f"w{suffix}") as tf:
                for p in paths:
                    p = os.path.expanduser(p)
                    if not os.path.exists(p):
                        print(f"{YLW}tar:{RESET} skip (not found) {p}"); continue
                    tf.add(p, arcname=os.path.basename(p.rstrip(os.sep)))
                    print(f"  + {p}")
            print(f"{GRN}wrote{RESET} {archive}  ({_human_bytes(os.path.getsize(archive))})")
        elif mode_op == "x":
            with tarfile.open(archive, f"r{suffix}") as tf:
                dest = os.path.expanduser(chdir) if chdir else "."
                tf.extractall(dest)
                print(f"{GRN}extracted{RESET} into {dest}")
        elif mode_op == "t":
            with tarfile.open(archive, f"r{suffix}") as tf:
                for m in tf.getmembers():
                    print(f"  {m.name}  {DIM}{_human_bytes(m.size)}{RESET}")
    except (OSError, tarfile.TarError) as e:
        print(f"{RED}tar:{RESET} {e}")


@builtin("gzip")
def _gzip_cmd(sh: "Shell", argv: List[str]) -> None:
    """gzip <file>  — compress a file in place; output is <file>.gz."""
    if not argv:
        print(f"{RED}gzip:{RESET} usage: gzip <file>"); return
    import gzip, shutil
    src = os.path.expanduser(argv[0])
    if not os.path.isfile(src):
        print(f"{RED}gzip:{RESET} no such file: {src}"); return
    dst = src + ".gz"
    try:
        with open(src, "rb") as fi, gzip.open(dst, "wb", compresslevel=6) as fo:
            shutil.copyfileobj(fi, fo, 1024 * 1024)
        os.remove(src)
        print(f"{GRN}gzipped{RESET} {src} → {dst}  "
              f"({_human_bytes(os.path.getsize(dst))})")
    except OSError as e:
        print(f"{RED}gzip:{RESET} {e}")


@builtin("gunzip")
def _gunzip_cmd(sh: "Shell", argv: List[str]) -> None:
    """gunzip <file.gz>  — decompress a .gz file; restores the original."""
    if not argv:
        print(f"{RED}gunzip:{RESET} usage: gunzip <file.gz>"); return
    import gzip, shutil
    src = os.path.expanduser(argv[0])
    if not src.endswith(".gz") or not os.path.isfile(src):
        print(f"{RED}gunzip:{RESET} expected an existing *.gz file"); return
    dst = src[:-3]
    try:
        with gzip.open(src, "rb") as fi, open(dst, "wb") as fo:
            shutil.copyfileobj(fi, fo, 1024 * 1024)
        os.remove(src)
        print(f"{GRN}gunzipped{RESET} {src} → {dst}  "
              f"({_human_bytes(os.path.getsize(dst))})")
    except (OSError, gzip.BadGzipFile) as e:
        print(f"{RED}gunzip:{RESET} {e}")


@builtin("manim")
def _manim_cmd(sh: "Shell", argv: List[str]) -> None:
    """manim [render] [-pql/-pqm/-pqh/-qk] [-s] [-r W,H] FILE [SCENE]

    Wrap manim's CLI for a one-line render from the shell.

    Quality flags (combine with -p to preview):
        -ql / -pql       low_quality   (480p15)
        -qm / -pqm       medium_quality (720p30)
        -qh / -pqh       high_quality  (1080p60)
        -qk / -pqk       4k_quality    (2160p60)
    Other useful flags:
        -s               only save the last frame as a PNG
        -p               preview after render (open the file)
        -r W,H           custom resolution
        --format mp4|gif|webm|png      output container
        -o NAME          override output filename

    Examples:
        manim -pql scene.py SquareToCircle
        manim -qh -s plot.py FunctionGraph
        manim --format gif -ql anim.py MyScene
    """
    # `manim <flags> file.py [Scene]` — most usage is `manim -ql file.py Scene`.
    # Manim itself uses click; the cleanest surface is the CLI module's main.
    try:
        from manim.__main__ import main as _manim_main
    except ImportError as e:
        print(f"{RED}manim:{RESET} cannot import manim CLI: {e}"); return

    # If the user typed `manim file.py Scene` (no subcommand, no flags),
    # manim's CLI requires either `render` or a quality flag — be nice
    # and inject `render` so the bare form works.
    rewritten = list(argv)
    has_subcmd = bool(rewritten) and rewritten[0] in (
        "render", "checkhealth", "init", "new", "plugins", "cfg")
    has_quality = any(a in (
        "-ql","-qm","-qh","-qk","-qp",
        "-pql","-pqm","-pqh","-pqk","-pqp",
        "--quality",
    ) or a.startswith("-q") or a.startswith("-pq") for a in rewritten)
    if not has_subcmd and rewritten and not rewritten[0].startswith("-"):
        rewritten = ["render"] + rewritten
    elif not has_subcmd and has_quality:
        rewritten = ["render"] + rewritten

    # Manim's CLI is click-based; passing standalone_mode=False stops it
    # from calling sys.exit() on completion (which would tear down our
    # shell's Python interpreter).
    try:
        _manim_main(rewritten, standalone_mode=False)
    except SystemExit as e:
        if e.code not in (0, None):
            print(f"{RED}manim exited with code {e.code}{RESET}")
    except Exception as e:
        print(f"{RED}manim:{RESET} {type(e).__name__}: {e}")
        traceback.print_exc()


@builtin("base64")
def _base64_cmd(sh: "Shell", argv: List[str]) -> None:
    """base64 [-d] [file]  — encode (default) or decode (-d) base64.

    Reads from a file if given, else from the trailing positional
    argument as a literal string. With `-d`, decodes; output is
    written to stdout (lossy decode for non-UTF-8 bytes).
    """
    import base64 as _b64
    decode = False
    args = list(argv)
    if args and args[0] == "-d":
        decode = True
        args.pop(0)
    if not args:
        print(f"{RED}base64:{RESET} usage: base64 [-d] <file|string>"); return
    arg = args[0]
    p = os.path.expanduser(arg)
    if os.path.isfile(p):
        data = open(p, "rb").read()
    else:
        data = arg.encode("utf-8")
    if decode:
        try:
            out = _b64.b64decode(data, validate=False)
        except Exception as e:
            print(f"{RED}base64:{RESET} {e}"); return
        sys.stdout.write(out.decode("utf-8", errors="replace"))
        if not out.endswith(b"\n"):
            sys.stdout.write("\n")
    else:
        # Match GNU coreutils: 76-char lines.
        encoded = _b64.b64encode(data).decode("ascii")
        for i in range(0, len(encoded), 76):
            print(encoded[i:i + 76])


def _hash_file_or_stdin(algo: str, argv: List[str]) -> None:
    import hashlib
    if not argv:
        # Read stdin (rare in this REPL, but support it for tee-style use).
        h = hashlib.new(algo)
        h.update(sys.stdin.buffer.read())
        print(f"{h.hexdigest()}  -")
        return
    for path in argv:
        p = os.path.expanduser(path)
        try:
            h = hashlib.new(algo)
            with open(p, "rb") as f:
                for chunk in iter(lambda: f.read(1024 * 1024), b""):
                    h.update(chunk)
            print(f"{h.hexdigest()}  {path}")
        except OSError as e:
            print(f"{RED}{algo}sum:{RESET} {e}")


@builtin("sha256sum")
def _sha256sum(sh: "Shell", argv: List[str]) -> None:
    """sha256sum <file…>  — print SHA-256 hash of each file."""
    _hash_file_or_stdin("sha256", argv)

@builtin("sha1sum")
def _sha1sum(sh: "Shell", argv: List[str]) -> None:
    """sha1sum <file…>  — print SHA-1 hash of each file."""
    _hash_file_or_stdin("sha1", argv)

@builtin("md5sum")
def _md5sum(sh: "Shell", argv: List[str]) -> None:
    """md5sum <file…>  — print MD5 hash of each file."""
    _hash_file_or_stdin("md5", argv)


@builtin("uname")
def _uname(sh: "Shell", argv: List[str]) -> None:
    """uname [-a]  — print system identification.

    Without flags prints the kernel name. With -a prints all
    fields (kernel, hostname, release, version, machine).
    """
    import platform
    show_all = bool(argv) and "a" in argv[0]
    sysname = platform.system()
    if not show_all:
        print(sysname); return
    node = platform.node() or "ios"
    rel  = platform.release()
    ver  = platform.version()
    mach = platform.machine()
    print(f"{sysname} {node} {rel} {ver} {mach}")


@builtin("whoami")
def _whoami(sh: "Shell", argv: List[str]) -> None:
    """whoami  — print the current user (or 'mobile' on iOS)."""
    try:
        import getpass
        print(getpass.getuser())
    except Exception:
        # iOS sandbox sometimes doesn't expose pwd.getpwuid — fall back
        # to whatever USER env says, then the iOS convention 'mobile'.
        print(os.environ.get("USER") or os.environ.get("LOGNAME") or "mobile")


@builtin("hostname")
def _hostname(sh: "Shell", argv: List[str]) -> None:
    """hostname  — print this device's network name."""
    import socket
    try:
        print(socket.gethostname())
    except OSError:
        print("localhost")


@builtin("sort")
def _sort(sh: "Shell", argv: List[str]) -> None:
    """sort [-r] [-n] [-u] [file…]  — sort lines.

    Flags:
        -r   reverse order
        -n   numeric (lines compare as numbers, not strings)
        -u   drop duplicates after sorting
    """
    rev = num = uniq = False
    args = list(argv)
    while args and args[0].startswith("-") and args[0] != "-":
        for ch in args.pop(0)[1:]:
            if ch == "r": rev = True
            elif ch == "n": num = True
            elif ch == "u": uniq = True
            else: print(f"{RED}sort:{RESET} unknown flag -{ch}"); return
    lines: List[str] = []
    if not args:
        lines = sys.stdin.read().splitlines()
    else:
        for p in args:
            try: lines.extend(open(os.path.expanduser(p)).read().splitlines())
            except OSError as e: print(f"{RED}sort:{RESET} {e}"); return
    if num:
        def _key(s):
            try: return (0, float(s.strip()))
            except ValueError: return (1, s)
        lines.sort(key=_key, reverse=rev)
    else:
        lines.sort(reverse=rev)
    if uniq:
        seen = set(); out = []
        for ln in lines:
            if ln not in seen: out.append(ln); seen.add(ln)
        lines = out
    sys.stdout.write("\n".join(lines))
    if lines: sys.stdout.write("\n")


@builtin("uniq")
def _uniq(sh: "Shell", argv: List[str]) -> None:
    """uniq [-c] [file]  — collapse adjacent duplicate lines.

    With -c, prefix each output line with its run length (like the
    real uniq). Doesn't sort first — pipe through `sort` if needed.
    """
    show_count = False
    args = list(argv)
    if args and args[0] == "-c":
        show_count = True; args.pop(0)
    if not args:
        text = sys.stdin.read()
    else:
        try: text = open(os.path.expanduser(args[0])).read()
        except OSError as e: print(f"{RED}uniq:{RESET} {e}"); return
    prev, count = None, 0
    out_lines: List[str] = []
    for ln in text.splitlines():
        if ln == prev:
            count += 1
        else:
            if prev is not None:
                out_lines.append(f"{count:>4} {prev}" if show_count else prev)
            prev, count = ln, 1
    if prev is not None:
        out_lines.append(f"{count:>4} {prev}" if show_count else prev)
    sys.stdout.write("\n".join(out_lines))
    if out_lines: sys.stdout.write("\n")


@builtin("tr")
def _tr(sh: "Shell", argv: List[str]) -> None:
    """tr [-d] SET1 [SET2]  — translate or delete characters from stdin.

    Examples:
        echo hello | tr a-z A-Z         # uppercase
        echo abc123 | tr -d 0-9         # strip digits
    """
    delete = False
    args = list(argv)
    if args and args[0] == "-d":
        delete = True; args.pop(0)
    if not args:
        print(f"{RED}tr:{RESET} usage: tr [-d] SET1 [SET2]"); return
    def _expand(spec: str) -> str:
        # Handle `a-z` style ranges.
        out = []
        i = 0
        while i < len(spec):
            if i + 2 < len(spec) and spec[i + 1] == "-":
                lo, hi = ord(spec[i]), ord(spec[i + 2])
                if lo <= hi:
                    out.extend(chr(c) for c in range(lo, hi + 1))
                    i += 3; continue
            out.append(spec[i]); i += 1
        return "".join(out)
    set1 = _expand(args[0])
    text = sys.stdin.read()
    if delete:
        table = str.maketrans("", "", set1)
        sys.stdout.write(text.translate(table))
        return
    if len(args) < 2:
        print(f"{RED}tr:{RESET} non-delete mode needs SET2"); return
    set2 = _expand(args[1])
    if len(set2) < len(set1):
        # Real tr pads with the last char of SET2 — match that.
        set2 = set2 + (set2[-1] * (len(set1) - len(set2))) if set2 else ""
    table = str.maketrans(set1, set2[:len(set1)])
    sys.stdout.write(text.translate(table))


@builtin("seq")
def _seq(sh: "Shell", argv: List[str]) -> None:
    """seq [START [STEP]] END  — print numbers from START to END (inclusive).

    Examples:
        seq 5            # 1..5
        seq 2 10         # 2..10
        seq 0 2 10       # 0,2,4,6,8,10
    """
    if not argv:
        print(f"{RED}seq:{RESET} usage: seq [START [STEP]] END"); return
    try:
        nums = [float(a) for a in argv]
    except ValueError:
        print(f"{RED}seq:{RESET} arguments must be numeric"); return
    if   len(nums) == 1: start, step, end = 1.0, 1.0, nums[0]
    elif len(nums) == 2: start, step, end = nums[0], 1.0, nums[1]
    elif len(nums) == 3: start, step, end = nums
    else: print(f"{RED}seq:{RESET} too many args"); return
    if step == 0:
        print(f"{RED}seq:{RESET} step cannot be 0"); return
    integer = all(float(a).is_integer() for a in argv)
    x = start
    while (x <= end) if step > 0 else (x >= end):
        print(int(x) if integer else f"{x:g}")
        x += step


@builtin("yes")
def _yes(sh: "Shell", argv: List[str]) -> None:
    """yes [STRING]  — print STRING (or 'y') 100 times.

    Capped at 100 iterations because the iOS PTY can't be properly
    interrupted from a tight loop — real `yes | other-cmd` piping
    isn't useful here anyway.
    """
    msg = " ".join(argv) if argv else "y"
    for _ in range(100):
        print(msg)


# ---------------------------------------------------------------------------
# Additional Unix-y builtins. iOS sandbox + lack of fork/exec means we can't
# spawn /usr/bin tools, so each one is a pure-Python re-implementation that
# covers the common-usage subset.
# ---------------------------------------------------------------------------

@builtin("sleep")
def _sleep(sh: "Shell", argv: List[str]) -> None:
    """sleep N  — wait N seconds (supports decimals: `sleep 0.5`)."""
    if not argv:
        print(f"{RED}sleep:{RESET} usage: sleep N"); return
    try:
        secs = float(argv[0])
    except ValueError:
        print(f"{RED}sleep:{RESET} not a number: {argv[0]!r}"); return
    if secs < 0:
        print(f"{RED}sleep:{RESET} N must be ≥ 0"); return
    time.sleep(min(secs, 3600))  # cap at 1h so a typo doesn't wedge the REPL


@builtin("time")
def _time_cmd(sh: "Shell", argv: List[str]) -> None:
    """time <command…>  — measure how long another builtin takes.

    Mirrors `bash`'s real/user/sys triple, but on iOS we don't have
    fork/exec, so user/sys are 0; only real (wall clock) is meaningful.
    """
    if not argv:
        print(f"{RED}time:{RESET} usage: time <command…>"); return
    name = argv[0]
    fn = BUILTINS.get(name)
    if fn is None:
        print(f"{RED}time:{RESET} not a builtin: {name}"); return
    t0 = time.perf_counter()
    try:
        fn(sh, argv[1:])
    finally:
        elapsed = time.perf_counter() - t0
        print(f"\n{DIM}real  {elapsed:.3f}s{RESET}")


@builtin("nproc")
def _nproc(sh: "Shell", argv: List[str]) -> None:
    """nproc  — print the number of logical CPU cores available."""
    try:
        import psutil
        n = psutil.cpu_count(logical=True) or 1
    except Exception:
        try: n = os.cpu_count() or 1
        except Exception: n = 1
    print(n)


@builtin("id")
def _id(sh: "Shell", argv: List[str]) -> None:
    """id  — print the (sandbox) user identity."""
    try:
        import getpass, pwd
        u = getpass.getuser()
        try:
            entry = pwd.getpwnam(u)
            print(f"uid={entry.pw_uid}({u}) gid={entry.pw_gid}")
        except KeyError:
            print(f"uid=?({u}) gid=?")
    except Exception:
        print(f"uid=?({os.environ.get('USER', 'mobile')}) gid=?")


@builtin("basename")
def _basename(sh: "Shell", argv: List[str]) -> None:
    """basename PATH [SUFFIX]  — strip the directory + optional suffix."""
    if not argv:
        print(f"{RED}basename:{RESET} usage: basename PATH [SUFFIX]"); return
    name = os.path.basename(argv[0])
    if len(argv) >= 2 and name.endswith(argv[1]) and name != argv[1]:
        name = name[: -len(argv[1])]
    print(name)


@builtin("dirname")
def _dirname(sh: "Shell", argv: List[str]) -> None:
    """dirname PATH  — strip the last component, leaving the directory."""
    if not argv:
        print(f"{RED}dirname:{RESET} usage: dirname PATH"); return
    print(os.path.dirname(argv[0]) or ".")


@builtin("realpath")
def _realpath(sh: "Shell", argv: List[str]) -> None:
    """realpath PATH  — print the canonical absolute path."""
    if not argv:
        print(f"{RED}realpath:{RESET} usage: realpath PATH"); return
    print(os.path.realpath(os.path.expanduser(argv[0])))


@builtin("file")
def _file(sh: "Shell", argv: List[str]) -> None:
    """file PATH…  — best-effort guess of file type from contents.

    Sniffs the first 512 bytes for common magic numbers (PNG, JPEG, PDF,
    ZIP, gzip, ELF, Mach-O, …) and falls back to a UTF-8/ASCII probe."""
    if not argv:
        print(f"{RED}file:{RESET} usage: file PATH…"); return
    magic_hits = [
        (b"\x89PNG\r\n\x1a\n", "PNG image"),
        (b"\xff\xd8\xff", "JPEG image"),
        (b"GIF87a", "GIF image (87a)"),
        (b"GIF89a", "GIF image (89a)"),
        (b"%PDF-", "PDF document"),
        (b"PK\x03\x04", "Zip archive (or zip-based: docx, jar, …)"),
        (b"\x1f\x8b", "gzip compressed data"),
        (b"BZh", "bzip2 compressed data"),
        (b"\xfd7zXZ\x00", "xz compressed data"),
        (b"\x7fELF", "ELF binary"),
        (b"\xca\xfe\xba\xbe", "Mach-O fat binary"),
        (b"\xcf\xfa\xed\xfe", "Mach-O 64-bit binary"),
        (b"\xfe\xed\xfa\xce", "Mach-O 32-bit binary"),
        (b"\xfe\xed\xfa\xcf", "Mach-O 64-bit binary"),
        (b"#!", "POSIX shell script"),
    ]
    for path in argv:
        p = os.path.expanduser(path)
        if not os.path.exists(p):
            print(f"{path}: cannot open: No such file"); continue
        if os.path.isdir(p):
            print(f"{path}: directory"); continue
        try:
            with open(p, "rb") as f:
                head = f.read(512)
        except OSError as e:
            print(f"{path}: cannot read: {e}"); continue
        if not head:
            print(f"{path}: empty"); continue
        kind = next((label for sig, label in magic_hits if head.startswith(sig)), None)
        if kind is None:
            try:
                head.decode("utf-8")
                kind = "ASCII / UTF-8 text"
            except UnicodeDecodeError:
                kind = "data"
        print(f"{path}: {kind}")


@builtin("mktemp")
def _mktemp(sh: "Shell", argv: List[str]) -> None:
    """mktemp [-d]  — create a unique temp file (or `-d` directory).

    Returns its path. Paths live under the iOS app's TMPDIR (Documents/tmp)
    so they're auto-cleaned when the OS reaps app temp space."""
    import tempfile
    want_dir = bool(argv) and argv[0] == "-d"
    try:
        if want_dir:
            print(tempfile.mkdtemp(prefix="codebench_"))
        else:
            fd, p = tempfile.mkstemp(prefix="codebench_")
            os.close(fd)
            print(p)
    except OSError as e:
        print(f"{RED}mktemp:{RESET} {e}")


@builtin("nl")
def _nl(sh: "Shell", argv: List[str]) -> None:
    """nl [file…]  — number each non-empty line."""
    src = sys.stdin.read() if not argv else _read_files(argv, "nl")
    if src is None: return
    n = 0
    for line in src.splitlines():
        if line.strip():
            n += 1
            print(f"{n:>6}\t{line}")
        else:
            print()


@builtin("tac")
def _tac(sh: "Shell", argv: List[str]) -> None:
    """tac [file…]  — print lines in reverse order (last → first)."""
    src = sys.stdin.read() if not argv else _read_files(argv, "tac")
    if src is None: return
    for line in reversed(src.splitlines()):
        print(line)


@builtin("rev")
def _rev(sh: "Shell", argv: List[str]) -> None:
    """rev [file…]  — reverse each line's character order."""
    src = sys.stdin.read() if not argv else _read_files(argv, "rev")
    if src is None: return
    for line in src.splitlines():
        print(line[::-1])


@builtin("cut")
def _cut(sh: "Shell", argv: List[str]) -> None:
    """cut -d DELIM -f FIELDS [file…]  — extract columns.

    Examples:
        cut -d, -f 1,3 data.csv          # first + third comma-separated cols
        cut -d: -f 1 /etc/passwd         # usernames
        cut -c 1-10 file.txt             # first 10 chars of each line
    """
    delim = "\t"
    fields_spec = None
    chars_spec = None
    args = list(argv)
    while args and args[0].startswith("-"):
        flag = args.pop(0)
        if flag.startswith("-d"):
            delim = flag[2:] if len(flag) > 2 else (args.pop(0) if args else "\t")
        elif flag.startswith("-f"):
            fields_spec = flag[2:] if len(flag) > 2 else (args.pop(0) if args else "")
        elif flag.startswith("-c"):
            chars_spec = flag[2:] if len(flag) > 2 else (args.pop(0) if args else "")
        else:
            print(f"{RED}cut:{RESET} unknown flag {flag!r}"); return
    if fields_spec is None and chars_spec is None:
        print(f"{RED}cut:{RESET} need -f FIELDS or -c CHARS"); return

    def _parse_ranges(spec: str) -> List[tuple]:
        out: List[tuple] = []
        for part in spec.split(","):
            part = part.strip()
            if "-" in part:
                a, b = part.split("-", 1)
                lo = int(a) if a else 1
                hi = int(b) if b else 10**9
                out.append((lo, hi))
            else:
                n = int(part); out.append((n, n))
        return out

    src = sys.stdin.read() if not args else _read_files(args, "cut")
    if src is None: return
    try:
        ranges = _parse_ranges(fields_spec or chars_spec)
    except ValueError:
        print(f"{RED}cut:{RESET} bad range spec"); return

    for line in src.splitlines():
        if fields_spec is not None:
            parts = line.split(delim)
            picked = []
            for lo, hi in ranges:
                picked.extend(parts[lo - 1: hi])
            print(delim.join(picked))
        else:
            picked = []
            for lo, hi in ranges:
                picked.append(line[lo - 1: hi])
            print("".join(picked))


@builtin("tee")
def _tee(sh: "Shell", argv: List[str]) -> None:
    """tee [-a] FILE…  — copy stdin to stdout AND append/overwrite each FILE."""
    append = False
    args = list(argv)
    if args and args[0] == "-a":
        append = True; args.pop(0)
    if not args:
        print(f"{RED}tee:{RESET} usage: tee [-a] FILE…"); return
    data = sys.stdin.read()
    sys.stdout.write(data)
    mode = "a" if append else "w"
    for path in args:
        try:
            with open(os.path.expanduser(path), mode, encoding="utf-8") as f:
                f.write(data)
        except OSError as e:
            print(f"\n{RED}tee:{RESET} {path}: {e}", file=sys.stderr)


@builtin("diff")
def _diff(sh: "Shell", argv: List[str]) -> None:
    """diff FILE1 FILE2  — line-by-line unified diff (3 lines of context)."""
    if len(argv) < 2:
        print(f"{RED}diff:{RESET} usage: diff FILE1 FILE2"); return
    import difflib
    paths = [os.path.expanduser(p) for p in argv[:2]]
    try:
        a = open(paths[0]).read().splitlines(keepends=True)
        b = open(paths[1]).read().splitlines(keepends=True)
    except OSError as e:
        print(f"{RED}diff:{RESET} {e}"); return
    out = difflib.unified_diff(a, b, fromfile=argv[0], tofile=argv[1], n=3)
    had = False
    for line in out:
        had = True
        if line.startswith("+") and not line.startswith("+++"):
            sys.stdout.write(f"{GRN}{line}{RESET}")
        elif line.startswith("-") and not line.startswith("---"):
            sys.stdout.write(f"{RED}{line}{RESET}")
        elif line.startswith("@@"):
            sys.stdout.write(f"{CYN}{line}{RESET}")
        else:
            sys.stdout.write(line)
    if not had:
        print(f"{DIM}(files identical){RESET}")


@builtin("xxd")
@builtin("hexdump")
def _xxd(sh: "Shell", argv: List[str]) -> None:
    """xxd | hexdump FILE  — print a hex+ASCII dump of FILE.

    Output mirrors `xxd` (16 bytes per line: offset / hex / printable)."""
    if not argv:
        print(f"{RED}xxd:{RESET} usage: xxd FILE"); return
    p = os.path.expanduser(argv[0])
    try:
        with open(p, "rb") as f:
            data = f.read()
    except OSError as e:
        print(f"{RED}xxd:{RESET} {e}"); return
    for off in range(0, len(data), 16):
        chunk = data[off:off + 16]
        hexs = " ".join(f"{b:02x}" for b in chunk)
        printable = "".join(chr(b) if 32 <= b < 127 else "." for b in chunk)
        # Pad hex column to fixed width (16 bytes × "XX " - last space = 47)
        print(f"{off:08x}  {hexs:<47}  |{printable}|")


@builtin("bc")
def _bc(sh: "Shell", argv: List[str]) -> None:
    """bc EXPR…  — evaluate an arithmetic expression.

    Supports + - * / % ** and parentheses. Use the Python REPL for
    anything richer (math.sqrt, etc.).
    """
    if not argv:
        print(f"{RED}bc:{RESET} usage: bc EXPR"); return
    expr = " ".join(argv)
    # Restrict to a safe subset — no function calls, no name lookup.
    if not all(ch in "0123456789.+-*/%() " for ch in expr):
        print(f"{RED}bc:{RESET} only digits and + - * / % ( ) allowed"); return
    try:
        result = eval(expr, {"__builtins__": {}}, {})  # noqa: S307 — intentional, sanitised
    except Exception as e:
        print(f"{RED}bc:{RESET} {e}"); return
    print(result)


@builtin("cal")
def _cal(sh: "Shell", argv: List[str]) -> None:
    """cal [MONTH] [YEAR]  — print a month calendar (defaults to current)."""
    import calendar
    now = time.localtime()
    if len(argv) == 0:
        month, year = now.tm_mon, now.tm_year
    elif len(argv) == 1:
        try: year = int(argv[0]); month = now.tm_mon
        except ValueError: print(f"{RED}cal:{RESET} bad year"); return
    else:
        try:
            month, year = int(argv[0]), int(argv[1])
        except ValueError:
            print(f"{RED}cal:{RESET} bad month/year"); return
    if not 1 <= month <= 12:
        print(f"{RED}cal:{RESET} month must be 1-12"); return
    print(calendar.month(year, month).rstrip())


@builtin("ps")
def _ps(sh: "Shell", argv: List[str]) -> None:
    """ps  — list visible processes (limited to the app process tree on iOS).

    iOS sandbox blocks enumeration of other apps' processes, so this
    really only shows our own python/swift threads. Useful to sanity-
    check what background work is running."""
    try:
        import psutil
    except ImportError:
        print(f"{RED}ps:{RESET} psutil not available"); return
    try:
        me = psutil.Process(os.getpid())
        print(f"{BOLD}{'PID':>6}  {'STATE':<10} {'CPU%':>6}  {'RSS':>8}  {'THR':>4}  CMD{RESET}")
        rows = [me] + me.children(recursive=True)
        for p in rows:
            try:
                info = p.as_dict(attrs=[
                    "pid", "status", "cpu_percent",
                    "memory_info", "num_threads", "name", "cmdline"])
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                continue
            rss = info["memory_info"].rss if info["memory_info"] else 0
            cmd = " ".join(info["cmdline"] or [info["name"] or "?"])[:64]
            print(f"{info['pid']:>6}  {info['status']:<10} "
                  f"{info['cpu_percent']:>5.1f}%  "
                  f"{_human_bytes(rss):>8}  {info['num_threads']:>4}  {cmd}")
    except Exception as e:
        print(f"{RED}ps:{RESET} {e}")


@builtin("kill")
def _kill(sh: "Shell", argv: List[str]) -> None:
    """kill [-SIGNAL] PID  — send a signal to a process.

    iOS only lets us signal processes we own (i.e. ourselves and child
    threads). Useful for `kill -INT <our pid>` to break a tight loop."""
    import signal as _sig
    sig = _sig.SIGTERM
    args = list(argv)
    if args and args[0].startswith("-"):
        s = args.pop(0).lstrip("-")
        if s.isdigit():
            sig = int(s)
        else:
            named = "SIG" + s if not s.startswith("SIG") else s
            try: sig = getattr(_sig, named)
            except AttributeError:
                print(f"{RED}kill:{RESET} unknown signal {s!r}"); return
    if not args:
        print(f"{RED}kill:{RESET} usage: kill [-SIGNAL] PID"); return
    for spid in args:
        try:
            os.kill(int(spid), sig)
        except (ValueError, OSError, ProcessLookupError) as e:
            print(f"{RED}kill:{RESET} {spid}: {e}")


@builtin("watch")
def _watch(sh: "Shell", argv: List[str]) -> None:
    """watch [-n SEC] CMD  — re-run CMD every SEC seconds (default 2).

    Capped at 60 iterations so a typo doesn't wedge the REPL.
    """
    interval = 2.0
    args = list(argv)
    while args and args[0].startswith("-"):
        flag = args.pop(0)
        if flag == "-n" and args:
            try: interval = max(0.1, float(args.pop(0)))
            except ValueError: print(f"{RED}watch:{RESET} bad interval"); return
        else:
            print(f"{RED}watch:{RESET} unknown flag {flag!r}"); return
    if not args:
        print(f"{RED}watch:{RESET} usage: watch [-n SEC] CMD"); return
    fn = BUILTINS.get(args[0])
    if fn is None:
        print(f"{RED}watch:{RESET} not a builtin: {args[0]}"); return
    for _ in range(60):
        sys.stdout.write("\x1b[H\x1b[2J")  # cursor home + clear
        print(f"{DIM}every {interval}s — {' '.join(args)}{RESET}\n")
        try:
            fn(sh, args[1:])
        except KeyboardInterrupt:
            return
        time.sleep(interval)


@builtin("less")
@builtin("more")
def _less(sh: "Shell", argv: List[str]) -> None:
    """less | more [file…]  — show file(s) one screen at a time.

    On iOS the in-app terminal already provides scrollback (drag up),
    so this just `cat`s the file with a divider — there's no real
    pager UI. Use the editor tab for proper pagination."""
    if not argv:
        print(f"{RED}less:{RESET} usage: less FILE…"); return
    for i, path in enumerate(argv):
        if i: print(f"\n{DIM}{'═' * 60}{RESET}\n")
        try:
            with open(os.path.expanduser(path)) as f:
                sys.stdout.write(f.read())
        except OSError as e:
            print(f"{RED}less:{RESET} {path}: {e}")


def _read_files(paths: List[str], cmd: str) -> Optional[str]:
    """Helper: concatenate every file in `paths`. Print error + return
    None on the first I/O failure so the caller can bail. Used by nl /
    tac / rev / cut to share the read+error path."""
    out = []
    for p in paths:
        try:
            with open(os.path.expanduser(p)) as f:
                out.append(f.read())
        except OSError as e:
            print(f"{RED}{cmd}:{RESET} {e}"); return None
    return "".join(out)


def repl():
    """Never returns — loops forever prompting + reading + dispatching.

    Swift does all the line editing (see PTYBridge.LineBuffer) and
    sends us complete lines terminated by \\n. We just read line by
    line and run each one.
    """
    import os, sys, errno, time, traceback, signal, threading, faulthandler

    def _write_out(s: str) -> None:
        try:
            sys.stdout.write(s)
            sys.stdout.flush()
        except Exception:
            pass

    # Install faulthandler FIRST thing, so any C-level crash (SIGSEGV,
    # SIGBUS, SIGFPE, SIGABRT, SIGILL) on this or any other thread
    # prints a Python stack trace to stderr before the process dies.
    # Without this, a segfault in a C extension surfaces only as
    # "EXC_BAD_ACCESS (code=1, address=0x…)" in Xcode with no hint
    # of which Python frame was executing. With faulthandler enabled,
    # stderr gets a full 'Fatal Python error: Segmentation fault' +
    # every active thread's Python call stack, which Swift captures
    # via the PTY and surfaces in the terminal.
    try:
        faulthandler.enable(file=sys.stderr, all_threads=True)
        # Also dump all thread tracebacks every 30s during a fault-
        # like situation — never fires unless explicitly triggered,
        # but provides a 'wedge' diagnostic if the REPL ever hangs.
        _crash_log_path = os.path.join(
            os.environ.get("TMPDIR", "/tmp"),
            "latex_signals", "shell_crash.log",
        )
        try:
            os.makedirs(os.path.dirname(_crash_log_path), exist_ok=True)
            _crash_fh = open(_crash_log_path, "a", buffering=1)
            faulthandler.register(signal.SIGUSR1, file=_crash_fh,
                                  all_threads=True, chain=False)
        except OSError:
            pass  # can't open the log file — faulthandler to stderr still works
    except Exception as _fh_err:
        # faulthandler should always be importable, but on exotic iOS
        # Python builds it might not; the REPL should still boot.
        print(f"[shell] faulthandler init failed: {_fh_err}", file=sys.stderr)

    # Python-level crash-in-__del__ hook. Doesn't catch C segfaults
    # (faulthandler handles those) but catches any exception raised
    # during garbage collection, which would otherwise be printed
    # without context and can mask the real problem.
    def _unraisable(args):
        try:
            sys.stderr.write(f"[shell] unraisable in {args.object!r}: "
                             f"{args.exc_type.__name__}: {args.exc_value}\n")
            if args.exc_traceback:
                traceback.print_tb(args.exc_traceback, file=sys.stderr)
            sys.stderr.flush()
        except Exception:
            pass
    sys.unraisablehook = _unraisable

    # ── Ctrl+C wiring ─────────────────────────────────────────────
    # Two paths have to work together for Ctrl+C to interrupt any
    # running command:
    #
    # 1) Default SIGINT → KeyboardInterrupt handler. Python installs
    #    this by default on the main thread, but ONLY if the
    #    interpreter was booted with initsigs=1 AND the signal module
    #    finishes initialization. Embedding-style builds (BeeWare
    #    Python-Apple-support) sometimes end up with SIG_DFL here,
    #    which silently terminates the process on ^C. Force the
    #    default handler ourselves so we get KeyboardInterrupt.
    #
    # 2) A watchdog thread that polls stdin for a bare 0x03 byte.
    #    Swift's PTYBridge forwards Ctrl+C as both PyErr_SetInterrupt()
    #    AND a raw 0x03 byte in the stdin pipe. The first path catches
    #    Python bytecode; the second catches blocking C calls (e.g.
    #    os.read in a library) because once the byte appears we call
    #    `_thread.interrupt_main()` which delivers SIGINT to the
    #    main/REPL thread.
    try:
        signal.signal(signal.SIGINT, signal.default_int_handler)
    except (ValueError, OSError):
        # ValueError means we're not on the main thread — skip, Swift's
        # PyErr_SetInterrupt path still works.
        pass

    try:
        import _thread as _thr
    except ImportError:
        _thr = None

    def _ctrlc_watchdog():
        """Peek at stdin for raw Ctrl+C bytes while a command runs.
        When detected, interrupt the main thread."""
        import fcntl, select
        try:
            # Make fd 0 non-blocking so the peek never hangs if the
            # pipe is empty.
            fl = fcntl.fcntl(0, fcntl.F_GETFL)
            fcntl.fcntl(0, fcntl.F_SETFL, fl | os.O_NONBLOCK)
        except OSError:
            return
        while True:
            try:
                r, _, _ = select.select([0], [], [], 0.1)
                if not r:
                    continue
                # Peek using MSG_PEEK-equivalent — just read and put back
                # isn't possible on a pipe; but we read one byte and if
                # it's 0x03 we raise. If not, we've consumed it, which
                # is fine: the REPL's own read loop ignores stray bytes
                # outside of a command.
                data = os.read(0, 64)
                if not data:
                    continue
                if b"\x03" in data:
                    if _thr is not None:
                        _thr.interrupt_main()
                # Anything else the watchdog consumed gets thrown away
                # — the REPL's read path will just prompt again on next
                # iteration. Rare: only happens if the user types while
                # a command is busy. Acceptable trade for working ^C.
            except (OSError, InterruptedError):
                time.sleep(0.05)
                continue

    # NB: disabled by default. The watchdog conflicts with the REPL's
    # own os.read(0) in the main loop — both would race for the same
    # stdin. Keep it here as documentation / opt-in for future work;
    # the signal.default_int_handler install + Swift's PyErr_SetInterrupt
    # is enough for most cases.
    # threading.Thread(target=_ctrlc_watchdog, daemon=True).start()

    _write_out(
        f"{GRN}{BOLD}CodeBench shell{RESET} — type {CYN}help{RESET} for builtins, "
        f"anything else is Python.\n"
    )

    line_buf = bytearray()

    while True:
        try:
            prompt_str = shell.ps2() if shell.pending else shell.prompt()
            _write_out(prompt_str)

            # Swift's LineBuffer sends complete lines ending with \n.
            # Read bytes until we see one.
            line_buf.clear()
            while True:
                try:
                    chunk = os.read(0, 256)
                except OSError as e:
                    if e.errno in (errno.EAGAIN, errno.EINTR):
                        continue
                    raise
                if not chunk:
                    time.sleep(0.05)
                    continue

                # Ctrl-C surface: Swift may send 0x03 as a bare byte to
                # interrupt an in-progress command. In the REPL context
                # we just discard the current accumulator and re-prompt.
                if b"\x03" in chunk:
                    line_buf.clear()
                    raise KeyboardInterrupt

                line_buf.extend(chunk)
                if b"\n" in line_buf:
                    break

            # Take everything up to the first \n as the line; anything
            # after (rare) stays for the next iteration via the next
            # os.read call.
            nl_idx = line_buf.index(b"\n")
            line = bytes(line_buf[:nl_idx]).decode("utf-8", errors="replace")
            line = line.rstrip("\r")
            # Breadcrumb: write the in-flight command to a last-line
            # file before dispatch. If the shell crashes mid-command,
            # shell_crash.log shows the exact line that was running
            # (faulthandler only prints the Python stack, not which
            # user command triggered the stack).
            try:
                _bc_path = os.path.join(
                    os.environ.get("TMPDIR", "/tmp"),
                    "latex_signals", "shell_last_line.txt",
                )
                with open(_bc_path, "w", encoding="utf-8") as _bc:
                    _bc.write(f"{time.time():.3f}\n{line[:4096]}\n")
            except OSError:
                pass
            shell.run_line(line)

        except KeyboardInterrupt:
            _write_out(f"\n{YLW}^C{RESET}\n")
            shell.pending.clear()
        except SystemExit:
            _write_out(f"\n{DIM}(SystemExit — shell staying alive){RESET}\n")
            shell.pending.clear()
        except BaseException:
            try:
                tb = traceback.format_exc()
                _write_out(tb)
            except Exception:
                pass
            shell.pending.clear()
            # Belt & suspenders: if something in the prompt / read path
            # keeps raising the same error, a tight loop of tracebacks
            # is unusable. Sleep a bit + try chdir'ing back home so the
            # next iteration has a fighting chance.
            try:
                os.chdir(shell.home)
            except OSError:
                pass
            time.sleep(0.1)
